'use client'

import React, { useMemo, useCallback, useState } from 'react'
import { useForm, FormProvider, useWatch } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'
import { CalculatorFormField } from '@/components/forms/CalculatorFormField'
import { FieldsByMode } from '@/lib/calc-field-helper'
import { PremiumCalculatorShell } from '@/components/premium/PremiumCalculatorShell.dynamic'
import { buildGenericDef } from '@/lib/generic-fallback'

type FieldDef = { name: string; label: string; type?: 'number' | 'select'; min?: number; max?: number; step?: number | string; placeholder?: string; options?: { label: string; value: string }[] }

type ResultValue = { result: number | string; label: string; unit: string; steps: (string | { label: string; value: string })[] }

type CalcDef = { schema: z.ZodObject<any, any, any>; fields: FieldDef[]; compute: (vals: Record<string, unknown>) => ResultValue; description: string; formula: string; interpretation: string; presets?: { label: string; values: Record<string, string> }[] }

function n(v: unknown): number { const x = parseFloat(String(v ?? '')); return isNaN(x) ? 0 : x }

const calcDefs: Record<string, CalcDef> = {

  'gpa-calculator': { schema: z.object({ grades: z.string(), credits: z.string() }), fields: [{ name: 'grades', label: 'Grade Points (comma-separated)', placeholder: '4.0, 3.7, 3.3' }, { name: 'credits', label: 'Credit Hours (comma-separated)', placeholder: '3, 3, 4' }], compute: (v) => { const g = String(v.grades || '').split(',').map(Number).filter(x => !isNaN(x)); const c = String(v.credits || '').split(',').map(Number).filter(x => !isNaN(x)); const gpa = c.length > 0 && g.length > 0 && c.length === g.length ? g.reduce((s, gi, i) => s + gi * (c[i] || 0), 0) / c.reduce((a, b) => a + b, 0) : 0; return { result: gpa, label: 'GPA', unit: '/4.0', steps: [`Courses: ${g.length}`, `Total quality points: ${g.reduce((s, gi, i) => s + gi * (c[i] || 0), 0).toFixed(2)}`, `Total credits: ${c.reduce((a, b) => a + b, 0)}`, `GPA: ${gpa.toFixed(3)}`] } }, description: 'Calculate GPA from grades and credit hours.', formula: 'GPA = Σ(Grade × Credits) / Σ(Credits)', interpretation: 'A = 4.0, A- = 3.7, B+ = 3.3, B = 3.0, B- = 2.7, C+ = 2.3, C = 2.0, D = 1.0, F = 0.0.' },
  'college-gpa-calculator': { schema: z.object({ grades: z.string(), credits: z.string(), currentGpa: z.string(), currentCredits: z.string() }), fields: [{ name: 'currentGpa', label: 'Current GPA', step: '0.01', min: 0, max: 4 }, { name: 'currentCredits', label: 'Current Earned Credits', step: '1', min: 0 }, { name: 'grades', label: 'New Grade Points (comma-separated)', placeholder: '4.0, 3.7' }, { name: 'credits', label: 'New Credits (comma-separated)', placeholder: '3, 4' }], compute: (v) => { const cGpa = n(v.currentGpa); const cCred = n(v.currentCredits); const g = String(v.grades || '').split(',').map(Number).filter(x => !isNaN(x)); const c = String(v.credits || '').split(',').map(Number).filter(x => !isNaN(x)); const newQP = c.length > 0 && g.length > 0 && c.length === g.length ? g.reduce((s, gi, i) => s + gi * (c[i] || 0), 0) : 0; const totalQP = cGpa * cCred + newQP; const totalCred = cCred + c.reduce((a, b) => a + b, 0); const gpa = totalCred > 0 ? totalQP / totalCred : 0; return { result: gpa, label: 'New Cumulative GPA', unit: '/4.0', steps: [`Current: ${cGpa.toFixed(2)} × ${cCred} credits = ${(cGpa * cCred).toFixed(2)} quality pts`, `New quality pts: ${newQP.toFixed(2)}`, `Total: ${totalQP.toFixed(2)} / ${totalCred} = ${gpa.toFixed(3)}`] } }, description: 'Calculate cumulative college GPA including new courses.', formula: 'GPA = (Current GPA × Current Credits + Σ(Grade × Credits)) / Total Credits', interpretation: 'Includes both existing and new coursework for accurate cumulative GPA.' },
  'high-school-gpa-calculator': { schema: z.object({ grades: z.string(), honors: z.string() }), fields: [{ name: 'grades', label: 'Course Grades (letter, comma-separated)', placeholder: 'A, B+, A-, C' }, { name: 'honors', label: 'Honors/AP Courses (comma-separated Y/N)', placeholder: 'N, Y, N, N' }], compute: (v) => { const gradeMap: Record<string, number> = { 'A': 4, 'A-': 3.7, 'B+': 3.3, 'B': 3, 'B-': 2.7, 'C+': 2.3, 'C': 2, 'C-': 1.7, 'D+': 1.3, 'D': 1, 'F': 0 }; const g = String(v.grades || '').split(',').map(s => gradeMap[s.trim().toUpperCase()] ?? 0); const h = String(v.honors || '').split(',').map(s => s.trim().toUpperCase() === 'Y'); const pts = g.map((gp, i) => gp + (h[i] ? 1 : 0)); const gpa = g.length > 0 ? pts.reduce((a, b) => a + b, 0) / pts.length : 0; return { result: gpa, label: 'High School GPA', unit: '/4.0', steps: [`Courses: ${g.length}`, `Weighted points: ${pts.reduce((a, b) => a + b, 0).toFixed(1)}`, `GPA: ${gpa.toFixed(3)} (unweighted: ${(g.reduce((a, b) => a + b, 0) / g.length).toFixed(3)})`] } }, description: 'Calculate high school GPA with honors/AP weighting.', formula: 'Weighted GPA = Σ(Grade.Pts + Honor.Bonus) / Courses', interpretation: 'Honors/AP courses typically add 0.5-1.0 point. Standard scale: A=4, B=3, C=2, D=1, F=0.' },
  'weighted-gpa-calculator': { schema: z.object({ grades: z.string(), weights: z.string() }), fields: [{ name: 'grades', label: 'Grade Points (comma-separated)', placeholder: '4.0, 3.7, 3.3' }, { name: 'weights', label: 'Weights (comma-separated)', placeholder: '1, 1.5, 1' }], compute: (v) => { const g = String(v.grades || '').split(',').map(Number).filter(x => !isNaN(x)); const w = String(v.weights || '').split(',').map(Number).filter(x => !isNaN(x)); const wgpa = w.length > 0 && g.length > 0 && w.length === g.length ? g.reduce((s, gi, i) => s + gi * (w[i] || 0), 0) / w.reduce((a, b) => a + b, 0) : 0; return { result: wgpa, label: 'Weighted GPA', unit: '/4.0', steps: [`Weighted sum: ${g.reduce((s, gi, i) => s + gi * (w[i] || 0), 0).toFixed(2)}`, `Total weight: ${w.reduce((a, b) => a + b, 0)}`, `Weighted GPA: ${wgpa.toFixed(3)}`] } }, description: 'Calculate weighted GPA with custom course weights.', formula: 'WGPA = Σ(Grade × Weight) / Σ(Weight)', interpretation: 'Use weights >1 for honors/AP courses, standard=1 for regular courses.' },
  'cumulative-gpa-calculator': { schema: z.object({ semesters: z.string(), gpas: z.string(), credits: z.string() }), fields: [{ name: 'semesters', label: 'Semester GPAs (comma-separated)', placeholder: '3.5, 3.8, 3.6' }, { name: 'gpas', label: 'Semester Credits (comma-separated)', placeholder: '15, 16, 15' }], compute: (v) => { const g = String(v.semesters || '').split(',').map(Number).filter(x => !isNaN(x)); const c = String(v.gpas || '').split(',').map(Number).filter(x => !isNaN(x)); const cum = c.length > 0 && g.length > 0 && c.length === g.length ? g.reduce((s, gi, i) => s + gi * (c[i] || 0), 0) / c.reduce((a, b) => a + b, 0) : 0; return { result: cum, label: 'Cumulative GPA', unit: '/4.0', steps: [`Semesters: ${g.length}`, `Total quality points: ${g.reduce((s, gi, i) => s + gi * (c[i] || 0), 0).toFixed(2)}`, `Total credits: ${c.reduce((a, b) => a + b, 0)}`, `Cumulative GPA: ${cum.toFixed(3)}`] } }, description: 'Calculate cumulative GPA across multiple semesters.', formula: 'Cumulative GPA = Σ(Semester GPA × Credits) / Σ(Credits)', interpretation: 'Combines all semesters with their respective credit hours for overall GPA.' },

  'grade-calculator': { schema: z.object({ earned: z.string(), total: z.string() }), fields: [{ name: 'earned', label: 'Points Earned', step: '0.1', min: 0 }, { name: 'total', label: 'Total Points Possible', step: '0.1', min: 0 }], compute: (v) => { const pct = n(v.total) > 0 ? (n(v.earned) / n(v.total)) * 100 : 0; return { result: pct, label: 'Grade Percentage', unit: '%', steps: [`${n(v.earned)} / ${n(v.total)} = ${(n(v.earned) / n(v.total) * 100).toFixed(2)}%`] } }, description: 'Calculate grade percentage from earned points.', formula: 'Grade % = (Earned / Total) × 100', interpretation: 'A ≥ 90%, B ≥ 80%, C ≥ 70%, D ≥ 60%, F < 60%.' },
  'final-grade-calculator': { schema: z.object({ current: z.string(), weight: z.string(), desired: z.string() }), fields: [{ name: 'current', label: 'Current Grade (%)', step: '0.1', min: 0, max: 100 }, { name: 'weight', label: 'Final Exam Weight (%)', step: '1', min: 0, max: 100 }, { name: 'desired', label: 'Desired Final Grade (%)', step: '0.1', min: 0, max: 100 }], compute: (v) => { const w = n(v.weight) / 100; const needed = w > 0 ? (n(v.desired) - n(v.current) * (1 - w)) / w : 0; return { result: needed, label: 'Grade Needed on Final', unit: '%', steps: [`Current: ${n(v.current)}% (weight: ${((1 - w) * 100).toFixed(1)}%)`, `Final weight: ${(w * 100).toFixed(1)}%`, `Need: ${needed.toFixed(2)}% on final for ${n(v.desired)}%`] } }, description: 'Calculate the grade needed on a final exam to reach a target.', formula: 'Needed = (Desired - Current × (1 - W)) / W', interpretation: 'W is the final exam weight as a decimal. Result > 100% means the target may be unreachable.' },
  'test-grade-calculator': { schema: z.object({ correct: z.string(), total: z.string() }), fields: [{ name: 'correct', label: 'Questions Correct', step: '1', min: 0 }, { name: 'total', label: 'Total Questions', step: '1', min: 1 }], compute: (v) => { const pct = n(v.total) > 0 ? (n(v.correct) / n(v.total)) * 100 : 0; return { result: pct, label: 'Test Score', unit: '%', steps: [`${n(v.correct)} / ${n(v.total)} correct = ${(n(v.correct) / n(v.total) * 100).toFixed(2)}%`] } }, description: 'Calculate test score as a percentage.', formula: 'Score % = (Correct / Total) × 100', interpretation: 'Each question weight = 100/Total points.' },
  'percentage-grade-calculator': { schema: z.object({ obtained: z.string(), total: z.string() }), fields: [{ name: 'obtained', label: 'Marks Obtained', step: '0.1', min: 0 }, { name: 'total', label: 'Total Marks', step: '0.1', min: 0 }], compute: (v) => { const pct = n(v.total) > 0 ? (n(v.obtained) / n(v.total)) * 100 : 0; return { result: pct, label: 'Percentage', unit: '%', steps: [`${n(v.obtained)} / ${n(v.total)} = ${(n(v.obtained) / n(v.total) * 100).toFixed(2)}%`] } }, description: 'Calculate percentage grade from obtained and total marks.', formula: '% = (Obtained / Total) × 100', interpretation: 'Percentage = marks obtained out of total, expressed as a percentage.' },
  'letter-grade-calculator': { schema: z.object({ percentage: z.string(), scale: z.string() }), fields: [{ name: 'percentage', label: 'Percentage Score', step: '0.1', min: 0, max: 100 }, { name: 'scale', label: 'Grading Scale', type: 'select', options: [{ label: 'Standard (A≥90)', value: 'standard' }, { label: 'College (A≥93)', value: 'college' }, { label: 'Strict (A≥95)', value: 'strict' }] }],    compute: (v) => { const pct = n(v.percentage); const scale = String(v.scale || 'standard'); const thresholds: Record<string, [number, string][]> = { standard: [[90, 'A'], [80, 'B'], [70, 'C'], [60, 'D'], [0, 'F']], college: [[93, 'A'], [90, 'A-'], [87, 'B+'], [83, 'B'], [80, 'B-'], [77, 'C+'], [73, 'C'], [70, 'C-'], [67, 'D+'], [63, 'D'], [60, 'D-'], [0, 'F']], strict: [[95, 'A'], [85, 'B'], [75, 'C'], [65, 'D'], [0, 'F']] }; const t = thresholds[scale] || thresholds.standard; const letter = t.find(([min]: [number, string]) => pct >= min)?.[1] || 'F'; return { result: letter, label: 'Letter Grade', unit: '', steps: [`Percentage: ${pct.toFixed(1)}%`, `Scale: ${scale}`, `Letter grade: ${letter}`] } }, description: 'Convert percentage score to letter grade.', formula: 'Letter = threshold lookup by percentage and scale.', interpretation: 'Standard: A≥90, B≥80, C≥70, D≥60, F<60. College: A≥93, A-≥90, etc.' },

  'sat-score-calculator': { schema: z.object({ math: z.string(), reading: z.string(), writing: z.string() }), fields: [{ name: 'math', label: 'Math Score (200-800)', step: '10', min: 200, max: 800 }, { name: 'reading', label: 'Reading Score (200-800)', step: '10', min: 200, max: 800 }, { name: 'writing', label: 'Writing Score (200-800)', step: '10', min: 200, max: 800 }], compute: (v) => { const total = n(v.math) + n(v.reading) + n(v.writing); return { result: total, label: 'Total SAT Score', unit: '/2400', steps: [`Math: ${n(v.math)}`, `Reading: ${n(v.reading)}`, `Writing: ${n(v.writing)}`, `Total: ${total}`] } }, description: 'Calculate total SAT score from section scores.', formula: 'Total = Math + Reading + Writing', interpretation: 'SAT scores range 600-2400. Each section 200-800. Current SAT: 400-1600 (EBRW + Math).' },
  'act-score-calculator': { schema: z.object({ english: z.string(), math: z.string(), reading: z.string(), science: z.string() }), fields: [{ name: 'english', label: 'English (1-36)', step: '1', min: 1, max: 36 }, { name: 'math', label: 'Math (1-36)', step: '1', min: 1, max: 36 }, { name: 'reading', label: 'Reading (1-36)', step: '1', min: 1, max: 36 }, { name: 'science', label: 'Science (1-36)', step: '1', min: 1, max: 36 }], compute: (v) => { const avg = (n(v.english) + n(v.math) + n(v.reading) + n(v.science)) / 4; return { result: avg, label: 'ACT Composite Score', unit: '/36', steps: [`English: ${n(v.english)}`, `Math: ${n(v.math)}`, `Reading: ${n(v.reading)}`, `Science: ${n(v.science)}`, `Composite: ${avg.toFixed(2)}`] } }, description: 'Calculate ACT composite score from section scores.', formula: 'Composite = (English + Math + Reading + Science) / 4', interpretation: 'ACT scores range 1-36 per section. Composite is the average rounded to nearest whole number.' },
  'gmat-score-calculator': { schema: z.object({ verbal: z.string(), quant: z.string(), integrated: z.string() }), fields: [{ name: 'verbal', label: 'Verbal (0-60)', step: '1', min: 0, max: 60 }, { name: 'quant', label: 'Quantitative (0-60)', step: '1', min: 0, max: 60 }, { name: 'integrated', label: 'Integrated Reasoning (1-8)', step: '1', min: 1, max: 8 }], compute: (v) => { const total = n(v.verbal) + n(v.quant); return { result: total, label: 'GMAT Total Score', unit: '/800', steps: [`Verbal: ${n(v.verbal)}`, `Quant: ${n(v.quant)}`, `IR: ${n(v.integrated)}`, `Total: ${total}/800`] } }, description: 'Calculate GMAT total score.', formula: 'Total = Verbal + Quantitative (200-800)', interpretation: 'GMAT scores: Verbal 0-60, Quantitative 0-60, IR 1-8, Total 200-800. AWA scored separately 0-6.' },
  'gre-score-calculator': { schema: z.object({ verbal: z.string(), quant: z.string(), writing: z.string() }), fields: [{ name: 'verbal', label: 'Verbal Reasoning (130-170)', step: '1', min: 130, max: 170 }, { name: 'quant', label: 'Quantitative Reasoning (130-170)', step: '1', min: 130, max: 170 }, { name: 'writing', label: 'Analytical Writing (0-6)', step: '0.5', min: 0, max: 6 }], compute: (v) => ({ result: `${n(v.verbal)}V / ${n(v.quant)}Q`, label: 'GRE Scores', unit: '', steps: [`Verbal: ${n(v.verbal)}/170`, `Quant: ${n(v.quant)}/170`, `Writing: ${n(v.writing)}/6`] }), description: 'View GRE section scores.', formula: 'Verbal 130-170, Quant 130-170, Writing 0-6', interpretation: 'GRE scores valid for 5 years. Each section scored separately. No composite score.' },
  'mcat-score-calculator': { schema: z.object({ cp: z.string(), cars: z.string(), bio: z.string(), ps: z.string() }), fields: [{ name: 'cp', label: 'Chem/Phys (118-132)', step: '1', min: 118, max: 132 }, { name: 'cars', label: 'CARS (118-132)', step: '1', min: 118, max: 132 }, { name: 'bio', label: 'Bio/Biochem (118-132)', step: '1', min: 118, max: 132 }, { name: 'ps', label: 'Psych/Soc (118-132)', step: '1', min: 118, max: 132 }], compute: (v) => { const total = n(v.cp) + n(v.cars) + n(v.bio) + n(v.ps); return { result: total, label: 'MCAT Total Score', unit: '/528', steps: [`CP: ${n(v.cp)}`, `CARS: ${n(v.cars)}`, `BB: ${n(v.bio)}`, `PS: ${n(v.ps)}`, `Total: ${total}/528`] } }, description: 'Calculate MCAT total score from section scores.', formula: 'Total = CP + CARS + BB + PS (472-528)', interpretation: 'MCAT scores: each section 118-132, total 472-528. Each section is scaled.' },

  'study-time-calculator': { schema: z.object({ pages: z.string(), speed: z.string(), breaks: z.string() }), fields: [{ name: 'pages', label: 'Pages to Study', step: '1', min: 1 }, { name: 'speed', label: 'Reading Speed (pages/hr)', placeholder: '20', step: '1', min: 1 }, { name: 'breaks', label: 'Break Minutes per Hour', placeholder: '10', step: '5', min: 0 }], compute: (v) => { const readingHrs = n(v.pages) / (n(v.speed || '20')); const breakHrs = readingHrs * (n(v.breaks || '10') / 60); const total = readingHrs + breakHrs; return { result: total, label: 'Total Study Time', unit: 'hours', steps: [`Reading: ${n(v.pages)} pages @ ${n(v.speed || '20')}/hr = ${readingHrs.toFixed(2)} hr`, `Breaks: ${breakHrs.toFixed(2)} hr`, `Total: ${total.toFixed(2)} hr`] } }, description: 'Estimate total study time including breaks.', formula: 'Time = Pages/Speed + Breaks', interpretation: 'Pomodoro technique suggests 25 min study + 5 min break cycles.' },
  'homework-time-calculator': { schema: z.object({ problems: z.string(), timePer: z.string(), setup: z.string() }), fields: [{ name: 'problems', label: 'Number of Problems', step: '1', min: 1 }, { name: 'timePer', label: 'Minutes per Problem', step: '1', min: 1, placeholder: '5' }, { name: 'setup', label: 'Setup/Review Time (min)', placeholder: '15', step: '1', min: 0 }], compute: (v) => { const totalMin = n(v.problems) * (n(v.timePer || '5')) + n(v.setup || '15'); return { result: totalMin / 60, label: 'Total Homework Time', unit: 'hours', steps: [`${n(v.problems)} problems × ${n(v.timePer || '5')} min = ${(n(v.problems) * (n(v.timePer || '5'))).toFixed(0)} min`, `Setup: ${n(v.setup || '15')} min`, `Total: ${totalMin.toFixed(0)} min = ${(totalMin / 60).toFixed(2)} hr`] } }, description: 'Estimate time needed to complete homework.', formula: 'Time = (Problems × Min/Problem + Setup) / 60', interpretation: 'Includes solving time plus setup and review overhead.' },
  'study-planner-calculator': { schema: z.object({ days: z.string(), hoursPerDay: z.string(), material: z.string(), difficulty: z.string() }), fields: [{ name: 'days', label: 'Days Until Exam', step: '1', min: 1 }, { name: 'hoursPerDay', label: 'Hours Available per Day', step: '0.5', min: 0.5 }, { name: 'material', label: 'Total Material (pages or chapters)', step: '1', min: 1 }, { name: 'difficulty', label: 'Difficulty Multiplier', type: 'select', options: [{ label: 'Easy (0.7x)', value: '0.7' }, { label: 'Medium (1.0x)', value: '1' }, { label: 'Hard (1.5x)', value: '1.5' }] }], compute: (v) => { const totalHrs = n(v.days) * n(v.hoursPerDay); const effMaterial = n(v.material) * n(v.difficulty || '1'); const pace = totalHrs > 0 ? effMaterial / totalHrs : 0; return { result: pace, label: 'Pace Needed', unit: 'units/hr', steps: [`Total study time: ${n(v.days)} days × ${n(v.hoursPerDay)} hr = ${totalHrs.toFixed(1)} hr`, `Effective material: ${n(v.material)} × ${n(v.difficulty || '1')} = ${effMaterial.toFixed(1)}`, `Pace: ${effMaterial.toFixed(1)} / ${totalHrs.toFixed(1)} = ${pace.toFixed(2)} units/hr`] } }, description: 'Plan study schedule based on available time and material.', formula: 'Pace = (Material × Difficulty) / (Days × Hours/Day)', interpretation: 'Difficulty multiplier adjusts for complex topics. Lower number = more study time needed per page.' },

  'attendance-calculator': { schema: z.object({ present: z.string(), total: z.string(), required: z.string() }), fields: [{ name: 'present', label: 'Days Present', step: '1', min: 0 }, { name: 'total', label: 'Total Class Days', step: '1', min: 1 }, { name: 'required', label: 'Required Attendance (%)', placeholder: '75', step: '1', min: 0, max: 100 }], compute: (v) => { const pct = n(v.total) > 0 ? (n(v.present) / n(v.total)) * 100 : 0; const req = n(v.required || '75'); const canMiss = n(v.total) > 0 ? Math.floor(n(v.total) * req / 100) : 0; const remaining = Math.max(0, canMiss - (n(v.total) - n(v.present))); return { result: pct, label: 'Attendance Rate', unit: '%', steps: [`Present: ${n(v.present)} / ${n(v.total)} = ${pct.toFixed(1)}%`, `Required: ${req}%`, `You can miss ${remaining} more day(s)`] } }, description: 'Calculate attendance rate and remaining absences allowed.', formula: 'Rate = Present/Total × 100 | Can Miss = Floor(Total × Required/100)', interpretation: 'Many institutions require 75% attendance minimum. Drops below threshold may affect eligibility.' },
  'class-rank-calculator': { schema: z.object({ gpa: z.string(), classSize: z.string(), percentile: z.string() }), fields: [{ name: 'gpa', label: 'Your GPA', step: '0.01', min: 0, max: 4 }, { name: 'classSize', label: 'Class Size', step: '1', min: 1 }, { name: 'percentile', label: 'Est. Percentile Rank', placeholder: '75', step: '1', min: 0, max: 100 }], compute: (v) => { const rank = Math.round(n(v.classSize) * (1 - n(v.percentile || '50') / 100) + 1); return { result: rank, label: 'Estimated Class Rank', unit: `/ ${n(v.classSize)}`, steps: [`Class size: ${n(v.classSize)}`, `Percentile: ${n(v.percentile || '50')}%`, `Est. rank: ${rank} of ${n(v.classSize)}`] } }, description: 'Estimate class rank from percentile.', formula: 'Rank ≈ ClassSize × (1 - Percentile/100) + 1', interpretation: 'Top 10% = rank in top 10% of class. Actual rank depends on GPA distribution.' },
  'grade-required-calculator': { schema: z.object({ current: z.string(), target: z.string(), remaining: z.string() }), fields: [{ name: 'current', label: 'Current Grade (%)', step: '0.1', min: 0, max: 100 }, { name: 'target', label: 'Target Grade (%)', step: '0.1', min: 0, max: 100 }, { name: 'remaining', label: 'Remaining Weight (%)', step: '1', min: 0, max: 100 }], compute: (v) => { const rw = n(v.remaining) / 100; const cw = 1 - rw; const needed = rw > 0 ? (n(v.target) - n(v.current) * cw) / rw : 0; return { result: needed, label: 'Grade Needed on Remaining Work', unit: '%', steps: [`Current: ${n(v.current)}% (weight: ${(cw * 100).toFixed(1)}%)`, `Remaining weight: ${(rw * 100).toFixed(1)}%`, `Need: ${needed.toFixed(2)}% on remaining to get ${n(v.target)}%`] } }, description: 'Calculate required grade on remaining assignments.', formula: 'Required = (Target - Current × CW) / RW', interpretation: 'CW = completed work weight, RW = remaining work weight (as decimals).' },
  'semester-grade-calculator': { schema: z.object({ quarter1: z.string(), quarter2: z.string(), final: z.string(), finalWeight: z.string() }), fields: [{ name: 'quarter1', label: 'Quarter 1 Grade (%)', step: '0.1', min: 0, max: 100 }, { name: 'quarter2', label: 'Quarter 2 Grade (%)', step: '0.1', min: 0, max: 100 }, { name: 'final', label: 'Final Exam Grade (%)', step: '0.1', min: 0, max: 100 }, { name: 'finalWeight', label: 'Final Exam Weight (%)', placeholder: '20', step: '1', min: 0, max: 100 }], compute: (v) => { const fw = n(v.finalWeight || '20') / 100; const qw = (1 - fw) / 2; const sem = n(v.quarter1) * qw + n(v.quarter2) * qw + n(v.final) * fw; return { result: sem, label: 'Semester Grade', unit: '%', steps: [`Q1: ${n(v.quarter1)}% × ${(qw * 100).toFixed(1)}%`, `Q2: ${n(v.quarter2)}% × ${(qw * 100).toFixed(1)}%`, `Final: ${n(v.final)}% × ${(fw * 100).toFixed(1)}%`, `Semester: ${sem.toFixed(2)}%`] } }, description: 'Calculate semester grade from quarters and final exam.', formula: 'Semester = Q1×QW + Q2×QW + Final×FW', interpretation: 'Typical weighting: 2 quarters (40% each) + final (20%) or similar.' },
  'quiz-score-calculator': { schema: z.object({ correct: z.string(), total: z.string(), avg: z.string() }), fields: [{ name: 'correct', label: 'Questions Correct', step: '1', min: 0 }, { name: 'total', label: 'Total Questions', step: '1', min: 1 }], compute: (v) => { const pct = n(v.total) > 0 ? (n(v.correct) / n(v.total)) * 100 : 0; return { result: pct, label: 'Quiz Score', unit: '%', steps: [`${n(v.correct)} / ${n(v.total)} = ${pct.toFixed(1)}%`] } }, description: 'Calculate quiz score percentage.', formula: 'Score % = (Correct / Total) × 100', interpretation: 'Each question counts equally toward the total score.' },
  'ap-score-calculator': { schema: z.object({ score: z.string() }), fields: [{ name: 'score', label: 'AP Score (1-5)', type: 'select', options: [{ label: '5 - Extremely Well Qualified', value: '5' }, { label: '4 - Well Qualified', value: '4' }, { label: '3 - Qualified', value: '3' }, { label: '2 - Possibly Qualified', value: '2' }, { label: '1 - No Recommendation', value: '1' }] }], compute: (v) => { const s = n(v.score); const recs: Record<number, string> = { 5: 'Extremely well qualified', 4: 'Well qualified', 3: 'Qualified', 2: 'Possibly qualified', 1: 'No recommendation' }; const credit = s >= 3 ? 'Most colleges grant credit for 3+' : 'Check your college AP credit policy'; return { result: `${s}: ${recs[s] || ''}`, label: 'AP Score Interpretation', unit: '', steps: [`Score: ${s}`, `Interpretation: ${recs[s] || '—'}`, credit] } }, description: 'Interpret AP exam scores.', formula: 'AP scores 1-5. Most colleges accept 3+ for credit.', interpretation: 'AP scores of 3+ often qualify for college credit or advanced placement. Policies vary by institution.' },
  'ib-score-calculator': { schema: z.object({ score: z.string() }), fields: [{ name: 'score', label: 'IB Score (1-7)', type: 'select', options: [{ label: '7 - Excellent', value: '7' }, { label: '6 - Very Good', value: '6' }, { label: '5 - Good', value: '5' }, { label: '4 - Satisfactory', value: '4' }, { label: '3 - Mediocre', value: '3' }, { label: '2 - Poor', value: '2' }, { label: '1 - Very Poor', value: '1' }] }], compute: (v) => { const s = n(v.score); const desc: Record<number, string> = { 7: 'Excellent', 6: 'Very Good', 5: 'Good', 4: 'Satisfactory', 3: 'Mediocre', 2: 'Poor', 1: 'Very Poor' }; return { result: `${s}: ${desc[s] || ''}`, label: 'IB Score', unit: '/7', steps: [`Score: ${s}`, `Description: ${desc[s] || '—'}`, s >= 4 ? 'Many universities accept IB scores of 4+ for credit' : 'Retake may be considered for scores below 4'] } }, description: 'Interpret IB (International Baccalaureate) exam scores.', formula: 'IB Diploma subjects scored 1-7 per subject.', interpretation: 'IB scores of 4+ are generally passing. Total diploma score combines 6 subjects + core points (max 45).' },

  'college-cost-calculator': { schema: z.object({ tuition: z.string(), fees: z.string(), room: z.string(), board: z.string(), books: z.string(), years: z.string() }), fields: [{ name: 'tuition', label: 'Annual Tuition ($)', step: '100', min: 0 }, { name: 'fees', label: 'Annual Fees ($)', step: '100', min: 0 }, { name: 'room', label: 'Room ($/year)', step: '100', min: 0 }, { name: 'board', label: 'Board ($/year)', step: '100', min: 0 }, { name: 'books', label: 'Books & Supplies ($/year)', step: '50', min: 0 }, { name: 'years', label: 'Number of Years', step: '1', min: 1, placeholder: '4' }], compute: (v) => { const annual = n(v.tuition) + n(v.fees) + n(v.room) + n(v.board) + n(v.books); const total = annual * n(v.years || '4'); return { result: total, label: 'Total College Cost', unit: '$', steps: [`Annual cost: $${annual.toFixed(0)}`, `Years: ${n(v.years || '4')}`, `Total: $${total.toFixed(0)}`] } }, description: 'Estimate total college costs over multiple years.', formula: 'Total = (Tuition + Fees + Room + Board + Books) × Years', interpretation: 'Does not include financial aid, scholarships, or interest on loans. Actual costs vary significantly.' },
  'scholarship-calculator': { schema: z.object({ totalCost: z.string(), scholarship: z.string(), grants: z.string(), workStudy: z.string(), savings: z.string() }), fields: [{ name: 'totalCost', label: 'Total College Cost ($)', step: '100', min: 0 }, { name: 'scholarship', label: 'Scholarships ($/year)', step: '100', min: 0 }, { name: 'grants', label: 'Grants ($/year)', step: '100', min: 0 }, { name: 'workStudy', label: 'Work-Study ($/year)', step: '100', min: 0 }, { name: 'savings', label: 'Family Savings ($/year)', step: '100', min: 0 }], compute: (v) => { const aid = n(v.scholarship) + n(v.grants) + n(v.workStudy) + n(v.savings); const gap = n(v.totalCost) - aid; return { result: gap, label: 'Remaining Gap', unit: '$/year', steps: [`Total cost: $${n(v.totalCost).toFixed(0)}/year`, `Total aid: $${aid.toFixed(0)}/year`, `Remaining gap: $${gap.toFixed(0)}/year (may need loans)`] } }, description: 'Calculate remaining college funding gap.', formula: 'Gap = Total Cost - (Scholarships + Grants + Work-Study + Savings)', interpretation: 'A positive gap may need to be covered by student/parent loans or payment plans.' },
  'student-loan-affordability-calculator': { schema: z.object({ loanAmount: z.string(), rate: z.string(), term: z.string(), income: z.string() }), fields: [{ name: 'loanAmount', label: 'Total Loan Amount ($)', step: '100', min: 0 }, { name: 'rate', label: 'Interest Rate (%)', step: '0.1', min: 0 }, { name: 'term', label: 'Term (years)', step: '1', min: 1, placeholder: '10' }, { name: 'income', label: 'Expected Starting Salary ($)', step: '1000', min: 0 }], compute: (v) => { const r = n(v.rate) / 100 / 12; const nMonths = n(v.term || '10') * 12; const payment = r > 0 ? n(v.loanAmount) * r * Math.pow(1 + r, nMonths) / (Math.pow(1 + r, nMonths) - 1) : n(v.loanAmount) / nMonths; const dti = n(v.income) > 0 ? (payment * 12) / n(v.income) * 100 : 0; return { result: payment, label: 'Monthly Payment', unit: '$/month', steps: [`Loan: $${n(v.loanAmount).toFixed(0)} @ ${n(v.rate)}% for ${n(v.term || '10')} yr`, `Monthly payment: $${payment.toFixed(2)}`, `DTI ratio: ${dti.toFixed(1)}% (recommended < 8%)`] } }, description: 'Calculate student loan affordability and debt-to-income ratio.', formula: 'M = P × r(1+r)^n / ((1+r)^n - 1) | DTI = (M×12)/Income × 100', interpretation: 'General rule: total student loans should not exceed first-year salary. DTI ratio under 8% recommended.' },

  'reading-speed-calculator': { schema: z.object({ words: z.string(), minutes: z.string() }), fields: [{ name: 'words', label: 'Words Read', step: '1', min: 1 }, { name: 'minutes', label: 'Time (minutes)', step: '0.5', min: 0.5 }], compute: (v) => { const wpm = n(v.minutes) > 0 ? n(v.words) / n(v.minutes) : 0; return { result: wpm, label: 'Reading Speed', unit: 'words/min', steps: [`${n(v.words)} words in ${n(v.minutes)} min`, `Speed: ${wpm.toFixed(0)} WPM`] } }, description: 'Calculate reading speed in words per minute.', formula: 'WPM = Words / Minutes', interpretation: 'Average: 200-300 WPM. Good: 300-400 WPM. Speed reader: 400-700+ WPM.' },
  'typing-speed-calculator': { schema: z.object({ characters: z.string(), minutes: z.string(), errors: z.string() }), fields: [{ name: 'characters', label: 'Characters Typed', step: '1', min: 1 }, { name: 'minutes', label: 'Time (minutes)', step: '0.5', min: 0.5 }, { name: 'errors', label: 'Errors', step: '1', min: 0 }], compute: (v) => { const gross = n(v.minutes) > 0 ? (n(v.characters) / 5) / n(v.minutes) : 0; const net = Math.max(0, gross - n(v.errors)); return { result: net, label: 'Typing Speed (Net WPM)', unit: 'WPM', steps: [`Gross WPM: ${gross.toFixed(1)}`, `Errors: ${n(v.errors)}`, `Net WPM: ${net.toFixed(1)}`] } }, description: 'Calculate typing speed in net words per minute.', formula: 'Net WPM = (Characters/5 / Minutes) - Errors', interpretation: 'Professional: 60-80 WPM. Average: 35-45 WPM. Each word = 5 characters.' },
  'test-score-calculator': { schema: z.object({ raw: z.string(), max: z.string(), curve: z.string() }), fields: [{ name: 'raw', label: 'Raw Score', step: '1', min: 0 }, { name: 'max', label: 'Maximum Possible', step: '1', min: 1 }, { name: 'curve', label: 'Curve Adjustment (+points)', placeholder: '0', step: '1', min: 0 }], compute: (v) => { const curved = n(v.raw) + n(v.curve || '0'); const pct = n(v.max) > 0 ? (curved / n(v.max)) * 100 : 0; return { result: pct, label: 'Curved Score', unit: '%', steps: [`Raw: ${n(v.raw)}`, `Curve: +${n(v.curve || '0')}`, `Curved: ${curved} / ${n(v.max)} = ${pct.toFixed(2)}%`] } }, description: 'Calculate test score with curve adjustment.', formula: 'Score % = (Raw + Curve) / Max × 100', interpretation: 'Curve adjustments compensate for difficult exams. Check your institution curving policy.' },
  'assignment-grade-calculator': { schema: z.object({ earned: z.string(), total: z.string(), weight: z.string() }), fields: [{ name: 'earned', label: 'Points Earned', step: '0.1', min: 0 }, { name: 'total', label: 'Points Possible', step: '0.1', min: 0 }, { name: 'weight', label: 'Assignment Weight (%)', step: '1', min: 0, max: 100 }], compute: (v) => { const pct = n(v.total) > 0 ? (n(v.earned) / n(v.total)) * 100 : 0; const weighted = pct * (n(v.weight) / 100); return { result: weighted, label: 'Weighted Contribution', unit: '%', steps: [`Score: ${n(v.earned)}/${n(v.total)} = ${pct.toFixed(2)}%`, `Weight: ${n(v.weight)}%`, `Contribution to final: ${weighted.toFixed(2)}%`] } }, description: 'Calculate weighted contribution of an assignment to final grade.', formula: 'Weighted = (Earned/Total × 100) × (Weight/100)', interpretation: 'The weighted contribution shows how much this assignment affects your overall grade.' },
  'curve-grade-calculator': { schema: z.object({ raw: z.string(), mean: z.string(), std: z.string(), targetMean: z.string() }), fields: [{ name: 'raw', label: 'Raw Score', step: '0.1', min: 0 }, { name: 'mean', label: 'Class Mean', step: '0.1', min: 0 }, { name: 'std', label: 'Standard Deviation', step: '0.1', min: 0 }, { name: 'targetMean', label: 'Target Mean', step: '0.1', min: 0, placeholder: '75' }], compute: (v) => { const zScore = n(v.std) > 0 ? (n(v.raw) - n(v.mean)) / n(v.std) : 0; const curved = n(v.targetMean || '75') + zScore * n(v.std); return { result: curved, label: 'Curved Score', unit: '%', steps: [`Z-score: (${n(v.raw)} - ${n(v.mean)}) / ${n(v.std)} = ${zScore.toFixed(2)}`, `Curved: ${n(v.targetMean || '75')} + ${zScore.toFixed(2)} × ${n(v.std)} = ${curved.toFixed(2)}%`] } }, description: 'Apply a curve adjustment to a raw score.', formula: 'Curved = TargetMean + ((Raw - Mean) / Std) × Std', interpretation: 'Bell curve adjustment normalizes scores to a target mean. Higher z-scores result in higher curved scores.' },
  'pass-fail-calculator': { schema: z.object({ earned: z.string(), passing: z.string(), total: z.string() }), fields: [{ name: 'earned', label: 'Points Earned', step: '0.1', min: 0 }, { name: 'total', label: 'Total Points', step: '0.1', min: 1 }, { name: 'passing', label: 'Passing Percentage (%)', placeholder: '60', step: '1', min: 0, max: 100 }], compute: (v) => { const pct = n(v.total) > 0 ? (n(v.earned) / n(v.total)) * 100 : 0; const pass = n(v.passing || '60'); const result = pct >= pass ? 'PASS' : 'FAIL'; return { result: result, label: 'Result', unit: '', steps: [`Score: ${pct.toFixed(2)}%`, `Passing threshold: ${pass}%`, `Result: ${result}`] } }, description: 'Determine pass/fail status based on threshold.', formula: 'Pass if: (Earned/Total) × 100 ≥ Passing Threshold', interpretation: 'Pass/fail grading does not differentiate levels of performance within each category.' },
  'extra-credit-calculator': { schema: z.object({ current: z.string(), extra: z.string(), extraMax: z.string(), totalMax: z.string() }), fields: [{ name: 'current', label: 'Current Points', step: '0.1', min: 0 }, { name: 'extra', label: 'Extra Credit Points Earned', step: '0.1', min: 0 }, { name: 'extraMax', label: 'Max Extra Credit Possible', step: '0.1', min: 0 }, { name: 'totalMax', label: 'Total Possible (without extra)', step: '0.1', min: 0 }], compute: (v) => { const newTotal = n(v.current) + n(v.extra); const max = n(v.totalMax) + n(v.extraMax); const pct = max > 0 ? (newTotal / max) * 100 : 0; return { result: pct, label: 'Grade After Extra Credit', unit: '%', steps: [`Before: ${n(v.current)}/${n(v.totalMax)} = ${(n(v.current) / n(v.totalMax) * 100).toFixed(2)}%`, `Extra: +${n(v.extra)}/${n(v.extraMax)}`, `After: ${newTotal.toFixed(1)}/${max.toFixed(1)} = ${pct.toFixed(2)}%`] } }, description: 'Calculate grade after extra credit.', formula: 'New % = (Current + Extra) / (TotalMax + ExtraMax) × 100', interpretation: 'Extra credit can boost grade but maximum benefit depends on available points.' },

  'honors-gpa-calculator': { schema: z.object({ regular: z.string(), honors: z.string(), ap: z.string() }), fields: [{ name: 'regular', label: 'Regular Course Grade Pts (comma-sep)', placeholder: '4,3,3.7' }, { name: 'honors', label: 'Honors Course Grade Pts (comma-sep)', placeholder: '4,3.3' }, { name: 'ap', label: 'AP/IB Course Grade Pts (comma-sep)', placeholder: '4,3.7' }], compute: (v) => { const r = String(v.regular || '').split(',').map(Number).filter(x => !isNaN(x)); const h = String(v.honors || '').split(',').map(Number).filter(x => !isNaN(x)); const a = String(v.ap || '').split(',').map(Number).filter(x => !isNaN(x)); const rPts = r.reduce((s, g) => s + g, 0); const hPts = h.reduce((s, g) => s + g + 0.5, 0); const aPts = a.reduce((s, g) => s + g + 1, 0); const total = rPts + hPts + aPts; const count = r.length + h.length + a.length; const gpa = count > 0 ? total / count : 0; return { result: gpa, label: 'Honors/AP Weighted GPA', unit: '/4.0', steps: [`Regular: ${r.length} courses (pts: ${rPts.toFixed(1)})`, `Honors: ${h.length} courses (+0.5 each, pts: ${hPts.toFixed(1)})`, `AP/IB: ${a.length} courses (+1.0 each, pts: ${aPts.toFixed(1)})`, `Weighted GPA: ${gpa.toFixed(3)}`] } }, description: 'Calculate weighted GPA with honors and AP bonuses.', formula: 'Weighted GPA = (ΣRegular + Σ(Honors+0.5) + Σ(AP+1)) / Total Courses', interpretation: 'Honors = +0.5, AP/IB = +1.0 weight added to the standard 4.0 scale grade points.' },
  'transfer-gpa-calculator': { schema: z.object({ currentGpa: z.string(), currentCredits: z.string(), newGrades: z.string(), newCredits: z.string() }), fields: [{ name: 'currentGpa', label: 'Current GPA', step: '0.01', min: 0, max: 4 }, { name: 'currentCredits', label: 'Current Credits', step: '1', min: 0 }, { name: 'newGrades', label: 'New Grades (comma-sep)', placeholder: '3.7, 4.0' }, { name: 'newCredits', label: 'New Credits (comma-sep)', placeholder: '3, 4' }], compute: (v) => { const cGpa = n(v.currentGpa); const cCred = n(v.currentCredits); const g = String(v.newGrades || '').split(',').map(Number).filter(x => !isNaN(x)); const c = String(v.newCredits || '').split(',').map(Number).filter(x => !isNaN(x)); const newQP = g.reduce((s, gi, i) => s + gi * (c[i] || 0), 0); const totalQP = cGpa * cCred + newQP; const totalCred = cCred + c.reduce((a, b) => a + b, 0); const gpa = totalCred > 0 ? totalQP / totalCred : 0; return { result: gpa, label: 'Transfer Combined GPA', unit: '/4.0', steps: [`Previous: ${cGpa.toFixed(2)} × ${cCred} = ${(cGpa * cCred).toFixed(2)}`, `New: ${newQP.toFixed(2)} quality pts`, `Combined GPA: ${gpa.toFixed(3)}`] } }, description: 'Calculate combined GPA after transferring schools.', formula: 'Combined GPA = (Current QP + New QP) / (Current Credits + New Credits)', interpretation: 'Transfer GPA combines all coursework. Some schools may exclude repeated courses.' },
  'degree-progress-calculator': { schema: z.object({ earned: z.string(), required: z.string(), currentGpa: z.string(), majorGpa: z.string() }), fields: [{ name: 'earned', label: 'Credits Earned', step: '1', min: 0 }, { name: 'required', label: 'Total Credits Required', step: '1', min: 1 }, { name: 'currentGpa', label: 'Current GPA', step: '0.01', min: 0, max: 4 }, { name: 'majorGpa', label: 'Major GPA', step: '0.01', min: 0, max: 4 }], compute: (v) => { const pct = n(v.required) > 0 ? (n(v.earned) / n(v.required)) * 100 : 0; const remaining = Math.max(0, n(v.required) - n(v.earned)); return { result: pct, label: 'Degree Progress', unit: '%', steps: [`Earned: ${n(v.earned)} / ${n(v.required)} credits`, `Remaining: ${remaining} credits`, `Progress: ${pct.toFixed(1)}%`, `Overall GPA: ${n(v.currentGpa).toFixed(2)} | Major GPA: ${n(v.majorGpa).toFixed(2)}`] } }, description: 'Track degree completion progress.', formula: 'Progress % = Credits Earned / Credits Required × 100', interpretation: 'Full-time: 12+ credits/semester. Most bachelor degrees require 120 credits. Check major requirements.' },
  'grade-improvement-calculator': { schema: z.object({ current: z.string(), desired: z.string(), completed: z.string(), total: z.string() }), fields: [{ name: 'current', label: 'Current Grade (%)', step: '0.1', min: 0, max: 100 }, { name: 'desired', label: 'Desired Grade (%)', step: '0.1', min: 0, max: 100 }, { name: 'completed', label: 'Completed Assignments (pts)', step: '1', min: 0 }, { name: 'total', label: 'Total Points Possible', step: '1', min: 1 }], compute: (v) => { const earned = n(v.completed) * (n(v.current) / 100); const remaining = n(v.total) - n(v.completed); const needed = remaining > 0 ? ((n(v.desired) / 100 * n(v.total) - earned) / remaining) * 100 : 0; return { result: needed, label: 'Average Needed on Remaining Work', unit: '%', steps: [`Earned so far: ${earned.toFixed(1)} / ${n(v.completed)} pts`, `Remaining: ${remaining.toFixed(0)} pts`, `Need avg of ${needed.toFixed(2)}% on remaining for ${n(v.desired)}%`] } }, description: 'Calculate the average grade needed on remaining assignments.', formula: 'Needed = ((Desired% × Total) - Earned) / Remaining × 100', interpretation: 'Shows the average percentage required on all future assignments to reach your target.' },
  'midterm-grade-calculator': { schema: z.object({ midterm: z.string(), midtermWeight: z.string(), current: z.string(), desired: z.string() }), fields: [{ name: 'current', label: 'Pre-Midterm Grade (%)', step: '0.1', min: 0, max: 100 }, { name: 'midterm', label: 'Midterm Score (%)', step: '0.1', min: 0, max: 100 }, { name: 'midtermWeight', label: 'Midterm Weight (%)', step: '1', min: 0, max: 100 }, { name: 'desired', label: 'Desired Final Grade (%)', step: '0.1', min: 0, max: 100 }], compute: (v) => { const mw = n(v.midtermWeight) / 100; const cw = 1 - mw; const after = n(v.current) * cw + n(v.midterm) * mw; const remaining = n(v.desired) - after; const needed = 1 - mw - cw > 0 ? remaining / (1 - mw - cw) : 0; return { result: after, label: 'Grade After Midterm', unit: '%', steps: [`Before: ${n(v.current)}% (${(cw * 100).toFixed(0)}% weight)`, `Midterm: ${n(v.midterm)}% (${(mw * 100).toFixed(0)}% weight)`, `After midterm: ${after.toFixed(2)}%`, `Need ${Math.max(0, needed).toFixed(2)}% on rest for ${n(v.desired)}%`] } }, description: 'Calculate grade after midterm exam.', formula: 'After = Current × CW + Midterm × MW', interpretation: 'Midterm weight varies by course (15-30% typical). Remaining components also affect final grade.' },
  'lab-grade-calculator': { schema: z.object({ reports: z.string(), quizzes: z.string(), practical: z.string(), reportWeight: z.string(), quizWeight: z.string() }), fields: [{ name: 'reports', label: 'Avg Lab Report Grade (%)', step: '0.1', min: 0, max: 100 }, { name: 'quizzes', label: 'Avg Lab Quiz Grade (%)', step: '0.1', min: 0, max: 100 }, { name: 'practical', label: 'Practical Exam Grade (%)', step: '0.1', min: 0, max: 100 }, { name: 'reportWeight', label: 'Report Weight (%)', placeholder: '40', step: '1', min: 0, max: 100 }, { name: 'quizWeight', label: 'Quiz Weight (%)', placeholder: '20', step: '1', min: 0, max: 100 }], compute: (v) => { const rw = n(v.reportWeight || '40') / 100; const qw = n(v.quizWeight || '20') / 100; const pw = 1 - rw - qw; const grade = n(v.reports) * rw + n(v.quizzes) * qw + n(v.practical) * pw; return { result: grade, label: 'Lab Grade', unit: '%', steps: [`Reports (${(rw * 100).toFixed(0)}%): ${n(v.reports)}%`, `Quizzes (${(qw * 100).toFixed(0)}%): ${n(v.quizzes)}%`, `Practical (${(pw * 100).toFixed(0)}%): ${n(v.practical)}%`, `Lab grade: ${grade.toFixed(2)}%`] } }, description: 'Calculate overall lab grade from components.', formula: 'Lab Grade = Reports×RW + Quizzes×QW + Practical×(1-RW-QW)', interpretation: 'Lab grades typically weight reports highest (30-50%), with quizzes and practicals making up the balance.' },
  'essay-score-calculator': { schema: z.object({ content: z.string(), organization: z.string(), style: z.string(), mechanics: z.string(), contentWt: z.string() }), fields: [{ name: 'content', label: 'Content Score (0-100)', step: '1', min: 0, max: 100 }, { name: 'organization', label: 'Organization (0-100)', step: '1', min: 0, max: 100 }, { name: 'style', label: 'Style/Voice (0-100)', step: '1', min: 0, max: 100 }, { name: 'mechanics', label: 'Mechanics (0-100)', step: '1', min: 0, max: 100 }, { name: 'contentWt', label: 'Content Weight (%)', placeholder: '40', step: '5', min: 0, max: 100 }], compute: (v) => { const cw = n(v.contentWt || '40') / 100; const rem = (1 - cw) / 3; const score = n(v.content) * cw + n(v.organization) * rem + n(v.style) * rem + n(v.mechanics) * rem; return { result: score, label: 'Essay Score', unit: '%', steps: [`Content (${(cw * 100).toFixed(0)}%): ${n(v.content)}`, `Organization (${(rem * 100).toFixed(0)}%): ${n(v.organization)}`, `Style (${(rem * 100).toFixed(0)}%): ${n(v.style)}`, `Mechanics (${(rem * 100).toFixed(0)}%): ${n(v.mechanics)}`, `Score: ${score.toFixed(2)}%`] } }, description: 'Calculate weighted essay score from rubric components.', formula: 'Score = Content×CW + Org×((1-CW)/3) + Style×R + Mechanics×R', interpretation: 'Rubric-based scoring with adjustable content weight. Remaining 60% split equally among other categories.' },
  'presentation-grade-calculator': { schema: z.object({ delivery: z.string(), content: z.string(), visual: z.string(), qa: z.string() }), fields: [{ name: 'delivery', label: 'Delivery (0-100)', step: '1', min: 0, max: 100 }, { name: 'content', label: 'Content (0-100)', step: '1', min: 0, max: 100 }, { name: 'visual', label: 'Visual Aids (0-100)', step: '1', min: 0, max: 100 }, { name: 'qa', label: 'Q&A (0-100)', step: '1', min: 0, max: 100 }], compute: (v) => { const score = (n(v.delivery) + n(v.content) + n(v.visual) + n(v.qa)) / 4; return { result: score, label: 'Presentation Score', unit: '%', steps: [`Delivery: ${n(v.delivery)}`, `Content: ${n(v.content)}`, `Visual: ${n(v.visual)}`, `Q&A: ${n(v.qa)}`, `Average: ${score.toFixed(2)}%`] } }, description: 'Calculate presentation grade from rubric categories.', formula: 'Score = (Delivery + Content + Visual + Q&A) / 4', interpretation: 'Equal-weight rubric. Adjust weights per course requirements if needed.' },
  'class-participation-calculator': { schema: z.object({ frequency: z.string(), quality: z.string(), initiative: z.string(), maxScore: z.string() }), fields: [{ name: 'frequency', label: 'Frequency Score (0-100)', step: '1', min: 0, max: 100 }, { name: 'quality', label: 'Quality Score (0-100)', step: '1', min: 0, max: 100 }, { name: 'initiative', label: 'Initiative Score (0-100)', step: '1', min: 0, max: 100 }, { name: 'maxScore', label: 'Max Possible', placeholder: '100', step: '1', min: 1 }], compute: (v) => { const score = (n(v.frequency) + n(v.quality) + n(v.initiative)) / 3; const max = n(v.maxScore || '100'); const scaled = score / 100 * max; return { result: scaled, label: 'Participation Grade', unit: `/ ${max.toFixed(0)}`, steps: [`Frequency: ${n(v.frequency)}`, `Quality: ${n(v.quality)}`, `Initiative: ${n(v.initiative)}`, `Average: ${score.toFixed(1)}% = ${scaled.toFixed(1)}/${max.toFixed(0)}`] } }, description: 'Calculate class participation grade.', formula: 'Participation = Avg(Frequency, Quality, Initiative) / 100 × Max', interpretation: 'Participation grading often subjective. Regular meaningful contributions score highest.' },
  'course-load-calculator': { schema: z.object({ courses: z.string(), creditsPer: z.string(), workHours: z.string(), extracurricular: z.string() }), fields: [{ name: 'courses', label: 'Number of Courses', step: '1', min: 1 }, { name: 'creditsPer', label: 'Credits per Course (avg)', step: '1', min: 1, placeholder: '3' }, { name: 'workHours', label: 'Work Hours per Week', step: '1', min: 0 }, { name: 'extracurricular', label: 'Extracurricular Hours/Week', step: '1', min: 0 }], compute: (v) => { const studyHrs = n(v.courses) * (n(v.creditsPer || '3')) * 3; const total = studyHrs + n(v.workHours) + n(v.extracurricular); return { result: total, label: 'Total Weekly Commitment', unit: 'hours', steps: [`Study: ${n(v.courses)} courses × ${n(v.creditsPer || '3')} cr × 3 hr/cr = ${studyHrs} hr`, `Work: ${n(v.workHours)} hr`, `Activities: ${n(v.extracurricular)} hr`, `Total: ${total} hr/week`] } }, description: 'Calculate total weekly time commitment.', formula: 'Total = (Courses × Credits × 3) + Work + Extracurricular', interpretation: 'General guideline: 3 hours of study per credit hour per week. 40-50 hr total is typical for full-time students.' },
  'graduation-gpa-calculator': { schema: z.object({ currentGpa: z.string(), completedCredits: z.string(), remainingCredits: z.string(), targetGpa: z.string() }), fields: [{ name: 'currentGpa', label: 'Current GPA', step: '0.01', min: 0, max: 4 }, { name: 'completedCredits', label: 'Completed Credits', step: '1', min: 0 }, { name: 'remainingCredits', label: 'Remaining Credits', step: '1', min: 1 }, { name: 'targetGpa', label: 'Target Graduation GPA', step: '0.01', min: 0, max: 4 }], compute: (v) => { const curQP = n(v.currentGpa) * n(v.completedCredits); const totalCredits = n(v.completedCredits) + n(v.remainingCredits); const targetQP = n(v.targetGpa) * totalCredits; const neededGpa = n(v.remainingCredits) > 0 ? (targetQP - curQP) / n(v.remainingCredits) : 0; return { result: neededGpa, label: 'GPA Needed on Remaining Credits', unit: '/4.0', steps: [`Current: ${n(v.currentGpa).toFixed(2)} × ${n(v.completedCredits)} = ${curQP.toFixed(2)} QP`, `Target: ${n(v.targetGpa).toFixed(2)} × ${totalCredits} = ${targetQP.toFixed(2)} QP`, `Need: ${neededGpa.toFixed(3)} GPA on remaining ${n(v.remainingCredits)} credits`] } }, description: 'Calculate GPA needed in remaining credits to reach graduation target.', formula: 'Needed GPA = (Target × Total - Current GPA × Completed) / Remaining', interpretation: 'Higher remaining credits make target more achievable. Consider retaking low grades to boost GPA.' },
  'repeat-course-calculator': { schema: z.object({ original: z.string(), originalCredits: z.string(), newGrade: z.string(), totalCredits: z.string(), currentGpa: z.string() }), fields: [{ name: 'original', label: 'Original Grade (grade pts)', step: '0.1', min: 0, max: 4 }, { name: 'originalCredits', label: 'Course Credits', step: '1', min: 1 }, { name: 'newGrade', label: 'New Grade (grade pts)', step: '0.1', min: 0, max: 4 }, { name: 'currentGpa', label: 'Current Overall GPA', step: '0.01', min: 0, max: 4 }, { name: 'totalCredits', label: 'Total Credits (including this)', step: '1', min: 1 }], compute: (v) => { const oldQP = n(v.original) * n(v.originalCredits); const newQP = n(v.newGrade) * n(v.originalCredits); const totalQP = n(v.currentGpa) * n(v.totalCredits) - oldQP + newQP; const newGpa = n(v.totalCredits) > 0 ? totalQP / n(v.totalCredits) : 0; return { result: newGpa, label: 'New GPA After Replacement', unit: '/4.0', steps: [`Original: ${n(v.original).toFixed(1)} × ${n(v.originalCredits)} = ${oldQP.toFixed(1)} QP`, `New: ${n(v.newGrade).toFixed(1)} × ${n(v.originalCredits)} = ${newQP.toFixed(1)} QP`, `Old GPA: ${n(v.currentGpa).toFixed(3)}`, `New GPA: ${newGpa.toFixed(3)}`] } }, description: 'Calculate GPA after repeating a course (grade replacement).', formula: 'New GPA = (Current GPA × Total Credits - Old + New) / Total Credits', interpretation: 'Grade replacement policies vary. Some schools replace, others average. Check your institution policy.' },
  'summer-school-grade-calculator': { schema: z.object({ assignments: z.string(), exams: z.string(), participation: z.string(), compressedWt: z.string() }), fields: [{ name: 'assignments', label: 'Assignment Avg (%)', step: '0.1', min: 0, max: 100 }, { name: 'exams', label: 'Exam Avg (%)', step: '0.1', min: 0, max: 100 }, { name: 'participation', label: 'Participation (%)', step: '0.1', min: 0, max: 100 }, { name: 'compressedWt', label: 'Exam Weight (%)', placeholder: '50', step: '5', min: 0, max: 100 }], compute: (v) => { const ew = n(v.compressedWt || '50') / 100; const aw = 1 - ew - 0.1; const pw = 0.1; const grade = n(v.assignments) * aw + n(v.exams) * ew + n(v.participation) * pw; return { result: grade, label: 'Summer School Grade', unit: '%', steps: [`Assignments (${(aw * 100).toFixed(0)}%): ${n(v.assignments)}%`, `Exams (${(ew * 100).toFixed(0)}%): ${n(v.exams)}%`, `Participation (${(pw * 100).toFixed(0)}%): ${n(v.participation)}%`, `Grade: ${grade.toFixed(2)}%`] } }, description: 'Calculate grade for accelerated summer courses.', formula: 'Grade = Assignments×(1-EW-0.1) + Exams×EW + Participation×0.1', interpretation: 'Summer courses are compressed: same content in fewer weeks. Weighting may differ from regular semester.' },
  'academic-probation-calculator': { schema: z.object({ currentGpa: z.string(), attemptedCredits: z.string(), newGrades: z.string(), newCredits: z.string(), minGpa: z.string() }), fields: [{ name: 'currentGpa', label: 'Current GPA', step: '0.01', min: 0, max: 4 }, { name: 'attemptedCredits', label: 'Attempted Credits', step: '1', min: 0 }, { name: 'newGrades', label: 'New Term Grades (comma-sep)', placeholder: '3.0, 2.7, 3.3' }, { name: 'newCredits', label: 'New Term Credits (comma-sep)', placeholder: '3, 4, 3' }, { name: 'minGpa', label: 'Minimum GPA Required', placeholder: '2.0', step: '0.1', min: 0, max: 4 }], compute: (v) => { const curQP = n(v.currentGpa) * n(v.attemptedCredits); const g = String(v.newGrades || '').split(',').map(Number).filter(x => !isNaN(x)); const c = String(v.newCredits || '').split(',').map(Number).filter(x => !isNaN(x)); const newQP = g.reduce((s, gi, i) => s + gi * (c[i] || 0), 0); const totalCredits = n(v.attemptedCredits) + c.reduce((a, b) => a + b, 0); const gpa = totalCredits > 0 ? (curQP + newQP) / totalCredits : 0; const min = n(v.minGpa || '2.0'); return { result: gpa, label: 'Projected GPA', unit: '/4.0', steps: [`Before: ${n(v.currentGpa).toFixed(2)}`, `New term QP: ${newQP.toFixed(2)}`, `Projected GPA: ${gpa.toFixed(3)}`, gpa >= min ? '✓ Above minimum — good standing' : `✗ Below ${min.toFixed(1)} — risk of probation`] } }, description: 'Calculate GPA and academic standing risk.', formula: 'Projected GPA = (Current GPA × Attempted + New QP) / (Attempted + New Credits)', interpretation: 'Most schools require 2.0 minimum GPA. Below that may result in academic probation or suspension.' },
  'dean-list-calculator': { schema: z.object({ termGpa: z.string(), minGpa: z.string(), completedCredits: z.string(), minCredits: z.string() }), fields: [{ name: 'termGpa', label: 'Term GPA', step: '0.01', min: 0, max: 4 }, { name: 'minGpa', label: 'Dean List Min GPA', placeholder: '3.5', step: '0.1', min: 0, max: 4 }, { name: 'completedCredits', label: 'Term Credits', step: '1', min: 0 }, { name: 'minCredits', label: 'Min Credits Required', placeholder: '12', step: '1', min: 1 }], compute: (v) => { const eligible = n(v.termGpa) >= n(v.minGpa || '3.5') && n(v.completedCredits) >= n(v.minCredits || '12'); return { result: eligible ? 'YES - Eligible' : 'Not Eligible', label: 'Dean List Status', unit: '', steps: [`Term GPA: ${n(v.termGpa).toFixed(2)} (need ${n(v.minGpa || '3.5').toFixed(1)})`, `Credits: ${n(v.completedCredits)} (need ${n(v.minCredits || '12')})`, eligible ? 'Qualified' : 'Not qualified'] } }, description: 'Check Dean List eligibility.', formula: 'Eligible if: Term GPA = Min GPA AND Credits = Min Credits', interpretation: 'Dean List requirements vary: typically top 10-15% of class or GPA above 3.5 with full-time enrollment.' },

  'gpa-semester': { schema: z.object({ courseGrades: z.string(), courseCredits: z.string() }), fields: [{ name: 'courseGrades', label: 'Grade Points (comma-sep)', placeholder: '4,3.7,3.3' }, { name: 'courseCredits', label: 'Credits (comma-sep)', placeholder: '3,3,4' }], compute: (v) => { const g = String(v.courseGrades||'').split(',').map(Number).filter(x=>!isNaN(x)); const c = String(v.courseCredits||'').split(',').map(Number).filter(x=>!isNaN(x)); const qp = g.reduce((s,gi,i)=>s+gi*(c[i]||0),0); const tc = c.reduce((a,b)=>a+b,0); return { result: tc>0?qp/tc:0, label: 'Semester GPA', unit: '/4.0', steps: [`QP: ${qp.toFixed(2)}`, `Credits: ${tc}`, `GPA: ${(tc>0?qp/tc:0).toFixed(3)}`] } }, description: 'Calculate semester GPA from course grades.', formula: 'GPA = (Grade x Credits) / Credits', interpretation: 'Standard 4.0 scale. A=4, A-=3.7, B+=3.3, B=3, etc.' },

  'cumulative-gpa': { schema: z.object({ semesterGpas: z.string(), semesterCredits: z.string() }), fields: [{ name: 'semesterGpas', label: 'Semester GPAs (comma-sep)', placeholder: '3.5,3.8,3.6' }, { name: 'semesterCredits', label: 'Semester Credits (comma-sep)', placeholder: '15,16,15' }], compute: (v) => { const g = String(v.semesterGpas||'').split(',').map(Number).filter(x=>!isNaN(x)); const c = String(v.semesterCredits||'').split(',').map(Number).filter(x=>!isNaN(x)); const qp = g.reduce((s,gi,i)=>s+gi*(c[i]||0),0); const tc = c.reduce((a,b)=>a+b,0); return { result: tc>0?qp/tc:0, label: 'Cumulative GPA', unit: '/4.0', steps: [`Semesters: ${g.length}`, `QP: ${qp.toFixed(2)}`, `Credits: ${tc}`, `GPA: ${(tc>0?qp/tc:0).toFixed(3)}`] } }, description: 'Cumulative GPA across semesters.', formula: 'GPA = (SemGPA x Credits) / Credits', interpretation: 'Combines all semesters with credit weighting.' },

  'weighted-gpa': { schema: z.object({ grades: z.string(), weights: z.string() }), fields: [{ name: 'grades', label: 'Grade Points (comma-sep)', placeholder: '4,3.7,3.3' }, { name: 'weights', label: 'Weights (comma-sep)', placeholder: '1,1.5,1' }], compute: (v) => { const g = String(v.grades||'').split(',').map(Number).filter(x=>!isNaN(x)); const w = String(v.weights||'').split(',').map(Number).filter(x=>!isNaN(x)); const ws = g.reduce((s,gi,i)=>s+gi*(w[i]||0),0); const tw = w.reduce((a,b)=>a+b,0); return { result: tw>0?ws/tw:0, label: 'Weighted GPA', unit: '/4.0', steps: [`Sum: ${ws.toFixed(2)}`, `Weight: ${tw}`, `GPA: ${(tw>0?ws/tw:0).toFixed(3)}`] } }, description: 'Weighted GPA with custom weights.', formula: 'WGPA = (Grade x Weight) / Weight', interpretation: 'Honors/AP courses typically weighted 1.5x.' },

  'unweighted-gpa': { schema: z.object({ letterGrades: z.string() }), fields: [{ name: 'letterGrades', label: 'Letter Grades (comma-sep)', placeholder: 'A,B+,A-,B' }], compute: (v) => { const m: Record<string,number> = {'A':4,'A-':3.7,'B+':3.3,'B':3,'B-':2.7,'C+':2.3,'C':2,'D':1,'F':0}; const g = String(v.letterGrades||'').split(',').map(s=>m[s.trim().toUpperCase()]??0); return { result: g.length>0?g.reduce((a,b)=>a+b,0)/g.length:0, label: 'Unweighted GPA', unit: '/4.0', steps: [`Courses: ${g.length}`, `Total: ${g.reduce((a,b)=>a+b,0).toFixed(1)}`, `GPA: ${(g.length>0?g.reduce((a,b)=>a+b,0)/g.length:0).toFixed(3)}`] } }, description: 'Unweighted GPA on standard 4.0 scale.', formula: 'GPA = GradePoints / Courses', interpretation: 'No honors/AP bonus. A=4, B=3, C=2, D=1, F=0.' },

  'percentage-to-gpa': { schema: z.object({ pct: z.string() }), fields: [{ name: 'pct', label: 'Percentage', step: 0.1, min: 0, max: 100 }], compute: (v) => { const p = n(v.pct); const gpa = p>=93?4:p>=90?3.7:p>=87?3.3:p>=83?3:p>=80?2.7:p>=77?2.3:p>=73?2:p>=70?1.7:p>=67?1.3:p>=63?1:p>=60?0.7:0; return { result: gpa, label: 'GPA Equivalent', unit: '/4.0', steps: [`${p}% = ${gpa.toFixed(1)} GPA`] } }, description: 'Convert percentage to GPA.', formula: 'Standard conversion table.', interpretation: '93%+=4.0, 90-92%=3.7, 87-89%=3.3, 83-86%=3.0, etc.' },

  'letter-grade-average': { schema: z.object({ grades: z.string() }), fields: [{ name: 'grades', label: 'Letter Grades (comma-sep)', placeholder: 'A,B+,B,A-' }], compute: (v) => { const m: Record<string,number> = {'A':4,'A-':3.7,'B+':3.3,'B':3,'B-':2.7,'C+':2.3,'C':2,'D':1,'F':0}; const g = String(v.grades||'').split(',').map(s=>m[s.trim().toUpperCase()]??0); const avg = g.length>0?g.reduce((a,b)=>a+b,0)/g.length:0; return { result: avg, label: 'Avg Grade Points', unit: '/4.0', steps: [`Avg: ${avg.toFixed(2)}`, `Equivalent: ${avg>=3.7?'A':avg>=3.3?'B+':avg>=3?'B':avg>=2.3?'C+':avg>=2?'C':avg>=1?'D':'F'}`] } }, description: 'Average letter grade from multiple courses.', formula: 'Average = GradePoints / Count', interpretation: 'A=4.0, B=3.0, C=2.0, D=1.0, F=0.0.' },

  'final-grade-needed': { schema: z.object({ current: z.string(), desired: z.string(), finalWt: z.string() }), fields: [{ name: 'current', label: 'Current Grade (%)', step: 0.1, min: 0, max: 100 }, { name: 'desired', label: 'Desired Grade (%)', step: 0.1, min: 0, max: 100 }, { name: 'finalWt', label: 'Final Weight (%)', step: 1, min: 0, max: 100 }], compute: (v) => { const fw = n(v.finalWt)/100; const need = fw>0?(n(v.desired)-n(v.current)*(1-fw))/fw:0; return { result: need, label: 'Needed on Final', unit: '%', steps: [`Need: ${need.toFixed(1)}%`, need>100?'Target may be unreachable':''] } }, description: 'Grade needed on final exam.', formula: 'Need = (Desired - Current x (1-W)) / W', interpretation: 'Result >100% means target is unreachable.' },

  'grade-calculator-semester': { schema: z.object({ g1: z.string(), g2: z.string(), g3: z.string(), g4: z.string(), g5: z.string() }), fields: [{ name: 'g1', label: 'Course 1 Grade (%)', step: 0.1, min: 0, max: 100 }, { name: 'g2', label: 'Course 2 Grade (%)', step: 0.1, min: 0, max: 100 }, { name: 'g3', label: 'Course 3 Grade (%)', step: 0.1, min: 0, max: 100 }, { name: 'g4', label: 'Course 4 Grade (%)', step: 0.1, min: 0, max: 100 }, { name: 'g5', label: 'Course 5 Grade (%)', step: 0.1, min: 0, max: 100 }], compute: (v) => { const grades = [n(v.g1),n(v.g2),n(v.g3),n(v.g4),n(v.g5)].filter(x=>x>0); const avg = grades.length>0?grades.reduce((a,b)=>a+b,0)/grades.length:0; return { result: avg, label: 'Semester Avg', unit: '%', steps: [`Courses: ${grades.length}`, `Avg: ${avg.toFixed(2)}%`] } }, description: 'Average grade across semester courses.', formula: 'Avg = Grades / Courses', interpretation: 'All courses weighted equally in average calculation.' },

  'gpa-planner': { schema: z.object({ targetGpa: z.string(), currentGpa: z.string(), currentCredits: z.string(), plannedCredits: z.string() }), fields: [{ name: 'currentGpa', label: 'Current GPA', step: 0.01, min: 0, max: 4 }, { name: 'currentCredits', label: 'Earned Credits', step: 1, min: 0 }, { name: 'plannedCredits', label: 'Planned Credits', step: 1, min: 1 }, { name: 'targetGpa', label: 'Target GPA', step: 0.01, min: 0, max: 4 }], compute: (v) => { const curQP = n(v.currentGpa)*n(v.currentCredits); const totCred = n(v.currentCredits)+n(v.plannedCredits); const need = n(v.plannedCredits)>0?(n(v.targetGpa)*totCred-curQP)/n(v.plannedCredits):0; return { result: need, label: 'GPA Needed', unit: '/4.0', steps: [`Need: ${need.toFixed(3)}`, need>4?'Target unreachable':need>3.5?'Stretch goal':'Achievable'] } }, description: 'Plan GPA for future semesters.', formula: 'Need = (Target x Total - CurrentQP) / Planned', interpretation: 'Shows GPA required on future courses to reach target.' },

  'class-rank-calc': { schema: z.object({ gpa: z.string(), classSize: z.string(), percentile: z.string() }), fields: [{ name: 'gpa', label: 'GPA', step: 0.01, min: 0, max: 4 }, { name: 'classSize', label: 'Class Size', step: 1, min: 1 }, { name: 'percentile', label: 'Est. Percentile', placeholder: '75', step: 1, min: 0, max: 100 }], compute: (v) => { const r = Math.round(n(v.classSize)*(1-(n(v.percentile)||75)/100)+1); return { result: r, label: 'Est. Rank', unit: '', steps: [`Rank: ${r} of ${n(v.classSize)}`, `Top ${(100-(n(v.percentile)||75)).toFixed(0)}%`] } }, description: 'Estimate class rank from percentile.', formula: 'Rank = ClassSize x (1-Percentile/100) + 1', interpretation: 'Top 10% = rank in top 10% of class.' },

  'honors-calc': { schema: z.object({ regular: z.string(), honors: z.string(), ap: z.string() }), fields: [{ name: 'regular', label: 'Regular Grades (comma-sep)', placeholder: '4,3,3.7' }, { name: 'honors', label: 'Honors Grades (comma-sep)', placeholder: '4,3.3' }, { name: 'ap', label: 'AP Grades (comma-sep)', placeholder: '4,3.7' }], compute: (v) => { const r = String(v.regular||'').split(',').map(Number).filter(x=>!isNaN(x)); const h = String(v.honors||'').split(',').map(Number).filter(x=>!isNaN(x)); const a = String(v.ap||'').split(',').map(Number).filter(x=>!isNaN(x)); const pts = r.reduce((s,g)=>s+g,0)+h.reduce((s,g)=>s+g+0.5,0)+a.reduce((s,g)=>s+g+1,0); const cnt = r.length+h.length+a.length; return { result: cnt>0?pts/cnt:0, label: 'Weighted GPA', unit: '/4.0', steps: [`Pts: ${pts.toFixed(1)}`, `Courses: ${cnt}`, `GPA: ${(cnt>0?pts/cnt:0).toFixed(3)}`] } }, description: 'Weighted GPA with honors/AP bonuses.', formula: '+0.5 honors, +1.0 AP on 4.0 scale.', interpretation: 'Honors +0.5, AP/IB +1.0 weight bonus.' },

  'professor-rating': { schema: z.object({ clarity: z.string(), helpfulness: z.string(), difficulty: z.string(), grading: z.string() }), fields: [{ name: 'clarity', label: 'Clarity (1-5)', step: 1, min: 1, max: 5 }, { name: 'helpfulness', label: 'Helpfulness (1-5)', step: 1, min: 1, max: 5 }, { name: 'difficulty', label: 'Difficulty (1-5)', step: 1, min: 1, max: 5 }, { name: 'grading', label: 'Fairness (1-5)', step: 1, min: 1, max: 5 }], compute: (v) => { const r = (n(v.clarity)+n(v.helpfulness)+n(v.grading)-n(v.difficulty)+4)/4; return { result: r, label: 'Overall Rating', unit: '/5', steps: [`Quality: ${((n(v.clarity)+n(v.helpfulness)+n(v.grading))/3).toFixed(1)}`, `Difficulty: ${n(v.difficulty)}`, `Rating: ${r.toFixed(1)}/5`] } }, description: 'Overall professor rating from student feedback.', formula: 'Rating = (Clarity+Helpfulness+Fairness-Difficulty+4)/4', interpretation: 'Adjusts for difficulty. Higher = better rated.' },

  'honor-roll': { schema: z.object({ termGpa: z.string(), minGpa: z.string(), credits: z.string(), minCredits: z.string() }), fields: [{ name: 'termGpa', label: 'Term GPA', step: 0.01, min: 0, max: 4 }, { name: 'minGpa', label: 'Min GPA', placeholder: '3.5', step: 0.1, min: 0, max: 4 }, { name: 'credits', label: 'Credits', step: 1, min: 0 }, { name: 'minCredits', label: 'Min Credits', placeholder: '12', step: 1, min: 1 }], compute: (v) => { const e = n(v.termGpa)>=n(v.minGpa||'3.5')&&n(v.credits)>=n(v.minCredits||'12'); return { result: e?'Eligible':'Not eligible', label: 'Status', unit: '', steps: [`GPA: ${n(v.termGpa).toFixed(2)}/${n(v.minGpa||'3.5').toFixed(1)}`, `Credits: ${n(v.credits)}/${n(v.minCredits||'12')}`] } }, description: 'Check honor roll eligibility.', formula: 'GPA>=Min AND Credits>=Min', interpretation: 'Typically 3.5+ GPA with full-time enrollment.' },

  'graduation-requirements': { schema: z.object({ earned: z.string(), required: z.string(), majorEarned: z.string(), majorRequired: z.string() }), fields: [{ name: 'earned', label: 'Total Credits Earned', step: 1, min: 0 }, { name: 'required', label: 'Total Required', step: 1, min: 1 }, { name: 'majorEarned', label: 'Major Credits Earned', step: 1, min: 0 }, { name: 'majorRequired', label: 'Major Credits Required', step: 1, min: 1 }], compute: (v) => { const pct = n(v.required)>0?n(v.earned)/n(v.required)*100:0; const mPct = n(v.majorRequired)>0?n(v.majorEarned)/n(v.majorRequired)*100:0; return { result: pct, label: 'Total Progress', unit: '%', steps: [`Total: ${n(v.earned)}/${n(v.required)} (${pct.toFixed(1)}%)`, `Major: ${n(v.majorEarned)}/${n(v.majorRequired)} (${mPct.toFixed(1)}%)`] } }, description: 'Track graduation requirements progress.', formula: 'Progress = Earned/Required x 100', interpretation: 'Most Bachelors: 120 total, ~30-40 major credits.' },

  'sat-score': { schema: z.object({ math: z.string(), ebRw: z.string() }), fields: [{ name: 'math', label: 'Math (200-800)', step: 10, min: 200, max: 800 }, { name: 'ebRw', label: 'EBRW (200-800)', step: 10, min: 200, max: 800 }], compute: (v) => ({ result: n(v.math)+n(v.ebRw), label: 'SAT Total', unit: '/1600', steps: [`Math: ${n(v.math)}`, `EBRW: ${n(v.ebRw)}`, `Total: ${n(v.math)+n(v.ebRw)}/1600`] }), description: 'Total SAT score (current 1600 scale).', formula: 'Total = Math + EBRW', interpretation: 'Current SAT: 400-1600 scale. Each section 200-800.' },

  'act-score': { schema: z.object({ english: z.string(), math: z.string(), reading: z.string(), science: z.string() }), fields: [{ name: 'english', label: 'English (1-36)', step: 1, min: 1, max: 36 }, { name: 'math', label: 'Math (1-36)', step: 1, min: 1, max: 36 }, { name: 'reading', label: 'Reading (1-36)', step: 1, min: 1, max: 36 }, { name: 'science', label: 'Science (1-36)', step: 1, min: 1, max: 36 }], compute: (v) => ({ result: (n(v.english)+n(v.math)+n(v.reading)+n(v.science))/4, label: 'ACT Composite', unit: '/36', steps: [`Avg: ${((n(v.english)+n(v.math)+n(v.reading)+n(v.science))/4).toFixed(2)}/36`] }), description: 'Calculate ACT composite score.', formula: 'Composite = (E+M+R+S)/4', interpretation: 'ACT 1-36 per section. Composite rounded to nearest whole.' },

  'sat-act-conversion': { schema: z.object({ testType: z.string(), score: z.string() }), fields: [{ name: 'testType', label: 'From Test', type: 'select', options: [{ label: 'SAT to ACT', value: 'sat2act' }, { label: 'ACT to SAT', value: 'act2sat' }] }, { name: 'score', label: 'Score', step: 10, min: 0 }], compute: (v) => { const s = n(v.score); const isSat = v.testType=='sat2act'; const conv = isSat?Math.round((s-400)/120*36/9+9):Math.round((s-1)*120/36+400); return { result: conv, label: isSat?'ACT Equivalent':'SAT Equivalent', unit: '', steps: [`${isSat?'SAT':'ACT'}: ${s}`, `≈ ${conv}`] } }, description: 'Convert between SAT and ACT scores.', formula: 'Concordance tables from College Board/ACT.', interpretation: 'SAT 1200 ≈ ACT 24. Rough concordance, not exact.' },

  'gre-score': { schema: z.object({ verbal: z.string(), quant: z.string() }), fields: [{ name: 'verbal', label: 'Verbal (130-170)', step: 1, min: 130, max: 170 }, { name: 'quant', label: 'Quant (130-170)', step: 1, min: 130, max: 170 }], compute: (v) => ({ result: `${n(v.verbal)}V, ${n(v.quant)}Q`, label: 'GRE Scores', unit: '', steps: [`V: ${n(v.verbal)}/170`, `Q: ${n(v.quant)}/170`] }), description: 'GRE section scores overview.', formula: 'GRE: Verbal 130-170, Quant 130-170.', interpretation: 'GRE scores valid 5 years. No composite.' },

  'gmat-score': { schema: z.object({ verbal: z.string(), quant: z.string() }), fields: [{ name: 'verbal', label: 'Verbal (0-60)', step: 1, min: 0, max: 60 }, { name: 'quant', label: 'Quant (0-60)', step: 1, min: 0, max: 60 }], compute: (v) => ({ result: n(v.verbal)+n(v.quant), label: 'GMAT Total', unit: '/800', steps: [`V: ${n(v.verbal)}`, `Q: ${n(v.quant)}`, `Total: ${n(v.verbal)+n(v.quant)}/800`] }), description: 'GMAT total score from sections.', formula: 'Total = Verbal + Quant (200-800)', interpretation: 'GMAT: V+Q 200-800. IR 1-8, AWA 0-6 separately.' },

  'lsat-score': { schema: z.object({ lr: z.string(), lg: z.string(), rc: z.string() }), fields: [{ name: 'lr', label: 'Logical Reasoning', step: 1, min: 0, max: 25 }, { name: 'lg', label: 'Logic Games', step: 1, min: 0, max: 23 }, { name: 'rc', label: 'Reading Comp', step: 1, min: 0, max: 27 }], compute: (v) => ({ result: n(v.lr)+n(v.lg)+n(v.rc), label: 'Raw Score', unit: '/75', steps: [`LR: ${n(v.lr)}`, `LG: ${n(v.lg)}`, `RC: ${n(v.rc)}`, `Raw: ${n(v.lr)+n(v.lg)+n(v.rc)}/75`] }), description: 'LSAT raw score from section counts.', formula: 'Raw = LR + LG + RC (max 75)', interpretation: 'Raw converted to scaled 120-180. 150=median.' },

  'mcat-score': { schema: z.object({ cp: z.string(), cars: z.string(), bio: z.string(), ps: z.string() }), fields: [{ name: 'cp', label: 'Chem/Phys', step: 1, min: 118, max: 132 }, { name: 'cars', label: 'CARS', step: 1, min: 118, max: 132 }, { name: 'bio', label: 'Bio/Biochem', step: 1, min: 118, max: 132 }, { name: 'ps', label: 'Psych/Soc', step: 1, min: 118, max: 132 }], compute: (v) => ({ result: n(v.cp)+n(v.cars)+n(v.bio)+n(v.ps), label: 'MCAT Total', unit: '/528', steps: [`Total: ${n(v.cp)+n(v.cars)+n(v.bio)+n(v.ps)}/528`] }), description: 'MCAT total from section scores.', formula: 'Total = CP + CARS + BB + PS', interpretation: 'Each section 118-132. Total 472-528.' },

  'toefl-score': { schema: z.object({ reading: z.string(), listening: z.string(), speaking: z.string(), writing: z.string() }), fields: [{ name: 'reading', label: 'Reading (0-30)', step: 1, min: 0, max: 30 }, { name: 'listening', label: 'Listening (0-30)', step: 1, min: 0, max: 30 }, { name: 'speaking', label: 'Speaking (0-30)', step: 1, min: 0, max: 30 }, { name: 'writing', label: 'Writing (0-30)', step: 1, min: 0, max: 30 }], compute: (v) => ({ result: n(v.reading)+n(v.listening)+n(v.speaking)+n(v.writing), label: 'TOEFL Total', unit: '/120', steps: [`Total: ${n(v.reading)+n(v.listening)+n(v.speaking)+n(v.writing)}/120`] }), description: 'TOEFL iBT total score.', formula: 'Total = R+L+S+W (0-120)', interpretation: 'Each section 0-30. Most unis require 80-100+. 100+=competitive.' },

  'ielts-score': { schema: z.object({ listening: z.string(), reading: z.string(), writing: z.string(), speaking: z.string() }), fields: [{ name: 'listening', label: 'Listening (0-9)', step: 0.5, min: 0, max: 9 }, { name: 'reading', label: 'Reading (0-9)', step: 0.5, min: 0, max: 9 }, { name: 'writing', label: 'Writing (0-9)', step: 0.5, min: 0, max: 9 }, { name: 'speaking', label: 'Speaking (0-9)', step: 0.5, min: 0, max: 9 }], compute: (v) => ({ result: (n(v.listening)+n(v.reading)+n(v.writing)+n(v.speaking))/4, label: 'IELTS Overall', unit: '/9', steps: [`Band: ${((n(v.listening)+n(v.reading)+n(v.writing)+n(v.speaking))/4).toFixed(1)}/9`] }), description: 'IELTS overall band score.', formula: 'Overall = (L+R+W+S)/4', interpretation: 'Each band 0-9. 7.0+=good, 8.0+=excellent. Min 6.0-6.5 typical.' },

  'ap-exam-score': { schema: z.object({ score: z.string() }), fields: [{ name: 'score', label: 'AP Score', type: 'select', options: [{ label: '5 - Extremely well', value: '5' }, { label: '4 - Well', value: '4' }, { label: '3 - Qualified', value: '3' }, { label: '2 - Possibly', value: '2' }, { label: '1 - No recommendation', value: '1' }] }], compute: (v) => { const s = n(v.score); const d: Record<number,string> = {5:'Extremely well qualified',4:'Well qualified',3:'Qualified',2:'Possibly qualified',1:'No recommendation'}; return { result: d[s]||'', label: 'AP Score', unit: '', steps: [`Score: ${s}`, d[s]||'', s>=3?'Usually grants college credit':'Check policy'] } }, description: 'AP score interpretation.', formula: 'AP 1-5 scale.', interpretation: 'Score 3+ often grants college credit.' },

  'ib-score': { schema: z.object({ score: z.string() }), fields: [{ name: 'score', label: 'IB Score (1-7)', type: 'select', options: [{ label: '7', value: '7' }, { label: '6', value: '6' }, { label: '5', value: '5' }, { label: '4', value: '4' }, { label: '3', value: '3' }, { label: '2', value: '2' }, { label: '1', value: '1' }] }], compute: (v) => { const d: Record<number,string> = {7:'Excellent',6:'Very Good',5:'Good',4:'Satisfactory',3:'Mediocre',2:'Poor',1:'Very Poor'}; return { result: `${n(v.score)}: ${d[n(v.score)]||''}`, label: 'IB Score', unit: '', steps: [`Score: ${n(v.score)}`, d[n(v.score)]||'', n(v.score)>=4?'Often grants credit':'Below passing'] } }, description: 'IB score interpretation.', formula: 'IB 1-7 per subject.', interpretation: '4+ is passing. Diploma: 24+ total across 6 subjects.' },

  'clep-score': { schema: z.object({ score: z.string() }), fields: [{ name: 'score', label: 'CLEP Score (20-80)', step: 1, min: 20, max: 80 }], compute: (v) => { const s = n(v.score); const rec = s>=50?'Likely credit eligible':'Check institution policy'; return { result: s, label: 'CLEP Score', unit: '/80', steps: [`Score: ${s}`, rec, `ACE rec: 50 for most exams`] } }, description: 'CLEP score interpretation.', formula: 'CLEP scored 20-80.', interpretation: 'ACE recommends 50+ for credit. Policies vary by college.' },

  'college-admission-chance': { schema: z.object({ gpa: z.string(), sat: z.string(), act: z.string(), rank: z.string(), activities: z.string() }), fields: [{ name: 'gpa', label: 'GPA (4.0 scale)', step: 0.01, min: 0, max: 4 }, { name: 'sat', label: 'SAT Score', step: 10, min: 400, max: 1600 }, { name: 'act', label: 'ACT Score', step: 1, min: 1, max: 36 }, { name: 'rank', label: 'Class Rank (top %)', step: 1, min: 0, max: 100, placeholder: '25' }, { name: 'activities', label: 'Extracurricular Score (1-10)', step: 1, min: 1, max: 10, placeholder: '7' }], compute: (v) => { const score = n(v.gpa)/4*30+Math.min(n(v.sat)/1600*25,25)+Math.min(n(v.act)/36*25,25)+Math.max(0,1-n(v.rank||'50')/100)*10+(n(v.activities||'5')/10)*10; const pct = Math.min(95,Math.max(5,score)); const cat = pct>=80?'High':pct>=50?'Moderate':pct>=25?'Reach':'Low'; return { result: pct, label: 'Admission Chance Est.', unit: '%', steps: [`Score: ${score.toFixed(0)}/100`, `Chance: ${cat} (${pct.toFixed(0)}%)`] } }, description: 'Estimate college admission chance.', formula: 'Weighted composite of GPA, test scores, rank, activities.', interpretation: 'Rough estimate. Holistic review includes essays, recs, demonstrated interest.' },

  'college-early-decision': { schema: z.object({ regular: z.string(), earlyPct: z.string() }), fields: [{ name: 'regular', label: 'Regular Acceptance Rate (%)', step: 0.1, min: 0, max: 100 }, { name: 'earlyPct', label: 'ED/EA Boost (%)', placeholder: '10', step: 1, min: 0, max: 50 }], compute: (v) => { const ed = n(v.regular)+n(v.earlyPct||'10'); return { result: ed, label: 'Est. ED/EA Rate', unit: '%', steps: [`Regular: ${n(v.regular)}%`, `ED/EA: ~${ed.toFixed(1)}%`, `Boost: +${(ed-n(v.regular)).toFixed(1)}%`] } }, description: 'Estimate early decision/action acceptance rate.', formula: 'ED Rate = Regular Rate + Boost', interpretation: 'ED typically 10-15% higher. EA boost smaller. Binding ED increases chances.' },

  'college-early-action': { schema: z.object({ regular: z.string(), eaPct: z.string() }), fields: [{ name: 'regular', label: 'Regular Rate (%)', step: 0.1, min: 0, max: 100 }, { name: 'eaPct', label: 'EA Boost (%)', placeholder: '5', step: 1, min: 0, max: 30 }], compute: (v) => ({ result: n(v.regular)+n(v.eaPct||'5'), label: 'Est. EA Rate', unit: '%', steps: [`Regular: ${n(v.regular)}%`, `EA: ~${(n(v.regular)+n(v.eaPct||'5')).toFixed(1)}%`] }), description: 'Estimate early action acceptance rate.', formula: 'EA Rate = Regular + Boost', interpretation: 'Non-binding EA provides smaller boost than ED.' },

  'college-calculator-aid': { schema: z.object({ cost: z.string(), efc: z.string(), merit: z.string(), grants: z.string() }), fields: [{ name: 'cost', label: 'Total Cost ($)', step: 1000, min: 0 }, { name: 'efc', label: 'EFC from FAFSA ($)', step: 500, min: 0 }, { name: 'merit', label: 'Merit Aid ($)', step: 500, min: 0 }, { name: 'grants', label: 'Need Grants ($)', step: 500, min: 0 }], compute: (v) => { const gap = n(v.cost)-n(v.efc)-n(v.merit)-n(v.grants); return { result: Math.max(0,gap), label: 'Remaining Gap', unit: '$', steps: [`Cost: $${n(v.cost).toFixed(0)}`, `EFC: $${n(v.efc).toFixed(0)}`, `Aid: $${(n(v.merit)+n(v.grants)).toFixed(0)}`, `Gap: $${Math.max(0,gap).toFixed(0)}`] } }, description: 'Calculate remaining college funding gap after aid.', formula: 'Gap = Cost - EFC - Merit - Grants', interpretation: 'Gap filled by loans, payment plans, outside scholarships.' },

  'pell-grant': { schema: z.object({ efc: z.string(), enrollment: z.string(), coa: z.string() }), fields: [{ name: 'efc', label: 'EFC ($)', step: 100, min: 0, max: 6000 }, { name: 'enrollment', label: 'Enrollment', type: 'select', options: [{ label: 'Full-time', value: 'full' }, { label: '3/4 time', value: 'three' }, { label: 'Half-time', value: 'half' }] }, { name: 'coa', label: 'Cost of Attendance ($)', step: 1000, min: 0 }], compute: (v) => { const maxPell = 7395; const enr = String(v.enrollment); const pct = enr=='full'?1:enr=='three'?0.75:0.5; const award = n(v.efc)<=6686?Math.min(maxPell*pct, n(v.coa)*pct):0; return { result: award, label: 'Est. Pell Grant', unit: '$/year', steps: [`EFC: $${n(v.efc)}`, `Award: $${award.toFixed(0)} (${(pct*100).toFixed(0)}% time)`] } }, description: 'Estimate Federal Pell Grant eligibility.', formula: 'Based on EFC, enrollment status, COA. Max ~$7395 (2024-25).', interpretation: 'Pell for undergrads with exceptional financial need. Does not need repayment.' },

  'work-study': { schema: z.object({ award: z.string(), hours: z.string(), wage: z.string() }), fields: [{ name: 'award', label: 'Work-Study Award ($)', step: 500, min: 0 }, { name: 'hours', label: 'Hours per Week', step: 1, min: 1, max: 20 }, { name: 'wage', label: 'Hourly Wage ($)', placeholder: '15', step: 0.5, min: 7.25 }], compute: (v) => { const annual = n(v.hours)*(n(v.wage)||15)*30; return { result: Math.min(n(v.award),annual), label: 'Est. Annual Earnings', unit: '$', steps: [`Rate: ${n(v.wage)||15}/hr x ${n(v.hours)} hr/wk x 30 wks`, `Earn: $${Math.min(n(v.award),annual).toFixed(0)}`] } }, description: 'Estimate work-study earnings.', formula: 'Earnings = min(Award, Hours x Wage x 30 weeks)', interpretation: 'Federal work-study: max 20 hr/wk. Award varies by school.' },

  'scholarship-search': { schema: z.object({ gpa: z.string(), sat: z.string(), act: z.string(), income: z.string(), state: z.string() }), fields: [{ name: 'gpa', label: 'GPA', step: 0.01, min: 0, max: 4 }, { name: 'sat', label: 'SAT', step: 10, min: 400, max: 1600 }, { name: 'act', label: 'ACT', step: 1, min: 1, max: 36 }, { name: 'income', label: 'Family Income ($)', step: 5000, min: 0 }], compute: (v) => { const profile = `GPA ${n(v.gpa).toFixed(2)}, SAT ${n(v.sat)}, Income $${n(v.income).toFixed(0)}`; const estPct = (n(v.gpa)/4*40+Math.min(n(v.sat)/1600*30,30)+Math.max(0,1-n(v.income)/200000)*30); const cat = estPct>=60?'Many scholarships available':estPct>=35?'Some scholarships':'Fewer options, try local'; return { result: estPct, label: 'Scholarship Potential', unit: '%', steps: [profile, cat] } }, description: 'Estimate scholarship eligibility profile.', formula: 'Composite of GPA, test scores, financial need.', interpretation: 'Start with local scholarships, then national. Merit + need-based aid.' },

  'in-state-out-state': { schema: z.object({ tuition: z.string(), fees: z.string(), roomBoard: z.string(), isOut: z.string() }), fields: [{ name: 'tuition', label: 'In-State Tuition ($)', step: 500, min: 0 }, { name: 'fees', label: 'Fees ($)', step: 200, min: 0 }, { name: 'roomBoard', label: 'Room & Board ($)', step: 500, min: 0 }, { name: 'isOut', label: 'Residency', type: 'select', options: [{ label: 'In-State', value: 'in' }, { label: 'Out-of-State', value: 'out' }] }], compute: (v) => { const tuition = n(v.tuition)*(String(v.isOut)=='out'?2.5:1); const total = tuition+n(v.fees)+n(v.roomBoard); return { result: total, label: 'Annual Total', unit: '$', steps: [`Tuition: $${tuition.toFixed(0)}`, `Fees: $${n(v.fees).toFixed(0)}`, `Room: $${n(v.roomBoard).toFixed(0)}`, `Total: $${total.toFixed(0)}`] } }, description: 'Compare in-state vs out-of-state costs.', formula: 'OOS tuition ~2.5x in-state.', interpretation: 'Out-of-state tuition significantly higher. Consider residency requirements.' },

  'room-board-cost': { schema: z.object({ roomType: z.string(), mealPlan: z.string(), months: z.string() }), fields: [{ name: 'roomType', label: 'Room Type', type: 'select', options: [{ label: 'Dorm double', value: 'double' }, { label: 'Dorm single', value: 'single' }, { label: 'Off-campus', value: 'off' }] }, { name: 'mealPlan', label: 'Meal Plan', type: 'select', options: [{ label: 'Standard 14 meals', value: 'standard' }, { label: 'Basic 10 meals', value: 'basic' }, { label: 'Unlimited', value: 'unlimited' }, { label: 'No meal plan', value: 'none' }] }, { name: 'months', label: 'Months', step: 1, min: 1, max: 12, placeholder: '9' }], compute: (v) => { const r: Record<string,number> = {double:6000,single:9000,off:8000}; const m: Record<string,number> = {standard:5000,basic:4000,unlimited:6000,none:0}; const total = (r[n(v.roomType)]||6000)+(m[n(v.mealPlan)]||5000); const monthly = total/(n(v.months)||9); return { result: total, label: 'Annual R&B Cost', unit: '$', steps: [`Room: $${(r[n(v.roomType)]||6000)}`, `Meals: $${(m[n(v.mealPlan)]||5000)}`, `Total: $${total} ($${monthly.toFixed(0)}/mo)`] } }, description: 'Estimate room and board costs.', formula: 'Room + Meal Plan cost.', interpretation: 'Dorm: $6-12k/yr. Off-campus varies widely by location.' },

  'meal-plan': { schema: z.object({ planType: z.string(), weeks: z.string() }), fields: [{ name: 'planType', label: 'Plan Type', type: 'select', options: [{ label: '14 meals/wk', value: '14' }, { label: '19 meals/wk', value: '19' }, { label: 'Unlimited', value: 'unlim' }] }, { name: 'weeks', label: 'Weeks per Semester', placeholder: '15', step: 1, min: 1 }], compute: (v) => { const p: Record<string,number> = {'14':3500,'19':4500,unlim:5500}; const pt = String(v.planType); const cost = p[pt]||3500; const perMeal = cost/(pt=='unlim'?21*14:parseInt(pt)*14); return { result: cost, label: 'Semester Cost', unit: '$', steps: [`Plan: ${pt} meals/wk`, `Cost: $${cost}`, `Per meal: ~$${perMeal.toFixed(2)}`] } }, description: 'Estimate meal plan cost.', formula: 'Plan price varies by institution.', interpretation: '14 meals/wk ~$3500/sem. Off-campus cooking cheaper.' },

  'textbook-budget': { schema: z.object({ courses: z.string(), newTexts: z.string(), usedTexts: z.string(), rentalPct: z.string() }), fields: [{ name: 'courses', label: 'Courses', step: 1, min: 1 }, { name: 'newTexts', label: 'New Books Needed', step: 1, min: 0 }, { name: 'usedTexts', label: 'Used Books', step: 1, min: 0 }, { name: 'rentalPct', label: 'Rental (%)', placeholder: '30', step: 5, min: 0, max: 100 }], compute: (v) => { const total = n(v.newTexts)*80+n(v.usedTexts)*50+n(v.courses)*(n(v.rentalPct||'30')/100)*30; return { result: total, label: 'Semester Textbook Cost', unit: '$', steps: [`New: ${n(v.newTexts)} x $80`, `Used: ${n(v.usedTexts)} x $50`, `Rental: ${n(v.courses)} x $30 x ${n(v.rentalPct||'30')}%`, `Total: $${total.toFixed(0)}`] } }, description: 'Estimate textbook and supply budget.', formula: 'Cost = New*80 + Used*50 + Rental*30', interpretation: 'Avg undergrad: $400-600/sem on books. Rent/digital to save.' },

  'college-living-expenses': { schema: z.object({ rent: z.string(), food: z.string(), transport: z.string(), other: z.string(), months: z.string() }), fields: [{ name: 'rent', label: 'Monthly Rent ($)', step: 100, min: 0 }, { name: 'food', label: 'Monthly Food ($)', step: 50, min: 0 }, { name: 'transport', label: 'Monthly Transport ($)', step: 25, min: 0 }, { name: 'other', label: 'Monthly Other ($)', step: 50, min: 0 }, { name: 'months', label: 'Months per Year', placeholder: '12', step: 1, min: 1 }], compute: (v) => { const mo = n(v.rent)+n(v.food)+n(v.transport)+n(v.other); const yr = mo*(n(v.months)||12); return { result: yr, label: 'Annual Living Expenses', unit: '$', steps: [`Monthly: $${mo.toFixed(0)}`, `Annual: $${yr.toFixed(0)}`] } }, description: 'Estimate off-campus living expenses.', formula: 'Annual = Monthly x Months', interpretation: 'Off-campus: $800-1500/mo typical. Share housing to reduce.' },

  'graduate-school-cost': { schema: z.object({ tuition: z.string(), fees: z.string(), years: z.string(), assistantship: z.string() }), fields: [{ name: 'tuition', label: 'Annual Tuition ($)', step: 2000, min: 0 }, { name: 'fees', label: 'Annual Fees ($)', step: 500, min: 0 }, { name: 'years', label: 'Program Length (years)', step: 0.5, min: 1, placeholder: '2' }, { name: 'assistantship', label: 'Annual Assistantship ($)', step: 1000, min: 0 }], compute: (v) => { const annual = n(v.tuition)+n(v.fees)-n(v.assistantship); const total = annual*n(v.years||'2'); return { result: total, label: 'Total Cost (net)', unit: '$', steps: [`Annual: $${annual.toFixed(0)}`, `Years: ${n(v.years||'2')}`, `Total: $${total.toFixed(0)}`] } }, description: 'Estimate graduate school cost.', formula: 'Total = (Tuition+Fees-Assistantship) x Years', interpretation: 'Master: 1-2yrs. PhD: 5-7yrs often funded. Assistantships reduce costs.' },

  'study-abroad-budget': { schema: z.object({ programFee: z.string(), airfare: z.string(), housing: z.string(), food: z.string(), visa: z.string(), spending: z.string() }), fields: [{ name: 'programFee', label: 'Program Fee ($)', step: 500, min: 0 }, { name: 'airfare', label: 'Airfare ($)', step: 200, min: 0 }, { name: 'housing', label: 'Housing ($)', step: 500, min: 0 }, { name: 'food', label: 'Food ($)', step: 200, min: 0 }, { name: 'visa', label: 'Visa/Insurance ($)', step: 100, min: 0 }, { name: 'spending', label: 'Personal Spending ($)', step: 200, min: 0 }], compute: (v) => ({ result: n(v.programFee)+n(v.airfare)+n(v.housing)+n(v.food)+n(v.visa)+n(v.spending), label: 'Total Study Abroad Budget', unit: '$', steps: [`Total: $${(n(v.programFee)+n(v.airfare)+n(v.housing)+n(v.food)+n(v.visa)+n(v.spending)).toFixed(0)}`] }), description: 'Budget for a study abroad semester.', formula: 'Total = Program+Airt+Housing+Food+Visa+Personal', interpretation: 'Study abroad: $10-30k for semester. Scholarships available.' },

  'semester-abroad-cost': { schema: z.object({ homeTuition: z.string(), abroadFee: z.string(), travel: z.string(), living: z.string() }), fields: [{ name: 'homeTuition', label: 'Home Tuition/Sem ($)', step: 1000, min: 0 }, { name: 'abroadFee', label: 'Abroad Program Fee ($)', step: 500, min: 0 }, { name: 'travel', label: 'Travel Costs ($)', step: 200, min: 0 }, { name: 'living', label: 'Living Expenses ($)', step: 500, min: 0 }], compute: (v) => ({ result: n(v.homeTuition)+(n(v.abroadFee)||0)+n(v.travel)+n(v.living), label: 'Semester Abroad Cost', unit: '$', steps: [`Home tuition: $${n(v.homeTuition).toFixed(0)}`, `Abroad fee: $${(n(v.abroadFee)||0).toFixed(0)}`, `Travel: $${n(v.travel).toFixed(0)}`, `Living: $${n(v.living).toFixed(0)}`, `Total: $${(n(v.homeTuition)+(n(v.abroadFee)||0)+n(v.travel)+n(v.living)).toFixed(0)}`] }), description: 'Compare semester abroad costs.', formula: 'Cost = HomeTuition + AbroadFee + Travel + Living', interpretation: 'Some home tuition waived. Scholarships available.', },

  'study-time-calc': { schema: z.object({ material: z.string(), speed: z.string(), breaks: z.string() }), fields: [{ name: 'material', label: 'Pages or Chapters', step: 1, min: 1 }, { name: 'speed', label: 'Pages per Hour', placeholder: '20', step: 1, min: 1 }, { name: 'breaks', label: 'Break %', placeholder: '15', step: 5, min: 0 }], compute: (v) => { const hr = n(v.material)/(n(v.speed)||20); const total = hr*(1+(n(v.breaks)||15)/100); return { result: total, label: 'Study Time Needed', unit: 'hrs', steps: [`Reading: ${hr.toFixed(1)} hr`, `Breaks: ${(total-hr).toFixed(1)} hr`, `Total: ${total.toFixed(1)} hr`] } }, description: 'Estimate study time for material.', formula: 'Time = Material/Speed x (1+Break%)', interpretation: 'Include breaks to maintain focus.' },

  'exam-countdown': { schema: z.object({ examDate: z.string(), studyHrs: z.string(), dailyHrs: z.string() }), fields: [{ name: 'examDate', label: 'Exam Date (YYYY-MM-DD)' }, { name: 'studyHrs', label: 'Total Study Hours Needed', step: 1, min: 1 }, { name: 'dailyHrs', label: 'Hours per Day Available', step: 0.5, min: 0.5 }], compute: (v) => { const now = new Date(); const exam = new Date(String(v.examDate)); const days = Math.max(1,Math.round((exam.getTime()-now.getTime())/(1000*60*60*24))); const hrsPerDay = n(v.dailyHrs); const capable = days*hrsPerDay; const status = capable>=n(v.studyHrs) ? 'On track' : 'Increase hours'; return { result: days, label: 'Days Until Exam', unit: 'days', steps: [`Days: ${days}`, `Can study: ${capable.toFixed(0)} hr`, `Need: ${n(v.studyHrs)} hr`, status] } }, description: 'Countdown to exam with study projection.', formula: 'Days to exam, compare study capacity vs need.', interpretation: 'Start studying well before. Cramming less effective.' },

  'final-grade-calc': { schema: z.object({ current: z.string(), weight: z.string(), desired: z.string() }), fields: [{ name: 'current', label: 'Current Grade (%)', step: 0.1, min: 0, max: 100 }, { name: 'weight', label: 'Final Weight (%)', step: 1, min: 0, max: 100 }, { name: 'desired', label: 'Desired Grade (%)', step: 0.1, min: 0, max: 100 }], compute: (v) => { const w = n(v.weight)/100; const need = w>0?(n(v.desired)-n(v.current)*(1-w))/w:0; return { result: need, label: 'Needed on Final', unit: '%', steps: [`Need: ${need.toFixed(1)}%`, need>100?'May be unreachable':''] } }, description: 'Grade needed on final exam.', formula: 'Need = (Desired - Current*(1-W))/W', interpretation: 'W = final weight as decimal.' },

  'semester-grade-calc': { schema: z.object({ q1: z.string(), q2: z.string(), finalEx: z.string(), fw: z.string() }), fields: [{ name: 'q1', label: 'Quarter 1 (%)', step: 0.1, min: 0, max: 100 }, { name: 'q2', label: 'Quarter 2 (%)', step: 0.1, min: 0, max: 100 }, { name: 'finalEx', label: 'Final (%)', step: 0.1, min: 0, max: 100 }, { name: 'fw', label: 'Final Weight (%)', placeholder: '20', step: 1, min: 0, max: 100 }], compute: (v) => { const fw = n(v.fw||'20')/100; const qw = (1-fw)/2; return { result: n(v.q1)*qw+n(v.q2)*qw+n(v.finalEx)*fw, label: 'Semester Grade', unit: '%', steps: [`Q1: ${(qw*100).toFixed(0)}%`, `Q2: ${(qw*100).toFixed(0)}%`, `Final: ${(fw*100).toFixed(0)}%`, `Grade: ${(n(v.q1)*qw+n(v.q2)*qw+n(v.finalEx)*fw).toFixed(2)}%`] } }, description: 'Semester grade from Q+Final.', formula: 'Grade = Q1*QW + Q2*QW + Final*FW', interpretation: 'QW = quarter weight, FW = final weight.' },

  'quiz-grade-calc': { schema: z.object({ correct: z.string(), total: z.string() }), fields: [{ name: 'correct', label: 'Correct', step: 1, min: 0 }, { name: 'total', label: 'Total', step: 1, min: 1 }], compute: (v) => ({ result: n(v.total)>0?n(v.correct)/n(v.total)*100:0, label: 'Quiz Score', unit: '%', steps: [`${n(v.correct)}/${n(v.total)} = ${(n(v.total)>0?n(v.correct)/n(v.total)*100:0).toFixed(1)}%`] }), description: 'Quiz score percentage.', formula: '% = Correct/Total x 100', interpretation: 'Each question counted equally.' },

  'assignment-planner': { schema: z.object({ tasks: z.string(), hoursPerTask: z.string(), dueDays: z.string(), existingHrs: z.string() }), fields: [{ name: 'tasks', label: 'Number of Tasks', step: 1, min: 1 }, { name: 'hoursPerTask', label: 'Hours per Task', step: 0.5, min: 0.5 }, { name: 'dueDays', label: 'Days Until Due', step: 1, min: 1 }, { name: 'existingHrs', label: 'Existing Commitments (hrs/day)', step: 0.5, min: 0 }], compute: (v) => { const totalHrs = n(v.tasks)*(n(v.hoursPerTask)||1); const availDays = n(v.dueDays); const perDay = totalHrs/availDays+(n(v.existingHrs)||0); return { result: perDay, label: 'Hours Needed per Day', unit: 'hrs/day', steps: [`Total: ${totalHrs.toFixed(1)} hr`, `Days: ${availDays}`, `${perDay.toFixed(1)} hr/day needed`] } }, description: 'Plan assignment schedule.', formula: 'Hrs/Day = (Tasks x Hrs/Task)/Days + Existing', interpretation: 'Start early to avoid cramming.' },

  'reading-speed-calc': { schema: z.object({ words: z.string(), minutes: z.string() }), fields: [{ name: 'words', label: 'Words Read', step: 1, min: 1 }, { name: 'minutes', label: 'Time (min)', step: 0.5, min: 0.5 }], compute: (v) => ({ result: n(v.minutes)>0?n(v.words)/n(v.minutes):0, label: 'Reading Speed', unit: 'WPM', steps: [`${n(v.words)} words in ${n(v.minutes)} min`, `${(n(v.minutes)>0?n(v.words)/n(v.minutes):0).toFixed(0)} WPM`] }), description: 'Calculate reading speed.', formula: 'WPM = Words/Minutes', interpretation: 'Avg: 200-300 WPM. Skilled: 400+ WPM.' },

  'typing-speed-calc': { schema: z.object({ chars: z.string(), minutes: z.string(), errors: z.string() }), fields: [{ name: 'chars', label: 'Characters Typed', step: 1, min: 1 }, { name: 'minutes', label: 'Time (min)', step: 0.5, min: 0.5 }, { name: 'errors', label: 'Errors', step: 1, min: 0 }], compute: (v) => { const gross = n(v.minutes)>0?(n(v.chars)/5)/n(v.minutes):0; return { result: Math.max(0,gross-n(v.errors)), label: 'Net WPM', unit: 'WPM', steps: [`Gross: ${gross.toFixed(1)} WPM`, `Errors: ${n(v.errors)}`, `Net: ${Math.max(0,gross-n(v.errors)).toFixed(1)} WPM`] } }, description: 'Typing speed (net WPM).', formula: 'Net = (Chars/5)/Min - Errors', interpretation: 'Professional: 60-80 WPM. Avg: 35-45 WPM.' },

  'vocabulary-calc': { schema: z.object({ correct: z.string(), total: z.string() }), fields: [{ name: 'correct', label: 'Words Known', step: 1, min: 0 }, { name: 'total', label: 'Total Words Tested', step: 1, min: 1 }], compute: (v) => ({ result: n(v.total)>0?n(v.correct)/n(v.total)*100:0, label: 'Vocabulary Score', unit: '%', steps: [`${n(v.correct)}/${n(v.total)} = ${(n(v.total)>0?n(v.correct)/n(v.total)*100:0).toFixed(1)}%`] }), description: 'Vocabulary test score.', formula: '% = Correct/Total x 100', interpretation: 'Assess vocabulary size. Adult vocab: ~20,000-35,000 words.' },

  'lexile-calc': { schema: z.object({ correct: z.string(), total: z.string(), grade: z.string() }), fields: [{ name: 'correct', label: 'Questions Correct', step: 1, min: 0 }, { name: 'total', label: 'Total Questions', step: 1, min: 1 }, { name: 'grade', label: 'Grade Level', type: 'select', options: [{ label: 'Grade 3', value: '3' }, { label: 'Grade 5', value: '5' }, { label: 'Grade 8', value: '8' }, { label: 'Grade 10', value: '10' }, { label: 'Grade 12', value: '12' }] }], compute: (v) => { const pct = n(v.total)>0?n(v.correct)/n(v.total):0; const base: Record<string,number> = {'3':450,'5':750,'8':1000,'10':1100,'12':1250}; const lexile = Math.round((base[n(v.grade)]||800)+pct*400-200); return { result: Math.max(0,lexile), label: 'Est. Lexile Measure', unit: 'L', steps: [`Score: ${(pct*100).toFixed(0)}%`, `Grade: ${n(v.grade)}`, `Lexile: ${Math.max(0,lexile)}L`] } }, description: 'Estimate Lexile reading measure.', formula: 'Lexile = GradeBase + Score%*400-200', interpretation: 'Lexile 200L-1700L. Grade 5: ~750L. Grade 10: ~1100L.' },

  'writing-word-count': { schema: z.object({ text: z.string() }), fields: [{ name: 'text', label: 'Paste your text' }], compute: (v) => { const t = String(v.text||''); const words = t.trim()?t.trim().split(/\s+/).length:0; const chars = t.length; return { result: words, label: 'Word Count', unit: 'words', steps: [`Words: ${words}`, `Characters: ${chars}`, `Paragraphs: ${t.trim()?t.split(/\n\s*\n/).length:0}`] } }, description: 'Count words, characters, paragraphs.', formula: 'Words = split by whitespace', interpretation: 'Standard essay: 500-1000 words. Typed: ~250 words/page.' },

  'reading-time': { schema: z.object({ words: z.string(), speed: z.string() }), fields: [{ name: 'words', label: 'Word Count', step: 50, min: 0 }, { name: 'speed', label: 'Reading Speed (WPM)', placeholder: '250', step: 10, min: 50 }], compute: (v) => { const min = (n(v.speed)||250)>0?n(v.words)/(n(v.speed)||250):0; return { result: min, label: 'Reading Time', unit: 'min', steps: [`${n(v.words)} words @ ${n(v.speed)||250} WPM`, `${min.toFixed(1)} min (${Math.floor(min/60)}h ${Math.round(min%60)}m)`] } }, description: 'Estimate reading time for text.', formula: 'Time = Words/WPM', interpretation: 'Avg adult reads 200-300 WPM for comprehension.' },

  'citing-citations': { schema: z.object({ sources: z.string(), type: z.string() }), fields: [{ name: 'sources', label: 'Number of Sources', step: 1, min: 1 }, { name: 'type', label: 'Format', type: 'select', options: [{ label: 'APA 7th', value: 'apa' }, { label: 'MLA 9th', value: 'mla' }, { label: 'Chicago', value: 'chicago' }] }], compute: (v) => { const t = String(v.type); const guide = t=='apa'?'Author, A. (Year). Title. Publisher.':t=='mla'?'Author. "Title." Publisher, Year.':'Author. Title. Publisher, Year.'; return { result: `Format: ${t.toUpperCase()}`, label: 'Citation Format', unit: '', steps: [`Sources: ${n(v.sources)}`, guide, `Add References/Bibliography page`] } }, description: 'Citation format reference guide.', formula: 'Format per APA/MLA/Chicago.', interpretation: 'Use citation manager (Zotero, Mendeley) for large projects.' },

  'curriculum-planner': { schema: z.object({ weeks: z.string(), subjects: z.string(), hoursPerWeek: z.string(), sessionsPerWeek: z.string() }), fields: [{ name: 'weeks', label: 'Total Weeks', step: 1, min: 1 }, { name: 'subjects', label: 'Subjects', step: 1, min: 1 }, { name: 'hoursPerWeek', label: 'Hours per Week per Subject', step: 0.5, min: 0.5 }, { name: 'sessionsPerWeek', label: 'Sessions per Week per Subject', step: 1, min: 1 }], compute: (v) => { const totalHrs = n(v.weeks)*n(v.subjects)*n(v.hoursPerWeek); const totalSessions = n(v.weeks)*n(v.subjects)*n(v.sessionsPerWeek); return { result: totalHrs, label: 'Total Curriculum Hours', unit: 'hrs', steps: [`${n(v.weeks)} wks x ${n(v.subjects)} subjects x ${n(v.hoursPerWeek)} hr = ${totalHrs} hrs`, `Sessions: ${totalSessions}`] } }, description: 'Plan curriculum pacing over weeks.', formula: 'Total = Weeks x Subjects x Hr/Week', interpretation: 'Adjust hours per subject based on complexity. Block scheduling adds focus.' },

  'credit-hours-calc': { schema: z.object({ earned: z.string(), total: z.string() }), fields: [{ name: 'earned', label: 'Credits Earned', step: 1, min: 0 }, { name: 'total', label: 'Total Required', step: 1, min: 1 }], compute: (v) => ({ result: n(v.total)>0?n(v.earned)/n(v.total)*100:0, label: 'Progress', unit: '%', steps: [`${n(v.earned)}/${n(v.total)} credits (${(n(v.total)>0?n(v.earned)/n(v.total)*100:0).toFixed(1)}%)`] }), description: 'Calculate credit hours progress.', formula: 'Progress = Earned/Required x 100', interpretation: 'Bachelors: 120 credits. Track each semester to stay on pace.' },

  'degree-audit': { schema: z.object({ earned: z.string(), required: z.string(), genEd: z.string(), genEdReq: z.string(), major: z.string(), majorReq: z.string() }), fields: [{ name: 'earned', label: 'Total Credits Earned', step: 1, min: 0 }, { name: 'required', label: 'Total Required', step: 1, min: 1 }, { name: 'genEd', label: 'Gen Ed Credits Earned', step: 1, min: 0 }, { name: 'genEdReq', label: 'Gen Ed Required', step: 1, min: 1 }, { name: 'major', label: 'Major Credits Earned', step: 1, min: 0 }, { name: 'majorReq', label: 'Major Required', step: 1, min: 1 }], compute: (v) => { const tPct = n(v.required)>0?n(v.earned)/n(v.required)*100:0; const gPct = n(v.genEdReq)>0?n(v.genEd)/n(v.genEdReq)*100:0; const mPct = n(v.majorReq)>0?n(v.major)/n(v.majorReq)*100:0; return { result: tPct, label: 'Overall Progress', unit: '%', steps: [`Total: ${n(v.earned)}/${n(v.required)} (${tPct.toFixed(1)}%)`, `Gen Ed: ${n(v.genEd)}/${n(v.genEdReq)} (${gPct.toFixed(1)}%)`, `Major: ${n(v.major)}/${n(v.majorReq)} (${mPct.toFixed(1)}%)`] } }, description: 'Degree audit tracking all requirements.', formula: 'Progress per category = Earned/Required x 100', interpretation: 'Check major+gen ed+elective requirements each semester.' },

  'transfer-credit-calc': { schema: z.object({ earned: z.string(), accepted: z.string(), institutionPct: z.string() }), fields: [{ name: 'earned', label: 'Credits Earned Elsewhere', step: 1, min: 0 }, { name: 'accepted', label: 'Credits Accepted', step: 1, min: 0 }, { name: 'institutionPct', label: 'Max Transferable (%)', placeholder: '75', step: 5, min: 0, max: 100 }], compute: (v) => { const max = n(v.earned)*(n(v.institutionPct||'75')/100); const accepted = Math.min(n(v.accepted),max); const lost = n(v.earned)-accepted; return { result: accepted, label: 'Credits Transferred', unit: 'credits', steps: [`Earned: ${n(v.earned)}`, `Max transferable: ${max.toFixed(0)}`, `Accepted: ${accepted.toFixed(0)}`, `Lost: ${lost.toFixed(0)}`] } }, description: 'Estimate transferable credits between schools.', formula: 'Transferred = min(Accepted, Earned x Max%)', interpretation: 'Most schools cap transfer credits at 60-75% of total.' },

  'college-comparison': { schema: z.object({ nameA: z.string(), nameB: z.string(), costA: z.string(), costB: z.string(), aidA: z.string(), aidB: z.string(), gradA: z.string(), gradB: z.string() }), fields: [{ name: 'nameA', label: 'College A Name' }, { name: 'costA', label: 'College A Cost ($/yr)', step: 1000, min: 0 }, { name: 'aidA', label: 'College A Aid ($/yr)', step: 500, min: 0 }, { name: 'gradA', label: 'College A Grad Rate (%)', step: 1, min: 0, max: 100 }, { name: 'nameB', label: 'College B Name' }, { name: 'costB', label: 'College B Cost ($/yr)', step: 1000, min: 0 }, { name: 'aidB', label: 'College B Aid ($/yr)', step: 500, min: 0 }, { name: 'gradB', label: 'College B Grad Rate (%)', step: 1, min: 0, max: 100 }], compute: (v) => { const netA = n(v.costA)-n(v.aidA); const netB = n(v.costB)-n(v.aidB); const diff = Math.abs(netA-netB); return { result: `Net: $${netA.toFixed(0)} vs $${netB.toFixed(0)}`, label: 'Comparison', unit: '', steps: [`${v.nameA||'A'}: net $${netA.toFixed(0)}, grad ${n(v.gradA)}%`, `${v.nameB||'B'}: net $${netB.toFixed(0)}, grad ${n(v.gradB)}%`, `Diff: $${diff.toFixed(0)}/yr`] } }, description: 'Compare two college costs side by side.', formula: 'Net = Cost - Aid. Compare grad rates.', interpretation: 'Consider net price, graduation rate, and student debt outcomes.' },

  'homework-time': { schema: z.object({ problems: z.string(), minPerProblem: z.string(), review: z.string() }), fields: [{ name: 'problems', label: 'Problems', step: 1, min: 1 }, { name: 'minPerProblem', label: 'Min per Problem', placeholder: '5', step: 1, min: 1 }, { name: 'review', label: 'Review Time (min)', placeholder: '15', step: 5, min: 0 }], compute: (v) => { const total = n(v.problems)*(n(v.minPerProblem)||5)+(n(v.review)||15); return { result: Math.round(total), label: 'Total Time', unit: 'min', steps: [`${n(v.problems)} x ${n(v.minPerProblem)||5} min = ${n(v.problems)*(n(v.minPerProblem)||5)}`, `+review ${n(v.review)||15} = ${total} min (${(total/60).toFixed(1)} hr)`] } }, description: 'Estimate homework time.', formula: 'Time = Problems x Min/Problem + Review', interpretation: 'Break large assignments into smaller chunks.' },

  'weekly-assignment': { schema: z.object({ assignments: z.string(), avgTime: z.string(), classes: z.string() }), fields: [{ name: 'assignments', label: 'Assignments Due This Week', step: 1, min: 1 }, { name: 'avgTime', label: 'Avg Hours per Assignment', step: 0.5, min: 0.5 }, { name: 'classes', label: 'Number of Classes', step: 1, min: 1 }], compute: (v) => { const total = n(v.assignments)*(n(v.avgTime)||1)*n(v.classes); return { result: total, label: 'Total Weekly Time', unit: 'hrs', steps: [`${n(v.assignments)} asgn x ${n(v.avgTime)||1} hr x ${n(v.classes)} classes = ${total.toFixed(1)} hr`] } }, description: 'Estimate total weekly homework time.', formula: 'Total = Assignments x AvgTime x Classes', interpretation: 'Plan your week around assignment due dates.' },

  'pomodoro-study': { schema: z.object({ sessions: z.string(), focusMin: z.string(), breakMin: z.string(), longBreakMin: z.string(), cycles: z.string() }), fields: [{ name: 'sessions', label: 'Total Pomodoro Sessions', step: 1, min: 1 }, { name: 'focusMin', label: 'Focus Minutes', placeholder: '25', step: 5, min: 5 }, { name: 'breakMin', label: 'Break Minutes', placeholder: '5', step: 1, min: 0 }, { name: 'longBreakMin', label: 'Long Break (every 4)', placeholder: '15', step: 5, min: 0 }, { name: 'cycles', label: 'Cycles Before Long Break', placeholder: '4', step: 1, min: 1 }], compute: (v) => { const fb = (n(v.focusMin)||25)+(n(v.breakMin)||5); const cycle = fb*(n(v.cycles)||4)+(n(v.longBreakMin)||15); const totalMin = Math.floor(n(v.sessions)/(n(v.cycles)||4))*cycle+(n(v.sessions)%(n(v.cycles)||4))*fb; return { result: Math.round(totalMin), label: 'Total Study Time', unit: 'min', steps: [`${n(v.sessions)} sessions x ${n(v.focusMin)||25} min focus`, `Total: ${Math.round(totalMin)} min (${(totalMin/60).toFixed(1)} hr)`] } }, description: 'Calculate Pomodoro study session schedule.', formula: 'Total = Sessions x (Focus + Break), with long breaks every N cycles.', interpretation: 'Pomodoro Technique: 25 min focus, 5 min break. Long break every 4 cycles.' },

  'spaced-repetition': { schema: z.object({ cards: z.string(), newDaily: z.string(), retention: z.string(), reviewDays: z.string() }), fields: [{ name: 'cards', label: 'Total Cards', step: 10, min: 1 }, { name: 'newDaily', label: 'New Cards per Day', step: 5, min: 1 }, { name: 'retention', label: 'Desired Retention Rate (%)', placeholder: '90', step: 1, min: 50, max: 100 }, { name: 'reviewDays', label: 'Review Interval (days)', placeholder: '3', step: 1, min: 1 }], compute: (v) => { const daysToLearn = Math.ceil(n(v.cards)/Math.max(1,n(v.newDaily))); const dailyReviews = n(v.cards)/(n(v.reviewDays)||3); const totalDaily = n(v.newDaily)+dailyReviews; return { result: totalDaily, label: 'Daily Reviews+New', unit: 'cards/day', steps: [`Learn: ${daysToLearn} days`, `Reviews: ~${dailyReviews.toFixed(0)}/day`, `Total: ~${totalDaily.toFixed(0)} cards/day`] } }, description: 'Plan spaced repetition study schedule.', formula: 'Workload = New/Daily + Reviews. Reviews = Cards/Interval.', interpretation: 'Anki-style: new cards daily + reviews. 20-30 min/day for 20 new cards.' },

  'active-recall': { schema: z.object({ topics: z.string(), questions: z.string(), time: z.string() }), fields: [{ name: 'topics', label: 'Topics to Cover', step: 1, min: 1 }, { name: 'questions', label: 'Questions per Topic', step: 1, min: 1, placeholder: '5' }, { name: 'time', label: 'Time per Question (min)', placeholder: '2', step: 0.5, min: 0.5 }], compute: (v) => { const total = n(v.topics)*(n(v.questions)||5)*(n(v.time)||2); return { result: total, label: 'Total Active Recall Time', unit: 'min', steps: [`Q's: ${n(v.topics)} x ${n(v.questions)||5} = ${n(v.topics)*(n(v.questions)||5)}`, `Time: ${total} min (${(total/60).toFixed(1)} hr)`] } }, description: 'Calculate active recall study session time.', formula: 'Time = Topics x Questions x Min/Question', interpretation: 'Active recall > passive re-reading. Quiz yourself, then check.' },

  'flashcard-deck': { schema: z.object({ cards: z.string(), daily: z.string(), totalDays: z.string() }), fields: [{ name: 'cards', label: 'Total Cards', step: 10, min: 1 }, { name: 'daily', label: 'Daily Study Limit', step: 5, min: 1 }, { name: 'totalDays', label: 'Days Until Exam', step: 1, min: 1 }], compute: (v) => { const perDay = Math.ceil(n(v.cards)/Math.max(1,n(v.daily))); const feasible = n(v.daily)*n(v.totalDays); return { result: perDay, label: 'Days Needed', unit: 'days', steps: [`${n(v.cards)} cards @ ${n(v.daily)}/day = ${perDay} days`, feasible>=n(v.cards)?'On track':'Increase daily cards'] } }, description: 'Flashcard deck study planning.', formula: 'Days = Cards / Daily Limit', interpretation: 'Review cards daily. Add new cards gradually.' },

  'semester-planner': { schema: z.object({ weeks: z.string(), courses: z.string(), exams: z.string(), projects: z.string() }), fields: [{ name: 'weeks', label: 'Weeks in Semester', step: 1, min: 1, placeholder: '16' }, { name: 'courses', label: 'Number of Courses', step: 1, min: 1 }, { name: 'exams', label: 'Major Exams', step: 1, min: 0 }, { name: 'projects', label: 'Major Projects', step: 1, min: 0 }], compute: (v) => { const weeks = n(v.weeks)||16; const busyWeeks = Math.ceil((n(v.exams)+n(v.projects))/weeks*weeks); return { result: `${weeks} weeks, ${busyWeeks} busy wk`, label: 'Semester Overview', unit: '', steps: [`Courses: ${n(v.courses)}`, `Exams: ${n(v.exams)}`, `Projects: ${n(v.projects)}`, `Key weeks with exams/projects: ~${busyWeeks}`] } }, description: 'Plan your semester schedule.', formula: 'Map exams and projects across weeks.', interpretation: 'Block out exam weeks and project deadlines first. Study backwards.' },

  'exam-schedule': { schema: z.object({ exams: z.string(), days: z.string(), gaps: z.string(), studyHrs: z.string() }), fields: [{ name: 'exams', label: 'Number of Exams', step: 1, min: 1 }, { name: 'days', label: 'Total Days Available', step: 1, min: 1 }, { name: 'gaps', label: 'Days Between Exams', step: 1, min: 0 }, { name: 'studyHrs', label: 'Study Hours per Day', step: 1, min: 1 }], compute: (v) => { const perExam = n(v.days)/n(v.exams); const totalHrs = n(v.days)*n(v.studyHrs); return { result: `${perExam.toFixed(1)}d/exam`, label: 'Schedule Pace', unit: '', steps: [`${n(v.days)} days for ${n(v.exams)} exams`, `${perExam.toFixed(1)} days/exam`, `Total: ${totalHrs} study hours`, n(v.gaps)>0?`Gaps: ${n(v.gaps)} days`:'No built-in gaps'] } }, description: 'Plan exam study schedule.', formula: 'Days/Exam = TotalDays/Exams', interpretation: 'Space out study. Prioritize exams by difficulty and weight.' },

  'study-planner': { schema: z.object({ subjects: z.string(), hoursTotal: z.string(), daysRemaining: z.string(), hoursPerDay: z.string() }), fields: [{ name: 'subjects', label: 'Subjects to Study', step: 1, min: 1 }, { name: 'hoursTotal', label: 'Total Hours Needed', step: 5, min: 1 }, { name: 'daysRemaining', label: 'Days Remaining', step: 1, min: 1 }, { name: 'hoursPerDay', label: 'Hours Available per Day', step: 0.5, min: 0.5 }], compute: (v) => { const cap = n(v.daysRemaining)*n(v.hoursPerDay); const perSubject = n(v.hoursTotal)/n(v.subjects); return { result: cap, label: 'Study Capacity', unit: 'hrs', steps: [`Capacity: ${n(v.daysRemaining)}d x ${n(v.hoursPerDay)}h = ${cap}h`, `Need: ${n(v.hoursTotal)}h total`, `Per subject: ${perSubject.toFixed(1)}h`, cap>=n(v.hoursTotal)?'Sufficient time':'Need more hours/day'] } }, description: 'Plan study schedule across subjects.', formula: 'Capacity = Days x Hours/Day', interpretation: 'Distribute study hours proportionally by subject difficulty and exam weight.' },

  'break-planner': { schema: z.object({ studyMin: z.string(), breakMin: z.string(), totalHours: z.string() }), fields: [{ name: 'studyMin', label: 'Study Block (min)', placeholder: '50', step: 5, min: 5 }, { name: 'breakMin', label: 'Break (min)', placeholder: '10', step: 5, min: 0 }, { name: 'totalHours', label: 'Total Study Hours', step: 0.5, min: 1 }], compute: (v) => { const cycleMin = (n(v.studyMin)||50)+(n(v.breakMin)||10); const totalMin = n(v.totalHours)*60; const cycles = Math.floor(totalMin/cycleMin); const studyTime = cycles*(n(v.studyMin)||50); const breakTime = cycles*(n(v.breakMin)||10); return { result: cycles, label: 'Study-Break Cycles', unit: 'cycles', steps: [`${totalMin.toFixed(0)} min total`, `Cycle: ${cycleMin} min`, `Cycles: ${cycles}`, `Study: ${studyTime} min, Breaks: ${breakTime} min`] } }, description: 'Plan study-break schedule for long sessions.', formula: 'Cycles = TotalMin / (StudyMin + BreakMin)', interpretation: 'Take breaks to maintain focus. Every 4th break can be longer (15-30 min).' },

  'extracurricular-hours': { schema: z.object({ activities: z.string(), hoursPer: z.string(), daysPerWeek: z.string(), weeksPerSem: z.string() }), fields: [{ name: 'activities', label: 'Activities', step: 1, min: 1 }, { name: 'hoursPer', label: 'Hours per Session', step: 0.5, min: 0.5 }, { name: 'daysPerWeek', label: 'Days per Week', step: 1, min: 1 }, { name: 'weeksPerSem', label: 'Weeks per Semester', placeholder: '16', step: 1, min: 1 }], compute: (v) => { const weekly = n(v.activities)*n(v.hoursPer)*n(v.daysPerWeek); const sem = weekly*(n(v.weeksPerSem)||16); return { result: sem, label: 'Semester Commitment', unit: 'hrs', steps: [`Weekly: ${weekly.toFixed(1)} hr`, `Semester: ${sem.toFixed(1)} hr`] } }, description: 'Calculate extracurricular time commitment.', formula: 'Semester = Activities x Hrs x Days x Weeks', interpretation: 'Balance ECs with academics. 10-15 hr/week max recommended.' },

  'volunteer-hours': { schema: z.object({ hours: z.string(), weeks: z.string(), required: z.string() }), fields: [{ name: 'hours', label: 'Hours per Week', step: 0.5, min: 0.5 }, { name: 'weeks', label: 'Weeks', step: 1, min: 1 }, { name: 'required', label: 'Required Hours', step: 5, min: 0 }], compute: (v) => { const total = n(v.hours)*n(v.weeks); return { result: total, label: 'Total Volunteer Hours', unit: 'hrs', steps: [`${n(v.hours)} hr/wk x ${n(v.weeks)} wks = ${total} hr`, n(v.required)>0?`Required: ${n(v.required)} hr - ${total>=n(v.required)?'Met':'Short by '+(n(v.required)-total).toFixed(0)+' hr'}`:'No requirement set'] } }, description: 'Track volunteer hours.', formula: 'Total = Hours/Week x Weeks', interpretation: 'Many schools require 20-100 hrs for graduation.' },

  'homeschool-assessment': { schema: z.object({ math: z.string(), reading: z.string(), writing: z.string(), science: z.string(), history: z.string() }), fields: [{ name: 'math', label: 'Math Score (%)', step: 1, min: 0, max: 100 }, { name: 'reading', label: 'Reading Score (%)', step: 1, min: 0, max: 100 }, { name: 'writing', label: 'Writing Score (%)', step: 1, min: 0, max: 100 }, { name: 'science', label: 'Science Score (%)', step: 1, min: 0, max: 100 }, { name: 'history', label: 'History Score (%)', step: 1, min: 0, max: 100 }], compute: (v) => { const scores = [n(v.math),n(v.reading),n(v.writing),n(v.science),n(v.history)]; const avg = scores.reduce((a,b)=>a+b,0)/scores.length; const lowest = Math.min(...scores); return { result: avg, label: 'Average Score', unit: '%', steps: [`Math: ${n(v.math)}%`, `Reading: ${n(v.reading)}%`, `Writing: ${n(v.writing)}%`, `Science: ${n(v.science)}%`, `History: ${n(v.history)}%`, `Avg: ${avg.toFixed(1)}%`, lowest<60?'Needs improvement in some subjects':'Progressing well'] } }, description: 'Assess homeschool progress across subjects.', formula: 'Average of all subject scores.', interpretation: 'Monitor progress quarterly. Adjust curriculum for low areas.' },

  'homeschool-budget': { schema: z.object({ curriculum: z.string(), supplies: z.string(), fieldTrips: z.string(), activities: z.string(), testing: z.string() }), fields: [{ name: 'curriculum', label: 'Curriculum ($/yr)', step: 100, min: 0 }, { name: 'supplies', label: 'Supplies ($/yr)', step: 50, min: 0 }, { name: 'fieldTrips', label: 'Field Trips ($/yr)', step: 50, min: 0 }, { name: 'activities', label: 'Activities ($/yr)', step: 50, min: 0 }, { name: 'testing', label: 'Testing/Assessment ($/yr)', step: 50, min: 0 }], compute: (v) => ({ result: n(v.curriculum)+n(v.supplies)+n(v.fieldTrips)+n(v.activities)+n(v.testing), label: 'Annual Homeschool Budget', unit: '$', steps: [`Curriculum: $${n(v.curriculum).toFixed(0)}`, `Supplies: $${n(v.supplies).toFixed(0)}`, `Trips: $${n(v.fieldTrips).toFixed(0)}`, `Activities: $${n(v.activities).toFixed(0)}`, `Testing: $${n(v.testing).toFixed(0)}`, `Total: $${(n(v.curriculum)+n(v.supplies)+n(v.fieldTrips)+n(v.activities)+n(v.testing)).toFixed(0)}`] }), description: 'Budget for homeschool expenses.', formula: 'Sum of all education expense categories.', interpretation: 'Avg homeschool spends $500-2000/yr per child. Many free resources available.' },

  'homeschool-hours': { schema: z.object({ daysPerWeek: z.string(), hoursPerDay: z.string(), subjects: z.string() }), fields: [{ name: 'daysPerWeek', label: 'Days per Week', step: 1, min: 1 }, { name: 'hoursPerDay', label: 'Hours per Day', step: 0.5, min: 0.5 }, { name: 'subjects', label: 'Subjects', step: 1, min: 1 }], compute: (v) => { const weekly = n(v.daysPerWeek)*n(v.hoursPerDay); const perSubject = weekly/n(v.subjects); const annual = weekly*36; return { result: weekly, label: 'Weekly Hours', unit: 'hrs', steps: [`${n(v.daysPerWeek)}d x ${n(v.hoursPerDay)}h = ${weekly}h/wk`, `Per subject: ${perSubject.toFixed(1)} hr/wk`, `Annual: ~${annual} hrs (36 wks)`] } }, description: 'Plan homeschool hours per week.', formula: 'Weekly = Days x Hrs/Day | Annual = Weekly x 36', interpretation: 'Aim for 3-5 hrs/day for K-8, 5-6 hrs for high school.' },

  'curriculum-map': { schema: z.object({ subjects: z.string(), units: z.string(), weeksPerUnit: z.string(), assessments: z.string() }), fields: [{ name: 'subjects', label: 'Subjects', step: 1, min: 1 }, { name: 'units', label: 'Units per Subject', step: 1, min: 1 }, { name: 'weeksPerUnit', label: 'Weeks per Unit', step: 1, min: 1 }, { name: 'assessments', label: 'Assessments per Unit', step: 1, min: 0 }], compute: (v) => { const totalUnits = n(v.subjects)*n(v.units); const totalWeeks = totalUnits*n(v.weeksPerUnit); const totalAssess = totalUnits*n(v.assessments); return { result: totalWeeks, label: 'Total Weeks', unit: 'weeks', steps: [`Units: ${totalUnits}`, `Weeks: ${totalWeeks}`, `Assessments: ${totalAssess}`] } }, description: 'Map curriculum pacing across subjects.', formula: 'Weeks = Subjects x Units x Weeks/Unit', interpretation: 'Map backwards from end date. Build in review weeks.' },

  'lesson-plan-duration': { schema: z.object({ topics: z.string(), minutesPer: z.string(), activities: z.string(), activityMin: z.string() }), fields: [{ name: 'topics', label: 'Topics to Cover', step: 1, min: 1 }, { name: 'minutesPer', label: 'Minutes per Topic', step: 5, min: 5 }, { name: 'activities', label: 'Activities', step: 1, min: 0 }, { name: 'activityMin', label: 'Minutes per Activity', step: 5, min: 0 }], compute: (v) => ({ result: n(v.topics)*(n(v.minutesPer)||15)+n(v.activities)*(n(v.activityMin)||10), label: 'Total Lesson Time', unit: 'min', steps: [`Topics: ${n(v.topics)} x ${n(v.minutesPer)||15} min = ${n(v.topics)*(n(v.minutesPer)||15)}`, `Activities: ${n(v.activities)} x ${n(v.activityMin)||10} min = ${n(v.activities)*(n(v.activityMin)||10)}`] }), description: 'Calculate lesson plan duration.', formula: 'Total = Topics x Min/Topic + Activities x Min/Activity', interpretation: 'Include buffer time for transitions and questions.' },

  'learning-objectives': { schema: z.object({ objectives: z.string(), classMin: z.string(), frequency: z.string() }), fields: [{ name: 'objectives', label: 'Learning Objectives', step: 1, min: 1 }, { name: 'classMin', label: 'Class Minutes per Week', step: 15, min: 15 }, { name: 'frequency', label: 'Weeks Available', step: 1, min: 1 }], compute: (v) => { const totalMin = n(v.classMin)*n(v.frequency); const minPerObj = totalMin/n(v.objectives); return { result: minPerObj, label: 'Minutes per Objective', unit: 'min', steps: [`Total: ${totalMin} min`, `Objectives: ${n(v.objectives)}`, `${minPerObj.toFixed(0)} min per objective`] } }, description: 'Allocate time per learning objective.', formula: 'Min/Obj = (ClassMin x Weeks) / Objectives', interpretation: 'Prioritize key objectives. Spend more time on complex skills.' },

  'reading-level': { schema: z.object({ correct: z.string(), total: z.string(), grade: z.string() }), fields: [{ name: 'correct', label: 'Passages Correct', step: 1, min: 0 }, { name: 'total', label: 'Total Passages', step: 1, min: 1 }, { name: 'grade', label: 'Current Grade Level', type: 'select', options: [{ label: 'K', value: 'K' }, { label: '1', value: '1' }, { label: '2', value: '2' }, { label: '3', value: '3' }, { label: '4', value: '4' }, { label: '5', value: '5' }] }], compute: (v) => { const pct = n(v.total)>0?n(v.correct)/n(v.total):0; const g = String(v.grade)=='K'?0:parseInt(String(v.grade)); const level = pct>=0.9?g+2:pct>=0.75?g+1:pct>=0.5?g:Math.max(0,g-1); return { result: `Grade ${level}`, label: 'Est. Reading Level', unit: '', steps: [`Score: ${(pct*100).toFixed(0)}%`, `Grade: ${String(v.grade)}`, `Reading Level: Grade ${level}`] } }, description: 'Estimate reading level from assessment.', formula: 'Level = Grade + (correct/total) based adjustment.', interpretation: 'Child reading at or above grade level is on track. Below = intervention.' },

  'dolch-words': { schema: z.object({ known: z.string(), total: z.string(), level: z.string() }), fields: [{ name: 'known', label: 'Words Known', step: 1, min: 0 }, { name: 'total', label: 'Total Words in Set', step: 1, min: 1 }, { name: 'level', label: 'Dolch Level', type: 'select', options: [{ label: 'Pre-Primer', value: 'pp' }, { label: 'Primer', value: 'p' }, { label: 'Grade 1', value: '1' }, { label: 'Grade 2', value: '2' }, { label: 'Grade 3', value: '3' }] }], compute: (v) => { const pct = n(v.total)>0?n(v.known)/n(v.total)*100:0; const next = pct>=80?'Ready for next level':'Practice this level'; return { result: pct, label: 'Dolch Mastery', unit: '%', steps: [`${n(v.known)}/${n(v.total)} known`, `${pct.toFixed(0)}%`, next] } }, description: 'Track Dolch sight word mastery.', formula: 'Mastery % = Known/Total x 100', interpretation: '80%+ mastery recommended before advancing to next Dolch level.' },

  'guided-reading-level': { schema: z.object({ accuracy: z.string(), comprehension: z.string(), rate: z.string() }), fields: [{ name: 'accuracy', label: 'Accuracy (%)', step: 1, min: 0, max: 100 }, { name: 'comprehension', label: 'Comprehension (%)', step: 1, min: 0, max: 100 }, { name: 'rate', label: 'Reading Rate (WPM)', step: 5, min: 0 }], compute: (v) => { const acc = n(v.accuracy)>=95?'Independent':n(v.accuracy)>=90?'Instructional':'Frustration'; const comp = n(v.comprehension)>=80?'Good':n(v.comprehension)>=60?'Fair':'Poor'; const r = acc=='Independent'&&comp=='Good'?'Move up':acc=='Frustration'?'Move down':'Stay'; return { result: `${acc}/${comp}`, label: 'Reading Level', unit: '', steps: [`Accuracy: ${n(v.accuracy)}% (${acc})`, `Comp: ${n(v.comprehension)}% (${comp})`, `Rate: ${n(v.rate)} WPM`, `Recommendation: ${r}`] } }, description: 'Determine guided reading level.', formula: 'Accuracy + Comprehension + Rate assessment.', interpretation: 'Independent: 95%+ accuracy, 80%+ comp. Instructional: 90-94%. Frustration: <90%.' },

  'reading-log': { schema: z.object({ pages: z.string(), minutes: z.string(), entries: z.string() }), fields: [{ name: 'pages', label: 'Total Pages Read', step: 5, min: 0 }, { name: 'minutes', label: 'Total Minutes', step: 5, min: 0 }, { name: 'entries', label: 'Number of Log Entries', step: 1, min: 1 }], compute: (v) => ({ result: n(v.minutes)>0?n(v.pages)/n(v.minutes)*60:0, label: 'Avg Pages per Hour', unit: 'pph', steps: [`${n(v.pages)} pages in ${n(v.minutes)} min`, `Avg: ${(n(v.minutes)>0?n(v.pages)/n(v.minutes)*60:0).toFixed(1)} pages/hr`, `Entries: ${n(v.entries)}`] }), description: 'Track reading log progress.', formula: 'Pace = Pages / Minutes x 60', interpretation: 'Track daily reading. Goal: 20-30 min/day for literacy growth.' },

  'reading-comprehension': { schema: z.object({ correct: z.string(), total: z.string() }), fields: [{ name: 'correct', label: 'Correct Answers', step: 1, min: 0 }, { name: 'total', label: 'Total Questions', step: 1, min: 1 }], compute: (v) => ({ result: n(v.total)>0?n(v.correct)/n(v.total)*100:0, label: 'Comprehension Score', unit: '%', steps: [`${n(v.correct)}/${n(v.total)} = ${(n(v.total)>0?n(v.correct)/n(v.total)*100:0).toFixed(1)}%`, n(v.total)>0&&n(v.correct)/n(v.total)>=0.75?'Proficient':'Needs practice'] }), description: 'Calculate reading comprehension score.', formula: '% = Correct/Total x 100', interpretation: '75%+ = proficient. Below = need strategy instruction.' },

  'essay-score': { schema: z.object({ content: z.string(), org: z.string(), style: z.string(), mechanics: z.string() }), fields: [{ name: 'content', label: 'Content (0-100)', step: 1, min: 0, max: 100 }, { name: 'org', label: 'Organization (0-100)', step: 1, min: 0, max: 100 }, { name: 'style', label: 'Style (0-100)', step: 1, min: 0, max: 100 }, { name: 'mechanics', label: 'Mechanics (0-100)', step: 1, min: 0, max: 100 }], compute: (v) => ({ result: (n(v.content)+n(v.org)+n(v.style)+n(v.mechanics))/4, label: 'Avg Essay Score', unit: '%', steps: [`Content: ${n(v.content)}`, `Org: ${n(v.org)}`, `Style: ${n(v.style)}`, `Mech: ${n(v.mechanics)}`, `Avg: ${((n(v.content)+n(v.org)+n(v.style)+n(v.mechanics))/4).toFixed(1)}%`] }), description: 'Average essay rubric score.', formula: 'Avg = (Content+Org+Style+Mechanics)/4', interpretation: 'Use specific rubric criteria for each dimension.' },

  'grammar-check': { schema: z.object({ errors: z.string(), words: z.string() }), fields: [{ name: 'errors', label: 'Grammar Errors Found', step: 1, min: 0 }, { name: 'words', label: 'Word Count', step: 10, min: 1 }], compute: (v) => ({ result: n(v.words)>0?n(v.errors)/n(v.words)*100:0, label: 'Error Rate', unit: '%', steps: [`${n(v.errors)} errors in ${n(v.words)} words`, `${(n(v.words)>0?n(v.errors)/n(v.words)*100:0).toFixed(2)}% error rate`, n(v.words)>0&&n(v.errors)/n(v.words)<=0.02?'Good grammar':'Proofread needed'] }), description: 'Calculate grammar error rate in writing.', formula: 'Error Rate = Errors/Words x 100', interpretation: 'Target <2% error rate for academic writing.' },

  'plagiarism-scan': { schema: z.object({ unique: z.string(), total: z.string(), sources: z.string() }), fields: [{ name: 'unique', label: 'Unique Words', step: 10, min: 0 }, { name: 'total', label: 'Total Words', step: 10, min: 1 }, { name: 'sources', label: 'Sources Cited', step: 1, min: 0 }], compute: (v) => { const origPct = n(v.total)>0?n(v.unique)/n(v.total)*100:0; return { result: origPct, label: 'Originality Score', unit: '%', steps: [`${n(v.unique)}/${n(v.total)} = ${origPct.toFixed(1)}%`, `Sources: ${n(v.sources)}`, origPct<50?'Low originality - cite sources':'Acceptable originality'] } }, description: 'Check for originality in writing.', formula: 'Originality = Unique/Total x 100', interpretation: 'High originality >80%. Always cite sources properly.' },

  'summer-reading-list': { schema: z.object({ books: z.string(), pages: z.string(), weeks: z.string() }), fields: [{ name: 'books', label: 'Books on List', step: 1, min: 1 }, { name: 'pages', label: 'Avg Pages per Book', step: 10, min: 1 }, { name: 'weeks', label: 'Weeks Available', step: 1, min: 1 }], compute: (v) => { const totalPages = n(v.books)*(n(v.pages)||200); const perWeek = totalPages/(n(v.weeks)||10); return { result: perWeek, label: 'Pages per Week', unit: 'pg/wk', steps: [`${n(v.books)} books x ${n(v.pages)||200} pg = ${totalPages} pg`, `${n(v.weeks)||10} weeks`, `${perWeek.toFixed(0)} pg/wk = ${(perWeek/7).toFixed(0)} pg/day`] } }, description: 'Plan summer reading schedule.', formula: 'Pace = (Books x Pages) / Weeks', interpretation: 'Read 15-20 min/day to stay on track. Use public library.' },

  'thesis-length': { schema: z.object({ chapters: z.string(), pagesPer: z.string(), figures: z.string(), wordsPerPage: z.string() }), fields: [{ name: 'chapters', label: 'Chapters', step: 1, min: 1 }, { name: 'pagesPer', label: 'Avg Pages per Chapter', step: 5, min: 1 }, { name: 'figures', label: 'Figures/Tables', step: 5, min: 0 }, { name: 'wordsPerPage', label: 'Words per Page', placeholder: '250', step: 25, min: 50 }], compute: (v) => { const pages = n(v.chapters)*(n(v.pagesPer)||20)+Math.ceil(n(v.figures)/2); const words = pages*(n(v.wordsPerPage)||250); return { result: pages, label: 'Estimated Length', unit: 'pages', steps: [`Chapters: ${n(v.chapters)} x ${n(v.pagesPer)||20} pg = ${n(v.chapters)*(n(v.pagesPer)||20)}`, `Figures: ~${Math.ceil(n(v.figures)/2)} pg`, `Total: ~${pages} pg (${words.toLocaleString()} words)`] } }, description: 'Estimate thesis or dissertation length.', formula: 'Pages = Chapters x Pages/Chapter + Figures/2', interpretation: 'Master thesis: 50-100 pg. PhD: 150-300 pg. Check dept guidelines.' },

  'dissertation-timeline': { schema: z.object({ proposal: z.string(), research: z.string(), writing: z.string(), defense: z.string(), months: z.string() }), fields: [{ name: 'proposal', label: 'Proposal Phase (months)', step: 1, min: 1 }, { name: 'research', label: 'Research Phase (months)', step: 1, min: 1 }, { name: 'writing', label: 'Writing Phase (months)', step: 1, min: 1 }, { name: 'defense', label: 'Defense Prep (months)', step: 1, min: 1 }, { name: 'months', label: 'Total Allowed Months', step: 3, min: 6 }], compute: (v) => { const total = n(v.proposal)+n(v.research)+n(v.writing)+n(v.defense); const allowed = n(v.months)||60; return { result: total, label: 'Projected Timeline', unit: 'months', steps: [`Proposal: ${n(v.proposal)} mo`, `Research: ${n(v.research)} mo`, `Writing: ${n(v.writing)} mo`, `Defense: ${n(v.defense)} mo`, `Total: ${total} mo (allowed: ${allowed} mo)`, total<=allowed? 'On track': 'Exceeds limit - adjust scope' ] } }, description: 'Plan dissertation timeline.', formula: 'Total = Proposal + Research + Writing + Defense', interpretation: 'PhD timeline: 4-7 years. Plan backwards from defense date.' },

  'lit-review-count': { schema: z.object({ sources: z.string(), weeks: z.string(), perWeek: z.string() }), fields: [{ name: 'sources', label: 'Total Sources Needed', step: 5, min: 1 }, { name: 'weeks', label: 'Weeks Available', step: 1, min: 1 }, { name: 'perWeek', label: 'Sources per Week (reading)', step: 1, min: 1 }], compute: (v) => { const capacity = n(v.weeks)*n(v.perWeek); const rate = n(v.weeks)>0?n(v.sources)/n(v.weeks):0; return { result: rate, label: 'Sources per Week', unit: '/wk', steps: [`${n(v.sources)} sources / ${n(v.weeks)} wks = ${rate.toFixed(0)}/wk`, `Capacity: ${capacity}`, capacity>=n(v.sources)?'Feasible':'Increase pace'] } }, description: 'Plan literature review reading schedule.', formula: 'Rate = Sources/Weeks', interpretation: 'Read+annotate 3-5 sources/week. Use reference manager.' },

  'research-proposal': { schema: z.object({ pages: z.string(), weeks: z.string(), sources: z.string(), experiments: z.string() }), fields: [{ name: 'pages', label: 'Pages Required', step: 1, min: 1 }, { name: 'weeks', label: 'Weeks Until Due', step: 1, min: 1 }, { name: 'sources', label: 'Sources to Review', step: 5, min: 0 }, { name: 'experiments', label: 'Experiments/Studies', step: 1, min: 0 }], compute: (v) => { const pagesPerWeek = n(v.pages)/n(v.weeks); const sourcesPerWeek = n(v.sources)/n(v.weeks); return { result: `${pagesPerWeek.toFixed(1)} pg/wk`, label: 'Writing Pace', unit: '', steps: [`Pages: ${pagesPerWeek.toFixed(1)}/wk`, `Sources: ${sourcesPerWeek.toFixed(0)}/wk`, `Experiments: ${n(v.experiments)}`] } }, description: 'Plan research proposal timeline.', formula: 'Pace = Pages/Weeks', interpretation: 'Write iteratively: outline, draft, revise, polish.' },

  'research-grant': { schema: z.object({ budget: z.string(), months: z.string(), personnel: z.string(), equipment: z.string(), travel: z.string() }), fields: [{ name: 'budget', label: 'Total Budget ($)', step: 10000, min: 0 }, { name: 'months', label: 'Months', step: 6, min: 6 }, { name: 'personnel', label: 'Personnel (%)', step: 5, min: 0, max: 100 }, { name: 'equipment', label: 'Equipment (%)', step: 5, min: 0, max: 100 }, { name: 'travel', label: 'Travel (%)', step: 5, min: 0, max: 100 }], compute: (v) => { const perMonth = n(v.budget)/n(v.months); const per = n(v.personnel)+n(v.equipment)+n(v.travel); const valid = per<=100; return { result: perMonth, label: 'Monthly Budget', unit: '$', steps: [`Total: $${n(v.budget).toFixed(0)} over ${n(v.months)} mo`, `Personnel: ${n(v.personnel)}% = $${(n(v.budget)*n(v.personnel)/100).toFixed(0)}`, `Equipment: ${n(v.equipment)}% = $${(n(v.budget)*n(v.equipment)/100).toFixed(0)}`, `Travel: ${n(v.travel)}% = $${(n(v.budget)*n(v.travel)/100).toFixed(0)}`, `Monthly: $${perMonth.toFixed(0)}`, valid?'':'Budget >100% - adjust percentages'] } }, description: 'Plan research grant budget.', formula: 'Allocation = Budget x %', interpretation: 'Allocate 40-60% personnel, 20-30% equipment, 10-20% travel/other.' },

  'conference-budget': { schema: z.object({ registration: z.string(), travel: z.string(), hotel: z.string(), meals: z.string(), days: z.string() }), fields: [{ name: 'registration', label: 'Registration ($)', step: 50, min: 0 }, { name: 'travel', label: 'Travel ($)', step: 100, min: 0 }, { name: 'hotel', label: 'Hotel/Night ($)', step: 50, min: 0 }, { name: 'meals', label: 'Meals/Day ($)', step: 25, min: 0 }, { name: 'days', label: 'Days', step: 1, min: 1 }], compute: (v) => ({ result: n(v.registration)+n(v.travel)+(n(v.hotel)*n(v.days))+(n(v.meals)*n(v.days)), label: 'Total Conference Cost', unit: '$', steps: [`Registration: $${n(v.registration).toFixed(0)}`, `Travel: $${n(v.travel).toFixed(0)}`, `Hotel: $${n(v.hotel).toFixed(0)} x ${n(v.days)} = $${(n(v.hotel)*n(v.days)).toFixed(0)}`, `Meals: $${n(v.meals).toFixed(0)} x ${n(v.days)} = $${(n(v.meals)*n(v.days)).toFixed(0)}`, `Total: $${(n(v.registration)+n(v.travel)+(n(v.hotel)*n(v.days))+(n(v.meals)*n(v.days))).toFixed(0)}`] }), description: 'Budget for academic conference attendance.', formula: 'Total = Registration + Travel + Hotel*Days + Meals*Days', interpretation: 'Apply for travel grants through your dept or professional organizations.' },

  'science-fair-budget': { schema: z.object({ materials: z.string(), equipment: z.string(), display: z.string(), travel: z.string(), registration: z.string() }), fields: [{ name: 'materials', label: 'Materials ($)', step: 10, min: 0 }, { name: 'equipment', label: 'Equipment ($)', step: 25, min: 0 }, { name: 'display', label: 'Display Board ($)', step: 10, min: 0 }, { name: 'travel', label: 'Travel ($)', step: 25, min: 0 }, { name: 'registration', label: 'Registration Fee ($)', step: 10, min: 0 }], compute: (v) => ({ result: n(v.materials)+n(v.equipment)+n(v.display)+n(v.travel)+n(v.registration), label: 'Total Cost', unit: '$', steps: [`Materials: $${n(v.materials).toFixed(0)}`, `Equipment: $${n(v.equipment).toFixed(0)}`, `Display: $${n(v.display).toFixed(0)}`, `Travel: $${n(v.travel).toFixed(0)}`, `Registration: $${n(v.registration).toFixed(0)}`, `Total: $${(n(v.materials)+n(v.equipment)+n(v.display)+n(v.travel)+n(v.registration)).toFixed(0)}`] }), description: 'Budget for science fair project.', formula: 'Sum of all categories.', interpretation: 'Keep budget under $100 for local fairs. Regional fairs may cost more.' },

  'science-fair-judging': { schema: z.object({ creativity: z.string(), method: z.string(), analysis: z.string(), display: z.string(), presentation: z.string() }), fields: [{ name: 'creativity', label: 'Creativity (0-20)', step: 1, min: 0, max: 20 }, { name: 'method', label: 'Scientific Method (0-30)', step: 1, min: 0, max: 30 }, { name: 'analysis', label: 'Data Analysis (0-25)', step: 1, min: 0, max: 25 }, { name: 'display', label: 'Display (0-15)', step: 1, min: 0, max: 15 }, { name: 'presentation', label: 'Presentation (0-10)', step: 1, min: 0, max: 10 }], compute: (v) => ({ result: n(v.creativity)+n(v.method)+n(v.analysis)+n(v.display)+n(v.presentation), label: 'Total Score', unit: '/100', steps: [`Creativity: ${n(v.creativity)}/20`, `Method: ${n(v.method)}/30`, `Analysis: ${n(v.analysis)}/25`, `Display: ${n(v.display)}/15`, `Presentation: ${n(v.presentation)}/10`] }), description: 'Score science fair projects.', formula: 'Total = Creativity + Method + Analysis + Display + Presentation', interpretation: 'Standard ISEF rubric categories with allocated points.' },

  'school-budget': { schema: z.object({ teachers: z.string(), staff: z.string(), supplies: z.string(), technology: z.string(), facilities: z.string(), reserve: z.string() }), fields: [{ name: 'teachers', label: 'Teachers ($)', step: 10000, min: 0 }, { name: 'staff', label: 'Staff ($)', step: 5000, min: 0 }, { name: 'supplies', label: 'Supplies ($)', step: 1000, min: 0 }, { name: 'technology', label: 'Technology ($)', step: 5000, min: 0 }, { name: 'facilities', label: 'Facilities ($)', step: 10000, min: 0 }, { name: 'reserve', label: 'Reserve Fund ($)', step: 5000, min: 0 }], compute: (v) => ({ result: n(v.teachers)+n(v.staff)+n(v.supplies)+n(v.technology)+n(v.facilities)+n(v.reserve), label: 'Total School Budget', unit: '$', steps: [`Teachers: $${n(v.teachers).toFixed(0)}`, `Staff: $${n(v.staff).toFixed(0)}`, `Supplies: $${n(v.supplies).toFixed(0)}`, `Tech: $${n(v.technology).toFixed(0)}`, `Facilities: $${n(v.facilities).toFixed(0)}`, `Reserve: $${n(v.reserve).toFixed(0)}`] }), description: 'Plan school budget allocation.', formula: 'Sum of all categories.', interpretation: '60-70% to instruction, 10-15% to operations, 5-10% to tech, 5-10% reserve.' },

  'school-fundraiser': { schema: z.object({ goal: z.string(), participants: z.string(), avgDonation: z.string(), weeks: z.string() }), fields: [{ name: 'goal', label: 'Fundraising Goal ($)', step: 100, min: 0 }, { name: 'participants', label: 'Participants', step: 1, min: 1 }, { name: 'avgDonation', label: 'Avg Donation per Person ($)', step: 5, min: 1 }, { name: 'weeks', label: 'Weeks', step: 1, min: 1 }], compute: (v) => { const projected = n(v.participants)*(n(v.avgDonation)||10)*n(v.weeks); return { result: projected, label: 'Projected Total', unit: '$', steps: [`${n(v.participants)} people x $${n(v.avgDonation)||10} x ${n(v.weeks)} wks`, `Projected: $${projected.toFixed(0)}`, `Goal: $${n(v.goal).toFixed(0)}`, projected>=n(v.goal)?'Goal achievable':'Increase participants or donation avg'] } }, description: 'Plan school fundraiser and track goal.', formula: 'Projected = Participants x AvgDonation x Weeks', interpretation: 'Include expenses in net calculation. Promote through multiple channels.' },

  'field-trip-budget': { schema: z.object({ students: z.string(), transport: z.string(), admission: z.string(), lunch: z.string(), chaperones: z.string() }), fields: [{ name: 'students', label: 'Students', step: 1, min: 1 }, { name: 'transport', label: 'Transport per Student ($)', step: 5, min: 0 }, { name: 'admission', label: 'Admission per Student ($)', step: 5, min: 0 }, { name: 'lunch', label: 'Lunch per Student ($)', step: 5, min: 0 }, { name: 'chaperones', label: 'Chaperone Ratio (1:X)', placeholder: '10', step: 1, min: 1 }], compute: (v) => { const perStudent = n(v.transport)+n(v.admission)+n(v.lunch); const numChaperones = Math.ceil(n(v.students)/Math.max(1,n(v.chaperones)||10)); const total = n(v.students)*perStudent+numChaperones*perStudent*0.5; return { result: total, label: 'Total Trip Cost', unit: '$', steps: [`Per student: $${perStudent.toFixed(0)}`, `Students: ${n(v.students)}`, `Chaperones: ${numChaperones}`, `Total: $${total.toFixed(0)}`] } }, description: 'Budget for field trip costs.', formula: 'Total = Students x (Transport+Admission+Lunch) + Chaperones', interpretation: 'Chaperone costs ~50% of student cost. Apply for PTA grants.' },

  'classroom-supplies': { schema: z.object({ students: z.string(), basicSupplies: z.string(), subjectSupplies: z.string(), techSupplies: z.string(), furniture: z.string() }), fields: [{ name: 'students', label: 'Students', step: 1, min: 1 }, { name: 'basicSupplies', label: 'Basic per Student ($)', placeholder: '25', step: 5, min: 0 }, { name: 'subjectSupplies', label: 'Subject per Student ($)', placeholder: '15', step: 5, min: 0 }, { name: 'techSupplies', label: 'Tech per Student ($)', placeholder: '10', step: 5, min: 0 }, { name: 'furniture', label: 'Classroom Furniture ($)', step: 50, min: 0 }], compute: (v) => ({ result: n(v.students)*((n(v.basicSupplies)||25)+(n(v.subjectSupplies)||15)+(n(v.techSupplies)||10))+n(v.furniture), label: 'Total Supplies Cost', unit: '$', steps: [`${n(v.students)} students`, `Basic: $${(n(v.basicSupplies)||25)}/student`, `Subject: $${(n(v.subjectSupplies)||15)}/student`, `Tech: $${(n(v.techSupplies)||10)}/student`, `Furniture: $${n(v.furniture).toFixed(0)}`, `Total: $${(n(v.students)*((n(v.basicSupplies)||25)+(n(v.subjectSupplies)||15)+(n(v.techSupplies)||10))+n(v.furniture)).toFixed(0)}`] }), description: 'Budget classroom supplies per student.', formula: 'Total = Students x (Basic+Subject+Tech) + Furniture', interpretation: 'Teachers spend $500-1000/yr of own money. Seek DonorsChoose grants.' },

  'daily-homework-tracker': { schema: z.object({ assignments: z.string(), completed: z.string(), days: z.string() }), fields: [{ name: 'assignments', label: 'Total Assignments', step: 1, min: 1 }, { name: 'completed', label: 'Completed', step: 1, min: 0 }, { name: 'days', label: 'Days Tracked', step: 1, min: 1 }], compute: (v) => { const rate = n(v.days)>0?n(v.completed)/n(v.days):0; const pct = n(v.assignments)>0?n(v.completed)/n(v.assignments)*100:0; return { result: rate, label: 'Completion Rate', unit: '/day', steps: [`${n(v.completed)}/${n(v.assignments)} (${pct.toFixed(0)}%)`, `${rate.toFixed(1)} assignments/day`] } }, description: 'Track daily homework completion rate.', formula: 'Rate = Completed/Days | % = Completed/Assignments', interpretation: 'Aim for >90% completion rate. Seek help if falling behind.' },

  'late-work-penalty': { schema: z.object({ earned: z.string(), lateDays: z.string(), penaltyPerDay: z.string() }), fields: [{ name: 'earned', label: 'Score Earned (%)', step: 1, min: 0, max: 100 }, { name: 'lateDays', label: 'Days Late', step: 1, min: 1 }, { name: 'penaltyPerDay', label: 'Penalty per Day (%)', placeholder: '10', step: 5, min: 0, max: 100 }], compute: (v) => { const penalty = n(v.lateDays)*(n(v.penaltyPerDay)||10); const finalScore = Math.max(0,n(v.earned)-penalty); return { result: finalScore, label: 'Score After Late Penalty', unit: '%', steps: [`Original: ${n(v.earned)}%`, `Penalty: ${n(v.lateDays)}d x ${n(v.penaltyPerDay)||10}% = ${penalty}%`, `Final: ${finalScore.toFixed(0)}%`] } }, description: 'Calculate late assignment penalty.', formula: 'Final = Original - (DaysLate x PenaltyRate)', interpretation: 'Typical: -10% per day for up to 3-5 days. Some teachers cap penalty.' },

  'make-up-work': { schema: z.object({ daysMissed: z.string(), assignmentsMissed: z.string(), perAssignment: z.string(), dailyAvailable: z.string() }), fields: [{ name: 'daysMissed', label: 'Days Missed', step: 1, min: 1 }, { name: 'assignmentsMissed', label: 'Assignments Missed', step: 1, min: 1 }, { name: 'perAssignment', label: 'Min per Assignment', step: 10, min: 10 }, { name: 'dailyAvailable', label: 'Available Min per Day', step: 15, min: 15 }], compute: (v) => { const totalMin = n(v.assignmentsMissed)*(n(v.perAssignment)||30); const daysNeeded = Math.ceil(totalMin/Math.max(1,n(v.dailyAvailable)||30)); return { result: daysNeeded, label: 'Days to Catch Up', unit: 'days', steps: [`Total: ${totalMin} min`, `${n(v.dailyAvailable)||30} min/day available`, `Need: ${daysNeeded} days`, daysNeeded<=n(v.daysMissed)*2?'Reasonable':'Prioritize key assignments'] } }, description: 'Plan make-up work schedule after absence.', formula: 'Days = (Assignments x Min/Assignment) / AvailableMin/Day', interpretation: 'Prioritize major assignments. Talk to teacher about extensions.' },

  'teacher-hours': { schema: z.object({ teaching: z.string(), prep: z.string(), grading: z.string(), meetings: z.string(), extracurricular: z.string(), admin: z.string() }), fields: [{ name: 'teaching', label: 'Teaching (hrs/wk)', step: 1, min: 0 }, { name: 'prep', label: 'Prep (hrs/wk)', step: 1, min: 0 }, { name: 'grading', label: 'Grading (hrs/wk)', step: 1, min: 0 }, { name: 'meetings', label: 'Meetings (hrs/wk)', step: 0.5, min: 0 }, { name: 'extracurricular', label: 'Extracurricular (hrs/wk)', step: 0.5, min: 0 }, { name: 'admin', label: 'Admin (hrs/wk)', step: 0.5, min: 0 }], compute: (v) => ({ result: n(v.teaching)+n(v.prep)+n(v.grading)+n(v.meetings)+n(v.extracurricular)+n(v.admin), label: 'Total Weekly Hours', unit: 'hrs/wk', steps: [`Teaching: ${n(v.teaching)}`, `Prep: ${n(v.prep)}`, `Grading: ${n(v.grading)}`, `Meetings: ${n(v.meetings)}`, `Extracurricular: ${n(v.extracurricular)}`, `Admin: ${n(v.admin)}`, `Total: ${(n(v.teaching)+n(v.prep)+n(v.grading)+n(v.meetings)+n(v.extracurricular)+n(v.admin)).toFixed(1)} hrs/wk`] }), description: 'Track teacher weekly work hours.', formula: 'Sum of all categories.', interpretation: 'Avg teacher: 50-55 hrs/wk. Budget 10 hrs/wk for planning and grading.' },

  'iep-accommodations': { schema: z.object({ extraTime: z.string(), smallGroup: z.string(), oralTest: z.string(), prefSeating: z.string(), breaks: z.string() }), fields: [{ name: 'extraTime', label: 'Extra Time Needed (50% more)', type: 'select', options: [{ label: 'Yes', value: '1' }, { label: 'No', value: '0' }] }, { name: 'smallGroup', label: 'Small Group Testing', type: 'select', options: [{ label: 'Yes', value: '1' }, { label: 'No', value: '0' }] }, { name: 'oralTest', label: 'Oral Testing', type: 'select', options: [{ label: 'Yes', value: '1' }, { label: 'No', value: '0' }] }, { name: 'prefSeating', label: 'Preferential Seating', type: 'select', options: [{ label: 'Yes', value: '1' }, { label: 'No', value: '0' }] }, { name: 'breaks', label: 'Frequent Breaks', type: 'select', options: [{ label: 'Yes', value: '1' }, { label: 'No', value: '0' }] }], compute: (v) => { const count = [n(v.extraTime),n(v.smallGroup),n(v.oralTest),n(v.prefSeating),n(v.breaks)].filter(x=>x>0).length; const needs = count>=3?'Significant supports':'Moderate supports'; return { result: count, label: 'Accommodations Needed', unit: 'active', steps: [`Accommodations: ${count}/5 active`, needs, 'Document in IEP. Review annually.'] } }, description: 'Track IEP accommodations for students.', formula: 'Count of active accommodations.', interpretation: 'IEP accommodations are legally required. Document implementation fidelity.' },

  'behavior-tracker': { schema: z.object({ positive: z.string(), negative: z.string(), days: z.string(), interventions: z.string() }), fields: [{ name: 'positive', label: 'Positive Behaviors (weekly)', step: 1, min: 0 }, { name: 'negative', label: 'Negative Behaviors (weekly)', step: 1, min: 0 }, { name: 'days', label: 'Days Tracked', step: 1, min: 1 }, { name: 'interventions', label: 'Interventions Used', step: 1, min: 0 }], compute: (v) => { const posDaily = n(v.positive)/n(v.days); const negDaily = n(v.negative)/n(v.days); const ratio = n(v.negative)>0?n(v.positive)/n(v.negative):n(v.positive); return { result: ratio.toFixed(1), label: 'Pos:Neg Ratio', unit: ':1', steps: [`Positive: ${n(v.positive)} (${posDaily.toFixed(1)}/day)`, `Negative: ${n(v.negative)} (${negDaily.toFixed(1)}/day)`, `Ratio: ${ratio.toFixed(1)}:1`, `Interventions: ${n(v.interventions)}`, ratio>=3?'Healthy ratio':'Increase positive reinforcement'] } }, description: 'Track student behavior over time.', formula: 'Pos:Neg Ratio = Positive / Negative', interpretation: 'Target 4:1 positive:negative interactions. Track trends weekly.' },

  'attendance-tracker': { schema: z.object({ present: z.string(), absent: z.string(), tardy: z.string(), totalDays: z.string() }), fields: [{ name: 'present', label: 'Days Present', step: 1, min: 0 }, { name: 'absent', label: 'Days Absent', step: 1, min: 0 }, { name: 'tardy', label: 'Times Tardy', step: 1, min: 0 }, { name: 'totalDays', label: 'Total School Days', step: 1, min: 1 }], compute: (v) => { const pct = n(v.totalDays)>0?(n(v.present)/n(v.totalDays))*100:0; const tardyRate = n(v.totalDays)>0?(n(v.tardy)/n(v.totalDays))*100:0; return { result: pct, label: 'Attendance Rate', unit: '%', steps: [`Present: ${n(v.present)}/${n(v.totalDays)}`, `Absent: ${n(v.absent)}`, `Tardy: ${n(v.tardy)} (${tardyRate.toFixed(1)}%)`, pct>=95?'Excellent attendance':pct>=90?'Satisfactory':'Concerning (<90%)'] } }, description: 'Track student attendance statistics.', formula: 'Rate = Present/TotalDays x 100', interpretation: '95%+ = excellent. Below 90% = chronic absenteeism. Tardies disrupt learning.' },

  'learning-style': { schema: z.object({ visual: z.string(), auditory: z.string(), reading: z.string(), kinesthetic: z.string() }), fields: [{ name: 'visual', label: 'Visual Score', step: 1, min: 0, max: 20 }, { name: 'auditory', label: 'Auditory Score', step: 1, min: 0, max: 20 }, { name: 'reading', label: 'Reading/Writing Score', step: 1, min: 0, max: 20 }, { name: 'kinesthetic', label: 'Kinesthetic Score', step: 1, min: 0, max: 20 }], compute: (v) => { const scores = {V: n(v.visual), A: n(v.auditory), R: n(v.reading), K: n(v.kinesthetic)}; const top = Object.entries(scores).sort((a,b)=>b[1]-a[1])[0]; const names: Record<string,string> = {V:'Visual', A:'Auditory', R:'Reading/Writing', K:'Kinesthetic'}; return { result: names[top[0]]||'', label: 'Primary Learning Style', unit: '', steps: [`V: ${scores.V}, A: ${scores.A}, R: ${scores.R}, K: ${scores.K}`, `Primary: ${names[top[0]]||''}`] } }, description: 'Identify VARK learning style preferences.', formula: 'VARK model: Visual, Auditory, Reading/Writing, Kinesthetic.', interpretation: 'Use preferred style for studying. Multi-modal is most effective.' },

  'gifted-identification': { schema: z.object({ cogAbility: z.string(), achievement: z.string(), creativity: z.string(), motivation: z.string() }), fields: [{ name: 'cogAbility', label: 'Cognitive Ability (%)', step: 1, min: 0, max: 100 }, { name: 'achievement', label: 'Achievement (%)', step: 1, min: 0, max: 100 }, { name: 'creativity', label: 'Creativity Score (%)', step: 1, min: 0, max: 100 }, { name: 'motivation', label: 'Motivation Rating (%)', step: 1, min: 0, max: 100 }], compute: (v) => { const avg = (n(v.cogAbility)+n(v.achievement)+n(v.creativity)+n(v.motivation))/4; const likely = avg>=85?'Strongly indicated':avg>=70?'Possibly indicated':'Not indicated'; return { result: avg, label: 'Gifted Indicator Score', unit: '%', steps: [`Cognitive: ${n(v.cogAbility)}%`, `Achievement: ${n(v.achievement)}%`, `Creativity: ${n(v.creativity)}%`, `Motivation: ${n(v.motivation)}%`, `Avg: ${avg.toFixed(0)}%`, likely] } }, description: 'Assess gifted program eligibility indicators.', formula: 'Multi-criteria assessment average.', interpretation: 'Gifted ID uses multiple criteria: ability tests, achievement, creativity, motivation.' },

  'dyslexia-screener': { schema: z.object({ phonAware: z.string(), decoding: z.string(), fluency: z.string(), comp: z.string(), spelling: z.string() }), fields: [{ name: 'phonAware', label: 'Phonological Awareness (%)', step: 1, min: 0, max: 100 }, { name: 'decoding', label: 'Decoding Skills (%)', step: 1, min: 0, max: 100 }, { name: 'fluency', label: 'Reading Fluency (%)', step: 1, min: 0, max: 100 }, { name: 'comp', label: 'Comprehension (%)', step: 1, min: 0, max: 100 }, { name: 'spelling', label: 'Spelling (%)', step: 1, min: 0, max: 100 }], compute: (v) => { const scores = [n(v.phonAware),n(v.decoding),n(v.fluency),n(v.comp),n(v.spelling)]; const avg = scores.reduce((a,b)=>a+b,0)/scores.length; const risk = scores.filter(s=>s<40).length; return { result: avg, label: 'Literacy Composite', unit: '%', steps: [`Avg: ${avg.toFixed(0)}%`, `Below threshold areas: ${risk}/5`, risk>=3?'Further evaluation recommended':'Continue monitoring'] } }, description: 'Quick dyslexia risk screening.', formula: 'Average of 5 literacy skill areas.', interpretation: 'Screening only. Formal evaluation needed for diagnosis. Early intervention is key.' },

  'ell-proficiency': { schema: z.object({ listening: z.string(), speaking: z.string(), reading: z.string(), writing: z.string() }), fields: [{ name: 'listening', label: 'Listening (1-6)', step: 1, min: 1, max: 6 }, { name: 'speaking', label: 'Speaking (1-6)', step: 1, min: 1, max: 6 }, { name: 'reading', label: 'Reading (1-6)', step: 1, min: 1, max: 6 }, { name: 'writing', label: 'Writing (1-6)', step: 1, min: 1, max: 6 }], compute: (v) => { const avg = (n(v.listening)+n(v.speaking)+n(v.reading)+n(v.writing))/4; const level = avg>=5?'Advanced':avg>=4?'Expanding':avg>=3?'Developing':avg>=2?'Emerging':'Entering'; return { result: avg.toFixed(1), label: 'ELL Proficiency Level', unit: '/6', steps: [`L: ${n(v.listening)}, S: ${n(v.speaking)}, R: ${n(v.reading)}, W: ${n(v.writing)}`, `Overall: ${level} (${avg.toFixed(1)}/6)`] } }, description: 'Determine ELL/ESL proficiency level.', formula: 'Average of 4 language domains.', interpretation: 'WIDA levels: 1-Entering to 6-Reaching. Exit criteria varies by state.' },

  'peer-evaluation': { schema: z.object({ contribution: z.string(), quality: z.string(), teamwork: z.string(), timeliness: z.string(), presentation: z.string() }), fields: [{ name: 'contribution', label: 'Contribution (1-5)', step: 1, min: 1, max: 5 }, { name: 'quality', label: 'Quality (1-5)', step: 1, min: 1, max: 5 }, { name: 'teamwork', label: 'Teamwork (1-5)', step: 1, min: 1, max: 5 }, { name: 'timeliness', label: 'Timeliness (1-5)', step: 1, min: 1, max: 5 }, { name: 'presentation', label: 'Presentation (1-5)', step: 1, min: 1, max: 5 }], compute: (v) => ({ result: (n(v.contribution)+n(v.quality)+n(v.teamwork)+n(v.timeliness)+n(v.presentation))/5, label: 'Avg Peer Rating', unit: '/5', steps: [`Avg: ${((n(v.contribution)+n(v.quality)+n(v.teamwork)+n(v.timeliness)+n(v.presentation))/5).toFixed(2)}/5`] }), description: 'Calculate peer evaluation average.', formula: 'Avg = (Contribution+Quality+Teamwork+Timeliness+Presentation)/5', interpretation: 'Include self-evaluation for comparison. Anonymize for honest feedback.' },

  'group-project': { schema: z.object({ members: z.string(), tasks: z.string(), weeks: z.string(), meetingsPerWk: z.string() }), fields: [{ name: 'members', label: 'Group Members', step: 1, min: 2 }, { name: 'tasks', label: 'Total Tasks', step: 1, min: 1 }, { name: 'weeks', label: 'Weeks Available', step: 1, min: 1 }, { name: 'meetingsPerWk', label: 'Meetings per Week', step: 1, min: 1 }], compute: (v) => { const perPerson = n(v.tasks)/n(v.members); const meetings = n(v.weeks)*n(v.meetingsPerWk); return { result: perPerson, label: 'Tasks per Person', unit: 'tasks', steps: [`${n(v.members)} members`, `${n(v.tasks)} tasks = ${perPerson.toFixed(1)}/person`, `${meetings} meetings planned`, 'Assign roles: leader, researcher, writer, editor'] } }, description: 'Plan group project workload distribution.', formula: 'Tasks/Person = Tasks / Members', interpretation: 'Divide work equitably. Set clear deadlines. Use shared docs.' },

  'project-planner': { schema: z.object({ tasks: z.string(), weeks: z.string(), hoursPerTask: z.string(), collaborators: z.string() }), fields: [{ name: 'tasks', label: 'Project Tasks', step: 1, min: 1 }, { name: 'weeks', label: 'Weeks Available', step: 1, min: 1 }, { name: 'hoursPerTask', label: 'Hours per Task', step: 1, min: 1 }, { name: 'collaborators', label: 'Collaborators', step: 1, min: 1 }], compute: (v) => { const totalHrs = n(v.tasks)*n(v.hoursPerTask); const hrsPerPerson = totalHrs/n(v.collaborators); const weeklyPerPerson = hrsPerPerson/n(v.weeks); return { result: weeklyPerPerson, label: 'Weekly Hours per Person', unit: 'hrs/wk', steps: [`Total: ${totalHrs} hrs`, `Split: ${hrsPerPerson.toFixed(0)} hrs/person`, `Pace: ${weeklyPerPerson.toFixed(1)} hrs/wk`] } }, description: 'Plan project with team workload.', formula: 'Weekly = (Tasks x Hrs/Task) / Collaborators / Weeks', interpretation: 'Include buffer time for unexpected delays.' },

  'poster-size': { schema: z.object({ width: z.string(), height: z.string(), fontSize: z.string(), content: z.string() }), fields: [{ name: 'width', label: 'Poster Width (inches)', placeholder: '48', step: 6, min: 12 }, { name: 'height', label: 'Poster Height (inches)', placeholder: '36', step: 6, min: 12 }, { name: 'fontSize', label: 'Title Font Size (pt)', placeholder: '72', step: 12, min: 24 }, { name: 'content', label: 'Content Sections', step: 1, min: 1, placeholder: '5' }], compute: (v) => { const area = n(v.width||48)*n(v.height||36); const sqIn = area; return { result: `${n(v.width||48)}"x${n(v.height||36)}"`, label: 'Poster Dimensions', unit: '', steps: [`Area: ${sqIn} sq in`, `Title: ${n(v.fontSize)||72}pt`, `Content: ${n(v.content)||5} sections`, 'Layout: title top, intro left, methods center, results right, conclusion bottom'] } }, description: 'Plan academic poster dimensions and layout.', formula: 'Custom sizing for academic poster sessions.', interpretation: 'Standard: 48x36 in. Title visible from 10 ft. Text blocks on columns.' },

  'keyboarding-skills': { schema: z.object({ chars: z.string(), minutes: z.string(), errors: z.string(), target: z.string() }), fields: [{ name: 'chars', label: 'Characters Typed', step: 10, min: 1 }, { name: 'minutes', label: 'Minutes', step: 1, min: 1 }, { name: 'errors', label: 'Errors', step: 1, min: 0 }, { name: 'target', label: 'Target WPM', placeholder: '35', step: 5, min: 1 }], compute: (v) => { const wpm = n(v.minutes)>0?Math.max(0,(n(v.chars)/5)/n(v.minutes)-n(v.errors)):0; const acc = (n(v.chars)-n(v.errors))/n(v.chars)*100; return { result: wpm, label: 'Net WPM', unit: 'WPM', steps: [`Speed: ${wpm.toFixed(0)} WPM`, `Accuracy: ${acc.toFixed(1)}%`, wpm>=(n(v.target)||35)?'Goal met':'Keep practicing'] } }, description: 'Assess keyboarding skills.', formula: 'Net WPM = (Chars/5)/Min - Errors', interpretation: 'Target: 35+ WPM by grade 5, 45+ by grade 8. Proper technique matters.' },

  'spelling-test': { schema: z.object({ correct: z.string(), total: z.string(), attempts: z.string() }), fields: [{ name: 'correct', label: 'Words Spelled Correctly', step: 1, min: 0 }, { name: 'total', label: 'Total Words', step: 1, min: 1 }, { name: 'attempts', label: 'Attempts', step: 1, min: 1 }], compute: (v) => ({ result: n(v.total)>0?n(v.correct)/n(v.total)*100:0, label: 'Spelling Score', unit: '%', steps: [`${n(v.correct)}/${n(v.total)} = ${(n(v.total)>0?n(v.correct)/n(v.total)*100:0).toFixed(0)}%`, n(v.attempts)>1?`Best of ${n(v.attempts)} attempts`:'First attempt'] }), description: 'Score spelling tests.', formula: '% = Correct/Total x 100', interpretation: '80%+ = passing. Use word families and patterns for instruction.' },

  '504-plan': { schema: z.object({ accommodations: z.string(), subjects: z.string(), checkIns: z.string(), parentContact: z.string() }), fields: [{ name: 'accommodations', label: 'Accommodations in Plan', step: 1, min: 1 }, { name: 'subjects', label: 'Subjects Needing Support', step: 1, min: 1 }, { name: 'checkIns', label: 'Weekly Check-ins Needed', step: 1, min: 0 }, { name: 'parentContact', label: 'Parent Contacts per Month', step: 1, min: 0 }], compute: (v) => { const total = n(v.accommodations)*n(v.subjects); return { result: total, label: 'Total Accommodation-Subject Pairs', unit: '', steps: [`Accommodations: ${n(v.accommodations)}`, `Subjects: ${n(v.subjects)}`, `Check-ins: ${n(v.checkIns)}/wk`, `Contacts: ${n(v.parentContact)}/mo`] } }, description: 'Track 504 Plan accommodations.', formula: 'Pairs = Accommodations x Subjects', interpretation: '504 Plans provide accommodations. Review annually. Parent input required.' },

  'internet-safety': { schema: z.object({ passwordCheck: z.string(), privacySetting: z.string(), cyberbullying: z.string(), screenTime: z.string(), sharing: z.string() }), fields: [{ name: 'passwordCheck', label: 'Has Strong Password (1-5)', step: 1, min: 1, max: 5 }, { name: 'privacySetting', label: 'Privacy Knowledge (1-5)', step: 1, min: 1, max: 5 }, { name: 'cyberbullying', label: 'Cyberbullying Awareness (1-5)', step: 1, min: 1, max: 5 }, { name: 'screenTime', label: 'Screen Time Management (1-5)', step: 1, min: 1, max: 5 }, { name: 'sharing', label: 'Safe Sharing Habits (1-5)', step: 1, min: 1, max: 5 }], compute: (v) => ({ result: (n(v.passwordCheck)+n(v.privacySetting)+n(v.cyberbullying)+n(v.screenTime)+n(v.sharing))/5, label: 'Digital Safety Score', unit: '/5', steps: [`Avg: ${((n(v.passwordCheck)+n(v.privacySetting)+n(v.cyberbullying)+n(v.screenTime)+n(v.sharing))/5).toFixed(1)}/5`, 'Review: passwords, privacy, cyberbullying, screen time, sharing'] }), description: 'Assess internet safety and digital citizenship.', formula: 'Avg of 5 safety dimensions (1-5 each).', interpretation: 'Score <3: needs education. Use Common Sense Media resources.' },

  'media-literacy': { schema: z.object({ sourceEval: z.string(), biasAware: z.string(), factCheck: z.string(), creation: z.string() }), fields: [{ name: 'sourceEval', label: 'Source Evaluation (1-5)', step: 1, min: 1, max: 5 }, { name: 'biasAware', label: 'Bias Awareness (1-5)', step: 1, min: 1, max: 5 }, { name: 'factCheck', label: 'Fact-Checking (1-5)', step: 1, min: 1, max: 5 }, { name: 'creation', label: 'Content Creation (1-5)', step: 1, min: 1, max: 5 }], compute: (v) => ({ result: (n(v.sourceEval)+n(v.biasAware)+n(v.factCheck)+n(v.creation))/4, label: 'Media Literacy Score', unit: '/5', steps: [`Score: ${((n(v.sourceEval)+n(v.biasAware)+n(v.factCheck)+n(v.creation))/4).toFixed(1)}/5`] }), description: 'Assess media literacy skills.', formula: 'Average of 4 competencies.', interpretation: 'Critical: evaluate sources, recognize bias, verify facts. Teach CRAAP test.' },

  'coding-skills': { schema: z.object({ syntax: z.string(), logic: z.string(), debugging: z.string(), projects: z.string(), concepts: z.string() }), fields: [{ name: 'syntax', label: 'Syntax Knowledge (1-5)', step: 1, min: 1, max: 5 }, { name: 'logic', label: 'Logical Thinking (1-5)', step: 1, min: 1, max: 5 }, { name: 'debugging', label: 'Debugging (1-5)', step: 1, min: 1, max: 5 }, { name: 'projects', label: 'Projects Completed', step: 1, min: 0 }], compute: (v) => ({ result: (n(v.syntax)+n(v.logic)+n(v.debugging))/3, label: 'Coding Competency', unit: '/5', steps: [`Syntax: ${n(v.syntax)}, Logic: ${n(v.logic)}, Debug: ${n(v.debugging)}`, `Avg: ${((n(v.syntax)+n(v.logic)+n(v.debugging))/3).toFixed(1)}/5`, `Projects: ${n(v.projects)}`] }), description: 'Assess coding skills and progress.', formula: 'Avg of syntax, logic, debugging.', interpretation: 'Use Code.org, Scratch for beginners. Python/JS for intermediate.' },

  'book-report': { schema: z.object({ pages: z.string(), days: z.string(), dailyMin: z.string(), reportPages: z.string() }), fields: [{ name: 'pages', label: 'Book Pages', step: 10, min: 1 }, { name: 'days', label: 'Days to Finish', step: 1, min: 1 }, { name: 'dailyMin', label: 'Daily Reading Minutes', step: 5, min: 5 }, { name: 'reportPages', label: 'Report Pages Needed', step: 1, min: 1 }], compute: (v) => { const pace = n(v.pages)/n(v.days); const feasible = (n(v.dailyMin)||20)*n(v.days)>=n(v.pages)*1.5; return { result: pace.toFixed(0), label: 'Pages per Day', unit: 'pg/day', steps: [`Pages: ${n(v.pages)}, Days: ${n(v.days)}`, `${pace.toFixed(0)} pg/day`, feasible?'Manageable pace':'Increase reading time', `Report: ${n(v.reportPages)} pages`, 'Include: summary, characters, theme, opinion'] } }, description: 'Plan book report reading schedule.', formula: 'Pace = Pages / Days', interpretation: 'Read actively: take notes, mark important passages.' },

  'math-fact-drill': { schema: z.object({ correct: z.string(), total: z.string(), seconds: z.string(), targetSec: z.string() }), fields: [{ name: 'correct', label: 'Correct Answers', step: 1, min: 0 }, { name: 'total', label: 'Total Problems', step: 1, min: 1 }, { name: 'seconds', label: 'Total Seconds', step: 5, min: 1 }, { name: 'targetSec', label: 'Target Seconds per Problem', placeholder: '3', step: 1, min: 1 }], compute: (v) => { const pct = n(v.total)>0?n(v.correct)/n(v.total)*100:0; const perProblem = n(v.total)>0?n(v.seconds)/n(v.total):0; return { result: perProblem.toFixed(1), label: 'Seconds per Problem', unit: 'sec', steps: [`Accuracy: ${pct.toFixed(0)}%`, `${perProblem.toFixed(1)} sec/problem`, perProblem<=n(v.targetSec||3)&&pct>=90?'Mastered':'Keep practicing'] } }, description: 'Track math fact fluency.', formula: 'Time/Problem = TotalSec/Problems | Accuracy = Correct/Total', interpretation: 'Target: 3 sec/problem with 90%+ accuracy. Use timed drills daily.' },

  'vocabulary-size': { schema: z.object({ known: z.string(), tested: z.string(), age: z.string() }), fields: [{ name: 'known', label: 'Words Known in Test', step: 1, min: 0 }, { name: 'tested', label: 'Words in Test Sample', step: 1, min: 1 }, { name: 'age', label: 'Age', step: 1, min: 3 }], compute: (v) => { const est = n(v.tested)>0?Math.round((n(v.known)/n(v.tested))*50000):0; const avg: Record<number,string> = {3:'1k-3k',5:'5k-10k',10:'15k-25k',15:'25k-35k',20:'35k-50k'}; const range = Object.entries(avg).reverse().find(([a])=>n(v.age)>=parseInt(a)); return { result: est.toLocaleString(), label: 'Est. Vocabulary Size', unit: 'words', steps: [`Sample: ${n(v.known)}/${n(v.tested)}`, `Est: ~${est.toLocaleString()} words`, range?`Typical for age ${n(v.age)}: ${range[1]}`:''] } }, description: 'Estimate vocabulary size.', formula: 'Estimate = (Known/Tested) x 50000', interpretation: 'Native adult: 20,000-35,000 word families. Reading expands vocabulary.' },

  'class-rank': { schema: z.object({ gpa: z.string(), classSize: z.string(), percentile: z.string() }), fields: [{ name: 'gpa', label: 'Your GPA', step: 0.01, min: 0, max: 4 }, { name: 'classSize', label: 'Class Size', step: 1, min: 1 }, { name: 'percentile', label: 'Est. Percentile', placeholder: '75', step: 1, min: 0, max: 100 }], compute: (v) => { const r = Math.round(n(v.classSize)*(1-(n(v.percentile)||75)/100)); return { result: r, label: 'Est. Class Rank', unit: `/${n(v.classSize)}`, steps: [`Rank: ${r} of ${n(v.classSize)}`, `Top ${(100-(n(v.percentile)||75)).toFixed(0)}%`] } }, description: 'Estimate class rank from GPA percentile.', formula: 'Rank = ClassSize x (1-Percentile/100)', interpretation: 'Top 10% = percentile 90+. Colleges look for top 10-25%.' },

  'course-load': { schema: z.object({ courses: z.string(), credits: z.string(), labs: z.string(), studyHrs: z.string() }), fields: [{ name: 'courses', label: 'Courses', step: 1, min: 1 }, { name: 'credits', label: 'Total Credits', step: 1, min: 1 }, { name: 'labs', label: 'Lab Courses', step: 1, min: 0 }, { name: 'studyHrs', label: 'Expected Study Hrs/Wk', step: 5, min: 0 }], compute: (v) => { const total = n(v.credits)*3+(n(v.labs)*2)+(n(v.studyHrs)||0); return { result: total, label: 'Total Weekly Hours', unit: 'hrs/wk', steps: [`Credits: ${n(v.credits)} x 3 = ${n(v.credits)*3}`, `Labs: ${n(v.labs)} x 2 = ${n(v.labs)*2}`, `Self-study: ${n(v.studyHrs)||0}`, `Total: ${total}`, total>60?'Heavy load (>60 hrs)':'Manageable'] } }, description: 'Calculate course load commitment.', formula: 'Hours = Credits*3 + Labs*2 + Study', interpretation: 'Full-time: 12-18 credits. Each credit = ~3 hrs/wk total (class + study).' },

  'credit-hours': { schema: z.object({ earned: z.string(), enrolled: z.string(), dropped: z.string(), minReq: z.string() }), fields: [{ name: 'earned', label: 'Credits Earned', step: 1, min: 0 }, { name: 'enrolled', label: 'Currently Enrolled', step: 1, min: 0 }, { name: 'dropped', label: 'Credits Dropped', step: 1, min: 0 }, { name: 'minReq', label: 'Min for Full-Time', placeholder: '12', step: 1, min: 1 }], compute: (v) => { const total = n(v.earned)+n(v.enrolled)-n(v.dropped); const min = n(v.minReq||'12'); return { result: total, label: 'Total Credit Hours', unit: 'credits', steps: [`Earned: ${n(v.earned)}`, `Enrolled: ${n(v.enrolled)}`, `Dropped: ${n(v.dropped)}`, `Total: ${total}`, total>=min?'Full-time':'Part-time (<'+min+')'] } }, description: 'Track credit hour status.', formula: 'Total = Earned + Enrolled - Dropped', interpretation: 'Full-time: 12+ credits undergrad, 9+ grad. Check financial aid requirements.' },

  'extra-credit': { schema: z.object({ currentPts: z.string(), totalPts: z.string(), extraPts: z.string(), extraMax: z.string() }), fields: [{ name: 'currentPts', label: 'Current Points', step: 1, min: 0 }, { name: 'totalPts', label: 'Total Possible (before EC)', step: 1, min: 1 }, { name: 'extraPts', label: 'Extra Credit Points Earned', step: 1, min: 0 }, { name: 'extraMax', label: 'Max EC Possible', step: 1, min: 0 }], compute: (v) => { const before = n(v.totalPts)>0?n(v.currentPts)/n(v.totalPts)*100:0; const after = n(v.totalPts)+n(v.extraMax)>0?(n(v.currentPts)+n(v.extraPts))/(n(v.totalPts)+n(v.extraMax))*100:0; return { result: after-before, label: 'Grade Boost from EC', unit: '%', steps: [`Before: ${before.toFixed(1)}%`, `After: ${after.toFixed(1)}%`, `Boost: +${(after-before).toFixed(1)}%`] } }, description: 'Calculate grade boost from extra credit.', formula: 'Before = Current/Total | After = (Current+EC)/(Total+MaxEC)', interpretation: 'Extra credit helps but do not rely on it. Max boost usually 1-3%.' },

  'participation-grade': { schema: z.object({ frequency: z.string(), quality: z.string(), attendance: z.string(), max: z.string() }), fields: [{ name: 'frequency', label: 'Frequency (0-100)', step: 1, min: 0, max: 100 }, { name: 'quality', label: 'Quality (0-100)', step: 1, min: 0, max: 100 }, { name: 'attendance', label: 'Attendance (0-100)', step: 1, min: 0, max: 100 }, { name: 'max', label: 'Max Score', placeholder: '100', step: 1, min: 1 }], compute: (v) => ({ result: ((n(v.frequency)+n(v.quality)+n(v.attendance))/3)/100*(n(v.max)||100), label: 'Participation Grade', unit: `/ ${n(v.max)||100}`, steps: [`Avg: ${((n(v.frequency)+n(v.quality)+n(v.attendance))/3).toFixed(1)}%`, `Score: ${(((n(v.frequency)+n(v.quality)+n(v.attendance))/3)/100*(n(v.max)||100)).toFixed(1)}/${n(v.max)||100}`] }), description: 'Calculate participation grade from criteria.', formula: 'Score = Avg(Freq,Quality,Attendance)/100 x Max', interpretation: 'Participate consistently, quality over quantity, attend all classes.' },

  'academic-probation': { schema: z.object({ currentGpa: z.string(), attemptedCredits: z.string(), minGpa: z.string(), plannedGpa: z.string(), plannedCredits: z.string() }), fields: [{ name: 'currentGpa', label: 'Current GPA', step: 0.01, min: 0, max: 4 }, { name: 'attemptedCredits', label: 'Attempted Credits', step: 1, min: 0 }, { name: 'minGpa', label: 'Min GPA Required', placeholder: '2.0', step: 0.1, min: 0, max: 4 }, { name: 'plannedGpa', label: 'Planned Term GPA', step: 0.01, min: 0, max: 4 }, { name: 'plannedCredits', label: 'Planned Term Credits', step: 1, min: 1 }], compute: (v) => { const curQP = n(v.currentGpa)*n(v.attemptedCredits); const newQP = n(v.plannedGpa)*n(v.plannedCredits); const totalQP = curQP+newQP; const totalCred = n(v.attemptedCredits)+n(v.plannedCredits); const projGpa = totalCred>0?totalQP/totalCred:0; const min = n(v.minGpa||'2.0'); return { result: projGpa, label: 'Projected GPA After Term', unit: '/4.0', steps: [`Current: ${n(v.currentGpa).toFixed(2)} (${n(v.attemptedCredits)} cr)`, `Planned: ${n(v.plannedGpa).toFixed(2)} (${n(v.plannedCredits)} cr)`, `Projected: ${projGpa.toFixed(3)}`, projGpa>=min?'Above minimum - good standing':`Below ${min.toFixed(1)} - probation risk`] } }, description: 'Check if projected GPA meets minimum.', formula: 'Projected = (CurrentQP + NewQP) / (Attempted + Planned)', interpretation: '2.0 minimum typically. Below = probation. Meet with advisor.' },

  'study-abroad-calc': { schema: z.object({ programFee: z.string(), airfare: z.string(), housing: z.string(), meals: z.string(), visa: z.string(), spending: z.string(), grants: z.string() }), fields: [{ name: 'programFee', label: 'Program Fee ($)', step: 500, min: 0 }, { name: 'airfare', label: 'Airfare ($)', step: 200, min: 0 }, { name: 'housing', label: 'Housing ($)', step: 500, min: 0 }, { name: 'meals', label: 'Meals ($)', step: 200, min: 0 }, { name: 'visa', label: 'Visa/Insurance ($)', step: 100, min: 0 }, { name: 'spending', label: 'Personal ($)', step: 200, min: 0 }, { name: 'grants', label: 'Scholarships/Grants ($)', step: 500, min: 0 }], compute: (v) => { const total = n(v.programFee)+n(v.airfare)+n(v.housing)+n(v.meals)+n(v.visa)+n(v.spending); const net = total-n(v.grants); return { result: net, label: 'Net Cost', unit: '$', steps: [`Total: $${total.toFixed(0)}`, `Grants: $${(n(v.grants)||0).toFixed(0)}`, `Net Cost: $${net.toFixed(0)}`] } }, description: 'Calculate study abroad cost.', formula: 'Net = (Program+Travel+Housing+Meals+Visa+Personal) - Grants', interpretation: 'Semester abroad: $10-30k typical. Apply for study abroad scholarships early.' },

  'scholarship-calc': { schema: z.object({ gpa: z.string(), testScore: z.string(), activities: z.string(), essays: z.string(), recommendations: z.string() }), fields: [{ name: 'gpa', label: 'GPA (4.0 scale)', step: 0.01, min: 0, max: 4 }, { name: 'testScore', label: 'Test Score (SAT/ACT)', step: 10, min: 0 }, { name: 'activities', label: 'Activities Impact (1-10)', step: 1, min: 1, max: 10 }, { name: 'essays', label: 'Essay Quality (1-10)', step: 1, min: 1, max: 10 }, { name: 'recommendations', label: 'Recommendations (1-10)', step: 1, min: 1, max: 10 }], compute: (v) => { var score = n(v.gpa)/4*25 + Math.min(n(v.testScore)/1600*20,20) + n(v.activities)*5 + n(v.essays)*5 + n(v.recommendations)*5; return { result: Math.min(100,score), label: 'Scholarship Competitiveness', unit: '%', steps: ['GPA: ' + n(v.gpa).toFixed(2) + '/4.0 (' + (n(v.gpa)/4*25).toFixed(0) + ' pts)', 'Test: ' + n(v.testScore).toFixed(0) + ' (' + Math.min(n(v.testScore)/1600*20,20).toFixed(0) + ' pts)', 'Activities: ' + n(v.activities) + ' (' + (n(v.activities)*5).toFixed(0) + ' pts)', 'Essays: ' + n(v.essays) + ' (' + (n(v.essays)*5).toFixed(0) + ' pts)', 'Recs: ' + n(v.recommendations) + ' (' + (n(v.recommendations)*5).toFixed(0) + ' pts)', 'Total: ' + score.toFixed(0) + '/100'] } }, description: 'Evaluate scholarship application competitiveness.', formula: 'Score = GPA pts + Test pts + Activities*5 + Essays*5 + Recs*5', interpretation: 'Score > 80: strong candidate. 60-80: competitive. < 60: improve profile.' },
  'recommendation-requests': { schema: z.object({ schools: z.string(), recommenders: z.string(), deadline: z.string(), waiveRight: z.string() }), fields: [{ name: 'schools', label: 'Number of Schools', step: 1, min: 1 }, { name: 'recommenders', label: 'Number of Recommenders', step: 1, min: 1 }, { name: 'deadline', label: 'Days Until Deadline', step: 1, min: 1 }, { name: 'waiveRight', label: 'Waive FERPA Right?', type: 'select', options: [{ label: 'Yes, waive right', value: 'yes' }, { label: 'No, keep right', value: 'no' }] }], compute: (v) => { var totalRequests = n(v.schools) * n(v.recommenders); var perDay = totalRequests / Math.max(1, n(v.deadline)); var recsPerRecommender = n(v.schools); return { result: totalRequests, label: 'Total Recommendation Requests', unit: '', steps: ['Schools: ' + n(v.schools), 'Recommenders: ' + n(v.recommenders), 'Total requests: ' + totalRequests, 'Per recommender: ' + recsPerRecommender + ' letters', 'Need ' + perDay.toFixed(1) + ' request(s) per day', String(v.waiveRight) === 'yes' ? 'Waiving FERPA right = stronger letters' : 'Not waiving may weaken letters' ] } }, description: 'Manage recommendation letter requests.', formula: 'Requests = Schools x Recommenders', interpretation: 'Give recommenders 3-4 weeks. Waive FERPA right for stronger letters. Send reminders 2 weeks before deadline.' },
  'corneil-notes': { schema: z.object({ pages: z.string(), cues: z.string(), notes: z.string(), summary: z.string() }), fields: [{ name: 'pages', label: 'Notebook Pages Used', step: 1, min: 0 }, { name: 'cues', label: 'Cues/Questions Written', step: 1, min: 0 }, { name: 'notes', label: 'Notes Sections Completed', step: 1, min: 0 }, { name: 'summary', label: 'Summaries Written', step: 1, min: 0 }], compute: (v) => { var completeness = n(v.notes)>0?(n(v.cues)+n(v.notes)+n(v.summary))/(n(v.notes)*3)*100:0; return { result: Math.min(100,completeness), label: 'Cornell Notes Score', unit: '%', steps: ['Pages: ' + n(v.pages), 'Cues: ' + n(v.cues), 'Notes: ' + n(v.notes), 'Summaries: ' + n(v.summary), 'Completeness: ' + Math.min(100,completeness).toFixed(0) + '%', completeness>=80?'Good note-taking habits':completeness>=50?'Room for improvement':'Include all sections for best results'] } }, description: 'Evaluate Cornell note-taking effectiveness.', formula: 'Score = (Cues + Notes + Summaries) / (Notes x 3) x 100', interpretation: 'Cornell method: cues column (left), notes (right), summary (bottom). Each page should have all three.' },
  'flashcard-ratings': { schema: z.object({ totalCards: z.string(), knownCards: z.string(), incorrectCards: z.string(), reviewTime: z.string() }), fields: [{ name: 'totalCards', label: 'Total Flashcards', step: 1, min: 1 }, { name: 'knownCards', label: 'Cards Known Correctly', step: 1, min: 0 }, { name: 'incorrectCards', label: 'Cards Answered Incorrectly', step: 1, min: 0 }, { name: 'reviewTime', label: 'Review Time (minutes)', step: 1, min: 1 }], compute: (v) => { var retention = n(v.totalCards)>0?n(v.knownCards)/n(v.totalCards)*100:0; var mastery = n(v.totalCards)>0?(n(v.knownCards)-n(v.incorrectCards))/n(v.totalCards)*100:0; var cardsPerMin = n(v.reviewTime)>0?n(v.totalCards)/n(v.reviewTime):0; return { result: retention, label: 'Flashcard Retention Rate', unit: '%', steps: ['Total: ' + n(v.totalCards), 'Known: ' + n(v.knownCards), 'Incorrect: ' + n(v.incorrectCards), 'Retention: ' + retention.toFixed(1) + '%', 'Mastery: ' + mastery.toFixed(1) + '%', cardsPerMin.toFixed(1) + ' cards/min', retention>=80?'Good retention':retention>=60?'Needs review':'Review more frequently'] } }, description: 'Rate flashcard study effectiveness.', formula: 'Retention = Known/Total x 100 | Mastery = (Known-Incorrect)/Total x 100', interpretation: 'Leitner system: space repetition. Target 80%+ retention. Cards with errors need more frequent review.' },
  'lab-notebook': { schema: z.object({ experiments: z.string(), procedures: z.string(), observations: z.string(), conclusions: z.string(), safetyNotes: z.string() }), fields: [{ name: 'experiments', label: 'Experiments Recorded', step: 1, min: 0 }, { name: 'procedures', label: 'Procedure Sections Complete', step: 1, min: 0 }, { name: 'observations', label: 'Observation Entries', step: 1, min: 0 }, { name: 'conclusions', label: 'Conclusion Sections', step: 1, min: 0 }, { name: 'safetyNotes', label: 'Safety Notes Included', step: 1, min: 0 }], compute: (v) => { var total = n(v.experiments)+n(v.procedures)+n(v.observations)+n(v.conclusions)+n(v.safetyNotes); var completeness = n(v.experiments)>0?total/(n(v.experiments)*5)*100:0; return { result: Math.min(100,completeness), label: 'Lab Notebook Score', unit: '%', steps: ['Experiments: ' + n(v.experiments), 'Procedures: ' + n(v.procedures) + '/' + n(v.experiments), 'Observations: ' + n(v.observations) + '/' + n(v.experiments), 'Conclusions: ' + n(v.conclusions) + '/' + n(v.experiments), 'Safety: ' + n(v.safetyNotes) + '/' + n(v.experiments), 'Completeness: ' + Math.min(100,completeness).toFixed(0) + '%'] } }, description: 'Evaluate lab notebook completeness.', formula: 'Score = (Procs + Obs + Conc + Safety) / (Experiments x 4) x 100', interpretation: 'Lab notebooks need: procedure, observations, data, conclusions, safety notes for each experiment. Dated entries with permanent ink.' },
  'quiz-generator': { schema: z.object({ topics: z.string(), questions: z.string(), difficulty: z.string(), timePerQ: z.string() }), fields: [{ name: 'topics', label: 'Number of Topics', step: 1, min: 1 }, { name: 'questions', label: 'Questions per Topic', step: 1, min: 1 }, { name: 'difficulty', label: 'Difficulty Level (1-5)', step: 1, min: 1, max: 5 }, { name: 'timePerQ', label: 'Time per Question (min)', placeholder: '1', step: 0.5, min: 0.5 }], compute: (v) => { var totalQ = n(v.topics)*n(v.questions); var totalTime = totalQ*(n(v.timePerQ)||1); return { result: totalQ, label: 'Total Quiz Questions', unit: '', steps: ['Topics: ' + n(v.topics), 'Questions per topic: ' + n(v.questions), 'Total: ' + totalQ + ' questions', 'Difficulty: ' + n(v.difficulty) + '/5', 'Est. time: ' + totalTime.toFixed(0) + ' min', totalQ>50?'Consider reducing question count for quiz length':'Good quiz size'] } }, description: 'Generate quiz parameters and estimates.', formula: 'Total = Topics x Questions/Topic | Time = Total x Time per Question', interpretation: 'Short quizzes: 10-20 questions. Unit tests: 20-40. Final exams: 50-100. Mix difficulty levels.' },
  'test-builder': { schema: z.object({ sections: z.string(), mcqPerSec: z.string(), essayPerSec: z.string(), ptsMCQ: z.string(), ptsEssay: z.string(), timeLimit: z.string() }), fields: [{ name: 'sections', label: 'Number of Sections', step: 1, min: 1 }, { name: 'mcqPerSec', label: 'MCQs per Section', step: 1, min: 0 }, { name: 'essayPerSec', label: 'Essay Questions per Section', step: 1, min: 0 }, { name: 'ptsMCQ', label: 'Points per MCQ', step: 1, min: 1, placeholder: '2' }, { name: 'ptsEssay', label: 'Points per Essay', step: 5, min: 1, placeholder: '10' }, { name: 'timeLimit', label: 'Time Limit (minutes)', step: 5, min: 1 }], compute: (v) => { var mcqTotal = n(v.sections)*n(v.mcqPerSec); var essayTotal = n(v.sections)*n(v.essayPerSec); var totalPts = mcqTotal*(n(v.ptsMCQ)||2)+essayTotal*(n(v.ptsEssay)||10); var ptsPerMin = n(v.timeLimit)>0?totalPts/n(v.timeLimit):0; return { result: totalPts, label: 'Total Test Points', unit: '', steps: ['Sections: ' + n(v.sections), 'MCQs: ' + mcqTotal + ' x ' + (n(v.ptsMCQ)||2) + ' pts = ' + mcqTotal*(n(v.ptsMCQ)||2), 'Essays: ' + essayTotal + ' x ' + (n(v.ptsEssay)||10) + ' pts = ' + essayTotal*(n(v.ptsEssay)||10), 'Total: ' + totalPts + ' points', 'Time: ' + n(v.timeLimit) + ' min', ptsPerMin.toFixed(1) + ' pts/min'] } }, description: 'Design test structure and scoring.', formula: 'Total = (MCQ x Pts/MCQ) + (Essays x Pts/Essay)', interpretation: 'Balance question types. MCQs: quick knowledge checks. Essays: deeper understanding. Aim for 1-2 pts per minute.' },
  'unit-test-builder': { schema: z.object({ modules: z.string(), objectives: z.string(), itemTypes: z.string(), totalItems: z.string(), passingPct: z.string() }), fields: [{ name: 'modules', label: 'Number of Modules', step: 1, min: 1 }, { name: 'objectives', label: 'Learning Objectives', step: 1, min: 1 }, { name: 'itemTypes', label: 'Question Types (comma-sep)', placeholder: 'MCQ, True/False, Short Answer' }, { name: 'totalItems', label: 'Total Test Items', step: 1, min: 1 }, { name: 'passingPct', label: 'Passing Score (%)', placeholder: '70', step: 5, min: 0, max: 100 }], compute: (v) => { var itemsPerObj = n(v.totalItems)/Math.max(1,n(v.objectives)); var itemsPerMod = n(v.totalItems)/Math.max(1,n(v.modules)); var passing = n(v.totalItems)*(n(v.passingPct||'70')/100); var types = String(v.itemTypes||'MCQ').split(',').length; return { result: itemsPerObj, label: 'Items per Objective', unit: '', steps: ['Modules: ' + n(v.modules), 'Objectives: ' + n(v.objectives), 'Total items: ' + n(v.totalItems), 'Items/objective: ' + itemsPerObj.toFixed(1), 'Items/module: ' + itemsPerMod.toFixed(1), 'Question types: ' + types, 'Passing: ' + passing.toFixed(0) + '/' + n(v.totalItems) + ' (' + (n(v.passingPct||'70')) + ')%'] } }, description: 'Plan unit test structure from learning objectives.', formula: 'Items/Obj = Total / Objectives', interpretation: 'Each objective needs 2-4 items for reliable assessment. More items = more valid assessment. Minimum 10 items per unit.' },
  'lexile-score': { schema: z.object({ words: z.string(), sentences: z.string(), syllables: z.string(), characters: z.string() }), fields: [{ name: 'words', label: 'Total Words', step: 1, min: 1 }, { name: 'sentences', label: 'Number of Sentences', step: 1, min: 1 }, { name: 'syllables', label: 'Total Syllables', step: 1, min: 1 }, { name: 'characters', label: 'Total Characters', step: 1, min: 1 }], compute: (v) => { var avgWordsPerSentence = n(v.sentences)>0?n(v.words)/n(v.sentences):0; var avgSyllablesPerWord = n(v.words)>0?n(v.syllables)/n(v.words):0; var avgCharsPerWord = n(v.words)>0?n(v.characters)/n(v.words):0; var lexile = Math.round(avgWordsPerSentence*3.3 + avgSyllablesPerWord*59.1 - 220); var clamped = Math.max(0,Math.min(1800,lexile)); var grade = {'0':'K-1','150':'1-2','300':'2-3','500':'3-4','650':'4-5','750':'5-6','850':'6-7','950':'7-8','1000':'8-9','1100':'9-10','1200':'11-12','1300':'College'}; var bands = Object.keys(grade).map(Number).sort(function(a,b){return b-a}); var band = null; for (var i=0;i<bands.length;i++) {     if (clamped >= bands[i]) { band = (grade as Record<string, string>)[String(bands[i])]; break; } } return { result: clamped, label: 'Lexile Score', unit: 'L', steps: ['Words/sentence: ' + avgWordsPerSentence.toFixed(1), 'Syllables/word: ' + avgSyllablesPerWord.toFixed(2), 'Lexile: ' + clamped + 'L', band ? 'Approx grade: ' + band : ''] } }, description: 'Estimate Lexile text complexity score.', formula: 'Lexile = (AvgWords/Sent x 3.3) + (AvgSyllables/Word x 59.1) - 220', interpretation: 'Lexile range: 0L-1800L. Higher = more complex. K-1: ~200L. Grade 6: ~900L. College: ~1300L.' },
  'typing-speed-test': { schema: z.object({ wpm: z.string(), accuracy: z.string(), time: z.string(), targetWpm: z.string() }), fields: [{ name: 'wpm', label: 'Your WPM', step: 1, min: 0 }, { name: 'accuracy', label: 'Accuracy (%)', step: 1, min: 0, max: 100 }, { name: 'time', label: 'Test Duration (minutes)', step: 0.5, min: 0.5 }, { name: 'targetWpm', label: 'Target WPM', placeholder: '60', step: 5, min: 0 }], compute: (v) => { var target = n(v.targetWpm||'60'); var adjWpm = n(v.wpm)*(n(v.accuracy)/100); var progress = target>0?adjWpm/target*100:0; var cat = adjWpm>=target?'Target met!':adjWpm>=target*0.8?'Close to target':'Needs practice'; return { result: adjWpm, label: 'Effective WPM', unit: 'WPM', steps: ['Raw WPM: ' + n(v.wpm), 'Accuracy: ' + n(v.accuracy) + '%', 'Effective: ' + adjWpm.toFixed(1) + ' WPM', 'Target: ' + target + ' WPM', 'Progress: ' + progress.toFixed(0) + '%', cat] } }, description: 'Calculate effective typing speed with accuracy adjustment.', formula: 'Effective WPM = Raw WPM x (Accuracy / 100)', interpretation: 'Accuracy matters more than speed. Target 60+ WPM with 95%+ accuracy. Professional: 65-80 WPM. Practice daily 15 min.' },

}

interface Props { calculator: { slug: string; title: string; description: string; tier: string; category: string; hubSlug: string; hubName: string; keywords: string[]; dataDependent?: boolean; dataRefreshCadence?: string } }

function FallbackEducation({ calculator }: Props) {
  return (
    <div className="text-center py-12 px-4">
      <div className="text-4xl mb-4">📚</div>
      <h2 className="text-xl font-semibold text-gray-700 dark:text-gray-300 mb-2">{calculator.title}</h2>
      <p className="text-gray-500 dark:text-gray-400 max-w-md mx-auto">{calculator.description}</p>
      <p className="text-sm text-gray-400 mt-4">This calculator is being developed. Browse other {calculator.hubName} in the menu.</p>
    </div>
  )
}

export function GenericEducationCalculator({ calculator }: Props) {
  let calcDef = calcDefs[calculator.slug]
  if (!calcDef) calcDef = buildGenericDef(calculator) as unknown as CalcDef
  const [useSlider, setUseSlider] = useState(true)
  const [lockedFields, setLockedFields] = useState<Set<string>>(new Set())
  const [extraFields, setExtraFields] = useState<Record<string, string>>({})
  const toggleLock = useCallback((name: string) => { setLockedFields(prev => { const next = new Set(prev); if (next.has(name)) next.delete(name); else next.add(name); return next }) }, [])
  const form = useForm({ resolver: zodResolver(calcDef.schema), mode: 'onChange' })
  const watched = useWatch({ control: form.control })
  const v = watched as Record<string, unknown>
  const watchedInputs = useMemo(() => {
    const vals = (typeof watched === 'object' && watched !== null) ? watched as Record<string, string> : {}
    return Object.fromEntries(Object.entries(vals).filter(([, v]) => v !== undefined && v !== ''))
  }, [watched])
  const mainValue = useMemo(() => {
    if (!v || Object.keys(v).length === 0) return undefined
    const res = calcDef.compute(v)
    const parsed = typeof res.result === 'number' ? res.result : parseFloat(String(res.result))
    return isNaN(parsed) ? undefined : parsed
  }, [v, calcDef])
  const result = useMemo(() => {
    if (!v || Object.keys(v).length === 0) return null
    const res = calcDef.compute(v)
    const displayVal = typeof res.result === 'number' ? res.result.toFixed(2) : res.result
    return (
      <div className="text-center space-y-4">
        <div className="bg-gray-50 dark:bg-gray-900 rounded-xl p-4">
          <p className="text-xs text-gray-500 dark:text-gray-400">{res.label}</p>
          <p className="text-3xl font-bold text-[#06b6d4]">{displayVal} {res.unit}</p>
        </div>
        {res.steps.length > 0 && (
          <div className="border-t border-gray-200 dark:border-gray-700 pt-3 text-xs text-gray-500 space-y-1.5 text-left">
            <p className="font-medium text-gray-700 dark:text-gray-300">Steps</p>
            {res.steps.map((step, i) => (
              <div key={i} className="flex items-start gap-2">
                <span className="flex-shrink-0 w-4 h-4 rounded-full bg-[#1a3a8a]/10 text-[#06b6d4] flex items-center justify-center text-[10px] font-medium mt-0.5">{i + 1}</span>
                <span>{typeof step === 'string' ? step : `${step.label}: ${step.value}`}</span>
              </div>
            ))}
          </div>
        )}
      </div>
    )
  }, [v, calcDef])
  const copyResultText = useMemo(() => { const lines: string[] = [calculator.title]; Object.entries(v).filter(([, val]) => val).forEach(([k, val]) => lines.push(`${k}: ${val}`)); return lines.join('\n') }, [calculator.title, v])
  const presets = calcDef?.presets || []
  const applyPreset = useCallback((preset: { label: string; values: Record<string, string> }) => {
    Object.entries(preset.values).forEach(([key, value]) => {
      if (!lockedFields.has(key)) form.setValue(key as any, value)
    })
  }, [form, lockedFields])
  const formContent = useMemo(() => (
    <>
      <FieldsByMode fields={calcDef.fields} useSlider={useSlider} lockedFields={lockedFields} toggleLock={toggleLock} />
    </>
  ), [calcDef, lockedFields, toggleLock, form, useSlider])
  return (
    <FormProvider {...form}>
      <PremiumCalculatorShell calculator={calculator} form={formContent} result={result} lockedFields={lockedFields} onExtraFieldsChange={setExtraFields} formula={calcDef.formula} interpretation={calcDef.interpretation} presets={presets} onPresetApply={applyPreset} onReset={() => {
          const locked = Object.fromEntries(
            Array.from(lockedFields).map(key => [key, form.getValues(key)])
          )
          form.reset()
          Object.entries(locked).forEach(([key, value]) => {
            if (value !== undefined && value !== '') form.setValue(key as any, value)
          })
        }} copyResultText={copyResultText} inputs={watchedInputs} showTabs={true} useSlider={useSlider} onToggleSlider={() => setUseSlider(!useSlider)} hubCategory="education" mainValue={mainValue} onSaveScenario={() => Object.entries(v).filter(([, val]) => val).map(([k, val]) => `${k}: ${val}`).join('\n')} onExportCSV={() => Object.entries(v).filter(([, val]) => val).map(([k, val]) => `${k},${val}`).join('\n')} userCount={3891} />
    </FormProvider>
  )
}
